/**
 * @fileoverview Chart "lite" price-line rendering — a minimal, clean
 * closing-price line chart suitable for sparklines, thumbnails, or quick
 * price-at-a-glance widgets.
 *
 * Lazy-loadable via `installLite(ctx)`.
 * Adds the `'price-line'` chart type.
 *
 * Features:
 *   - Single smooth closing-price line with gradient fill
 *   - Auto-scaled Y-axis with a handful of tick marks
 *   - Time axis (date labels, auto-density)
 *   - Optional current-price marker (dot + dashed line)
 *   - Hover tooltip showing date + price
 *   - Responsive / configurable dimensions
 *
 * Data format — same as the trading feature (OHLCV) or a simple array:
 * ```
 * datasets: [{
 *     data: [
 *         { date: '2025-01-01', close: 105 },
 *         { date: '2025-01-02', close: 112 },
 *         ...
 *     ],
 *     lineColor: 'hsl(216, 72%, 56%)',
 *     fillColor: 'hsl(216, 72%, 56%)',
 * }]
 * // — or simple numeric array —
 * datasets: [{ data: [105, 112, 108, ...] }]
 * ```
 *
 * Config:
 * ```
 * {
 *     type: 'price-line',
 *     showDot: true,           // current price dot
 *     showPriceLine: true,     // dashed horizontal at last close
 *     showAxis: true,          // Y-axis ticks
 *     showDateAxis: true,      // X-axis dates
 *     gradientFill: true,      // area fill below line
 *     priceFormat: (v) => v.toFixed(2),
 *     dateFormat:  (d) => ...,
 * }
 * ```
 *
 * @module module/Chart/features/lite
 */

import razyui from '../../../index.js';
import { svgEl, niceScale, smoothPath } from '../helpers.js';
import { bindHover } from '../events.js';
import { normalizeOHLC } from './trading.js';

// ── Installer ────────────────────────────────────

/**
 * Install the lite price-line chart type onto the Chart context.
 *
 * @param {Object} ctx — chart context bridge
 */
export function installLite(ctx) {
    ctx._liteInstalled = true;
}

// ── Main renderer ────────────────────────────────

/**
 * Render a lightweight single-line price chart.
 *
 * @param {Object} ctx — chart context bridge
 */
export function renderLite(ctx) {
    const cfg = ctx.config;
    // Y-axis is right-side only → shrink left padding, widen right for labels
    const pad = { ...cfg.padding, left: 8, right: Math.max(cfg.padding.right, 50) };

    // Measure actual container width so the chart fills it with no dead zones.
    const containerEl = ctx.container[0];
    const measured = containerEl ? containerEl.clientWidth : 0;
    const svgW = measured > 0 ? measured : 600;
    const svgH = typeof cfg.height === 'number' ? cfg.height : 280;

    const svg = svgEl('svg', {
        viewBox: `0 0 ${svgW} ${svgH}`,
        class: 'chart-svg chart-lite',
    });
    svg.style.width = '100%';
    svg.style.height = svgH + 'px';
    ctx.svg = svg;

    const ds = cfg.datasets?.[0];
    if (!ds?.data?.length) {
        ctx.container.append(svg);
        return;
    }

    // ── Normalise data ──
    const rawData = normalizeOHLC(ds.data);
    const isNumeric = typeof rawData[0] === 'number';
    const closes = isNumeric
        ? rawData
        : rawData.map(d => d.close ?? d.value ?? d.y ?? 0);
    const dates = isNumeric
        ? rawData.map((_, i) => String(i + 1))
        : rawData.map(d => d.date ?? d.label ?? '');

    const lineColor = ds.lineColor || ds.color || cfg.lineColor || 'hsl(216, 72%, 56%)';
    const fillColor = ds.fillColor || lineColor;

    // ── Layout ──
    const plotL = pad.left;
    const plotR = svgW - pad.right;
    const plotT = pad.top;
    const plotB = svgH - pad.bottom;
    const plotW = plotR - plotL;
    const plotH = plotB - plotT;

    // ── Price scale ──
    const pMin = Math.min(...closes);
    const pMax = Math.max(...closes);
    const scale = niceScale(pMin, pMax, 5);
    const toY = v => plotT + plotH - ((v - scale.min) / (scale.max - scale.min || 1)) * plotH;
    const toX = i => plotL + (i / Math.max(closes.length - 1, 1)) * plotW;

    // ── Grid lines + Y-axis ──
    if (cfg.showAxis !== false) {
        const fmt = cfg.priceFormat || (v => {
            if (Math.abs(v) >= 1e6) return (v / 1e6).toFixed(1) + 'M';
            if (Math.abs(v) >= 1e3) return (v / 1e3).toFixed(1) + 'K';
            return v % 1 === 0 ? String(v) : v.toFixed(2);
        });
        for (let v = scale.min; v <= scale.max; v += scale.step) {
            const y = toY(v);
            svg.appendChild(svgEl('line', {
                x1: plotL, y1: y, x2: plotR, y2: y,
                stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
                'stroke-dasharray': '3,3', 'stroke-opacity': '0.5',
            }));
            const label = svgEl('text', {
                x: plotR + 4, y: y + 3,
                'font-size': '9', fill: ctx.css('--rui-text-muted'),
            });
            label.textContent = fmt(v);
            svg.appendChild(label);
        }
    }

    // ── Date axis ──
    if (cfg.showDateAxis !== false && dates.length) {
        const maxLabels = Math.floor(plotW / 60);
        const step = Math.max(1, Math.ceil(dates.length / maxLabels));
        const dfmt = cfg.dateFormat || (d => {
            if (!d) return '';
            if (d.length > 10) return d.slice(5, 10);
            return d.length > 5 ? d.slice(5) : d;
        });
        for (let i = 0; i < dates.length; i += step) {
            const x = toX(i);
            const label = svgEl('text', {
                x, y: plotB + 14,
                'text-anchor': 'middle', 'font-size': '9',
                fill: ctx.css('--rui-text-muted'),
            });
            label.textContent = dfmt(dates[i]);
            svg.appendChild(label);
        }
    }

    // ── Build points ──
    const points = closes.map((v, i) => ({ x: toX(i), y: toY(v) }));
    if (points.length < 2) { ctx.container.append(svg); return; }

    const pathD = smoothPath(points);

    // ── Gradient fill ──
    if (cfg.gradientFill !== false) {
        const gradId = 'lite-grad-' + Math.random().toString(36).slice(2, 8);
        const defs = svgEl('defs', {});
        const grad = svgEl('linearGradient', {
            id: gradId, x1: '0', y1: '0', x2: '0', y2: '1',
        });
        const stop1 = svgEl('stop', {
            offset: '0%', 'stop-color': fillColor, 'stop-opacity': '0.25',
        });
        const stop2 = svgEl('stop', {
            offset: '100%', 'stop-color': fillColor, 'stop-opacity': '0.02',
        });
        grad.appendChild(stop1);
        grad.appendChild(stop2);
        defs.appendChild(grad);
        svg.appendChild(defs);

        // Area path
        const areaD = pathD
            + `L${points[points.length - 1].x},${plotB}`
            + `L${points[0].x},${plotB}Z`;
        svg.appendChild(svgEl('path', {
            d: areaD,
            fill: `url(#${gradId})`,
            class: 'chart-lite-area',
        }));
    }

    // ── Price line ──
    svg.appendChild(svgEl('path', {
        d: pathD,
        fill: 'none', stroke: lineColor, 'stroke-width': '2',
        'stroke-linejoin': 'round', 'stroke-linecap': 'round',
        class: 'chart-lite-line',
    }));

    // ── Current price dot + dashed line ──
    const lastClose = closes[closes.length - 1];
    const lastPt = points[points.length - 1];

    if (cfg.showPriceLine !== false) {
        svg.appendChild(svgEl('line', {
            x1: plotL, y1: lastPt.y, x2: plotR, y2: lastPt.y,
            stroke: lineColor, 'stroke-width': 0.8,
            'stroke-dasharray': '4,3', 'stroke-opacity': '0.5',
        }));
    }

    if (cfg.showDot !== false) {
        svg.appendChild(svgEl('circle', {
            cx: lastPt.x, cy: lastPt.y, r: 3.5,
            fill: lineColor, stroke: '#fff', 'stroke-width': 1.5,
            class: 'chart-lite-dot',
        }));
    }

    // ── Current price badge ──
    if (cfg.showPriceBadge !== false) {
        const fmtBadge = cfg.priceFormat || (v => {
            if (Math.abs(v) >= 1e6) return (v / 1e6).toFixed(1) + 'M';
            if (Math.abs(v) >= 1e3) return (v / 1e3).toFixed(1) + 'K';
            return v % 1 === 0 ? String(v) : v.toFixed(2);
        });
        const badgeText = fmtBadge(lastClose);
        const badgeW = Math.max(36, badgeText.length * 6 + 10);
        const badgeH = 16;
        const badgeX = plotR + 2;
        const badgeY = lastPt.y - badgeH / 2;
        svg.appendChild(svgEl('rect', {
            x: badgeX, y: badgeY, width: badgeW, height: badgeH, rx: 2,
            fill: lineColor, class: 'chart-lite-price-badge',
        }));
        const badgeTxt = svgEl('text', {
            x: badgeX + badgeW / 2, y: lastPt.y + 3.5,
            'text-anchor': 'middle', 'font-size': '9', 'font-weight': '600', fill: '#fff',
        });
        badgeTxt.textContent = badgeText;
        svg.appendChild(badgeTxt);
    }

    // ── Change badge ──
    if (closes.length >= 2) {
        const first = closes[0];
        const change = lastClose - first;
        const pct = ((change / first) * 100).toFixed(2);
        const positive = change >= 0;
        const badge = svgEl('text', {
            x: plotL + 4, y: plotT + 14,
            'font-size': '11', 'font-weight': '600',
            fill: positive ? 'hsl(145, 55%, 42%)' : 'hsl(0, 65%, 55%)',
        });
        badge.textContent = `${positive ? '+' : ''}${pct}%`;
        svg.appendChild(badge);
    }

    // ── Hover interaction ──
    const hoverLine = svgEl('line', {
        x1: 0, y1: plotT, x2: 0, y2: plotB,
        stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.8,
        'stroke-dasharray': '3,2', 'stroke-opacity': '0',
    });
    svg.appendChild(hoverLine);

    const hoverDot = svgEl('circle', {
        cx: 0, cy: 0, r: 3.5,
        fill: lineColor, stroke: '#fff', 'stroke-width': 1.5,
        opacity: '0',
    });
    svg.appendChild(hoverDot);

    // Hover price label on Y-axis
    const hoverPriceBg = svgEl('rect', {
        x: plotR + 1, y: 0, width: 46, height: 16, rx: 2,
        fill: 'hsl(220, 12%, 22%)', opacity: '0',
    });
    svg.appendChild(hoverPriceBg);
    const hoverPriceLabel = svgEl('text', {
        x: plotR + 4, y: 0,
        'font-size': '9', 'font-weight': '600', fill: '#fff', opacity: '0',
    });
    svg.appendChild(hoverPriceLabel);

    // Hover date label
    const hoverDateLabel = svgEl('text', {
        x: 0, y: plotB + 14,
        'text-anchor': 'middle', 'font-size': '9', fill: lineColor, opacity: '0',
    });
    svg.appendChild(hoverDateLabel);

    const fmt = cfg.priceFormat || (v => v.toFixed(2));

    razyui(svg).on('mousemove', (e) => {
        const rect = svg.getBoundingClientRect();
        const mx = (e.clientX - rect.left) * (svgW / rect.width);
        if (mx < plotL || mx > plotR) {
            hoverLine.setAttribute('stroke-opacity', '0');
            hoverDot.setAttribute('opacity', '0');
            hoverPriceBg.setAttribute('opacity', '0');
            hoverPriceLabel.setAttribute('opacity', '0');
            hoverDateLabel.setAttribute('opacity', '0');
            return;
        }
        const ratio = (mx - plotL) / plotW;
        const idx = Math.round(ratio * (closes.length - 1));
        const ci = Math.max(0, Math.min(closes.length - 1, idx));
        const px = toX(ci);
        const py = toY(closes[ci]);

        hoverLine.setAttribute('x1', px);
        hoverLine.setAttribute('x2', px);
        hoverLine.setAttribute('stroke-opacity', '0.5');
        hoverDot.setAttribute('cx', px);
        hoverDot.setAttribute('cy', py);
        hoverDot.setAttribute('opacity', '1');

        // Price label on right axis
        const priceText = fmt(closes[ci]);
        hoverPriceLabel.textContent = priceText;
        hoverPriceBg.setAttribute('y', py - 8);
        hoverPriceBg.setAttribute('width', Math.max(36, priceText.length * 6 + 8));
        hoverPriceBg.setAttribute('opacity', '1');
        hoverPriceLabel.setAttribute('y', py + 3);
        hoverPriceLabel.setAttribute('opacity', '1');

        // Date label
        if (dates[ci]) {
            hoverDateLabel.textContent = dates[ci];
            hoverDateLabel.setAttribute('x', px);
            hoverDateLabel.setAttribute('opacity', '1');
        }

        if (cfg.onHover) {
            cfg.onHover({ index: ci, date: dates[ci], price: closes[ci] });
        }
    });

    razyui(svg).on('mouseleave', () => {
        hoverLine.setAttribute('stroke-opacity', '0');
        hoverDot.setAttribute('opacity', '0');
        hoverPriceBg.setAttribute('opacity', '0');
        hoverPriceLabel.setAttribute('opacity', '0');
        hoverDateLabel.setAttribute('opacity', '0');
    });

    // ── Title ──
    if (cfg.title) {
        const titleEl = svgEl('text', {
            x: plotL, y: plotT - 6,
            'font-size': '12', 'font-weight': '600',
            fill: ctx.css('--rui-text'),
        });
        titleEl.textContent = cfg.title;
        svg.appendChild(titleEl);
    }

    ctx.container.append(svg);
}

// ── Baseline chart ───────────────────────────────

/**
 * Render a baseline chart — a line/area chart split at a reference price.
 * Area above the baseline is colored green, below is colored red.
 *
 * Config:
 * ```
 * {
 *     type: 'baseline',
 *     baselineValue: 100,        // reference price (default: first close)
 *     aboveColor: 'hsl(145,55%,42%)',
 *     belowColor: 'hsl(0,65%,55%)',
 * }
 * ```
 *
 * @param {Object} ctx — chart context bridge
 */
export function renderBaseline(ctx) {
    const cfg = ctx.config;
    // Y-axis is right-side only → shrink left padding, widen right for labels
    const pad = { ...cfg.padding, left: 8, right: Math.max(cfg.padding.right, 50) };

    // Measure actual container width so the chart fills it with no dead zones.
    const containerEl = ctx.container[0];
    const measured = containerEl ? containerEl.clientWidth : 0;
    const svgW = measured > 0 ? measured : 600;
    const svgH = typeof cfg.height === 'number' ? cfg.height : 280;

    const svg = svgEl('svg', {
        viewBox: `0 0 ${svgW} ${svgH}`,
        class: 'chart-svg chart-baseline',
    });
    svg.style.width = '100%';
    svg.style.height = svgH + 'px';
    ctx.svg = svg;

    const ds = cfg.datasets?.[0];
    if (!ds?.data?.length) { ctx.container.append(svg); return; }

    // Normalise data
    const rawData = normalizeOHLC(ds.data);
    const isNumeric = typeof rawData[0] === 'number';
    const closes = isNumeric ? rawData : rawData.map(d => d.close ?? d.value ?? d.y ?? 0);
    const dates = isNumeric ? rawData.map((_, i) => String(i + 1)) : rawData.map(d => d.date ?? d.label ?? '');

    const aboveColor = cfg.aboveColor || ds.aboveColor || 'hsl(145, 55%, 42%)';
    const belowColor = cfg.belowColor || ds.belowColor || 'hsl(0, 65%, 55%)';
    const baselineVal = cfg.baselineValue ?? closes[0];

    // Layout
    const plotL = pad.left;
    const plotR = svgW - pad.right;
    const plotT = pad.top;
    const plotB = svgH - pad.bottom;
    const plotW = plotR - plotL;
    const plotH = plotB - plotT;

    // Scale
    const pMin = Math.min(...closes, baselineVal);
    const pMax = Math.max(...closes, baselineVal);
    const scale = niceScale(pMin, pMax, 5);
    const toY = v => plotT + plotH - ((v - scale.min) / (scale.max - scale.min || 1)) * plotH;
    const toX = i => plotL + (i / Math.max(closes.length - 1, 1)) * plotW;
    const baseY = toY(baselineVal);

    // Grid + Y-axis
    if (cfg.showAxis !== false) {
        const fmt = cfg.priceFormat || (v => v % 1 === 0 ? String(v) : v.toFixed(2));
        for (let v = scale.min; v <= scale.max; v += scale.step) {
            const y = toY(v);
            svg.appendChild(svgEl('line', {
                x1: plotL, y1: y, x2: plotR, y2: y,
                stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
                'stroke-dasharray': '3,3', 'stroke-opacity': '0.5',
            }));
            const label = svgEl('text', {
                x: plotR + 4, y: y + 3,
                'font-size': '9', fill: ctx.css('--rui-text-muted'),
            });
            label.textContent = fmt(v);
            svg.appendChild(label);
        }
    }

    // Date axis
    if (cfg.showDateAxis !== false && dates.length) {
        const maxLabels = Math.floor(plotW / 60);
        const step = Math.max(1, Math.ceil(dates.length / maxLabels));
        const dfmt = cfg.dateFormat || (d => {
            if (!d) return '';
            return d.length > 10 ? d.slice(5, 10) : d.length > 5 ? d.slice(5) : d;
        });
        for (let i = 0; i < dates.length; i += step) {
            const label = svgEl('text', {
                x: toX(i), y: plotB + 14,
                'text-anchor': 'middle', 'font-size': '9', fill: ctx.css('--rui-text-muted'),
            });
            label.textContent = dfmt(dates[i]);
            svg.appendChild(label);
        }
    }

    // Build points
    const points = closes.map((v, i) => ({ x: toX(i), y: toY(v) }));
    if (points.length < 2) { ctx.container.append(svg); return; }

    // Defs: clip paths + gradients for above / below baseline
    const defs = svgEl('defs', {});
    const uid = 'bl-' + Math.random().toString(36).slice(2, 8);

    // Clip path for area ABOVE baseline (from top of chart to baseline)
    const clipAbove = svgEl('clipPath', { id: `${uid}-above` });
    clipAbove.appendChild(svgEl('rect', {
        x: plotL, y: plotT, width: plotW, height: baseY - plotT,
    }));
    defs.appendChild(clipAbove);

    // Clip path for area BELOW baseline
    const clipBelow = svgEl('clipPath', { id: `${uid}-below` });
    clipBelow.appendChild(svgEl('rect', {
        x: plotL, y: baseY, width: plotW, height: plotB - baseY,
    }));
    defs.appendChild(clipBelow);

    // Gradient above
    const gradAbove = svgEl('linearGradient', { id: `${uid}-grad-above`, x1: '0', y1: '0', x2: '0', y2: '1' });
    gradAbove.appendChild(svgEl('stop', { offset: '0%', 'stop-color': aboveColor, 'stop-opacity': '0.25' }));
    gradAbove.appendChild(svgEl('stop', { offset: '100%', 'stop-color': aboveColor, 'stop-opacity': '0.03' }));
    defs.appendChild(gradAbove);

    // Gradient below
    const gradBelow = svgEl('linearGradient', { id: `${uid}-grad-below`, x1: '0', y1: '0', x2: '0', y2: '1' });
    gradBelow.appendChild(svgEl('stop', { offset: '0%', 'stop-color': belowColor, 'stop-opacity': '0.03' }));
    gradBelow.appendChild(svgEl('stop', { offset: '100%', 'stop-color': belowColor, 'stop-opacity': '0.25' }));
    defs.appendChild(gradBelow);

    svg.appendChild(defs);

    // Build path and area strings
    const pathD = smoothPath(points);
    const areaD = pathD
        + `L${points[points.length - 1].x},${baseY}`
        + `L${points[0].x},${baseY}Z`;

    // Area above baseline (clipped + green gradient)
    svg.appendChild(svgEl('path', {
        d: areaD, fill: `url(#${uid}-grad-above)`,
        'clip-path': `url(#${uid}-above)`, class: 'chart-baseline-area-above',
    }));

    // Area below baseline (clipped + red gradient)
    svg.appendChild(svgEl('path', {
        d: areaD, fill: `url(#${uid}-grad-below)`,
        'clip-path': `url(#${uid}-below)`, class: 'chart-baseline-area-below',
    }));

    // Line above
    svg.appendChild(svgEl('path', {
        d: pathD, fill: 'none', stroke: aboveColor, 'stroke-width': '2',
        'stroke-linejoin': 'round', 'stroke-linecap': 'round',
        'clip-path': `url(#${uid}-above)`, class: 'chart-baseline-line-above',
    }));

    // Line below
    svg.appendChild(svgEl('path', {
        d: pathD, fill: 'none', stroke: belowColor, 'stroke-width': '2',
        'stroke-linejoin': 'round', 'stroke-linecap': 'round',
        'clip-path': `url(#${uid}-below)`, class: 'chart-baseline-line-below',
    }));

    // Baseline reference line
    svg.appendChild(svgEl('line', {
        x1: plotL, y1: baseY, x2: plotR, y2: baseY,
        stroke: ctx.css('--rui-text-muted'), 'stroke-width': 1,
        'stroke-dasharray': '5,3', 'stroke-opacity': '0.6',
        class: 'chart-baseline-ref',
    }));

    // Baseline label
    const blLabel = svgEl('text', {
        x: plotR + 4, y: baseY + 3,
        'font-size': '9', 'font-weight': '600', fill: ctx.css('--rui-text-muted'),
    });
    blLabel.textContent = (cfg.priceFormat || (v => v.toFixed(2)))(baselineVal);
    svg.appendChild(blLabel);

    // Change badge
    if (closes.length >= 2) {
        const last = closes[closes.length - 1];
        const change = last - baselineVal;
        const pct = ((change / baselineVal) * 100).toFixed(2);
        const positive = change >= 0;
        const badge = svgEl('text', {
            x: plotL + 4, y: plotT + 14,
            'font-size': '11', 'font-weight': '600',
            fill: positive ? aboveColor : belowColor,
        });
        badge.textContent = `${positive ? '+' : ''}${pct}%`;
        svg.appendChild(badge);
    }

    // Title
    if (cfg.title) {
        const titleEl = svgEl('text', {
            x: plotL, y: plotT - 6,
            'font-size': '12', 'font-weight': '600', fill: ctx.css('--rui-text'),
        });
        titleEl.textContent = cfg.title;
        svg.appendChild(titleEl);
    }

    // ── Current price indicator line + dot + badge ──
    const lastClose = closes[closes.length - 1];
    const lastPt = points[points.length - 1];
    const lastColor = lastClose >= baselineVal ? aboveColor : belowColor;

    svg.appendChild(svgEl('line', {
        x1: plotL, y1: lastPt.y, x2: plotR, y2: lastPt.y,
        stroke: lastColor, 'stroke-width': 0.8,
        'stroke-dasharray': '4,3', 'stroke-opacity': '0.5',
        class: 'chart-baseline-current-line',
    }));

    svg.appendChild(svgEl('circle', {
        cx: lastPt.x, cy: lastPt.y, r: 3.5,
        fill: lastColor, stroke: '#fff', 'stroke-width': 1.5,
        class: 'chart-baseline-dot',
    }));

    // Price badge
    const fmtBadge = cfg.priceFormat || (v => v.toFixed(2));
    const priceBadgeText = fmtBadge(lastClose);
    const pBadgeW = Math.max(36, priceBadgeText.length * 6 + 10);
    const pBadgeH = 16;
    svg.appendChild(svgEl('rect', {
        x: plotR + 2, y: lastPt.y - pBadgeH / 2, width: pBadgeW, height: pBadgeH, rx: 2,
        fill: lastColor, class: 'chart-baseline-price-badge',
    }));
    const pBadgeTxt = svgEl('text', {
        x: plotR + 2 + pBadgeW / 2, y: lastPt.y + 3.5,
        'text-anchor': 'middle', 'font-size': '9', 'font-weight': '600', fill: '#fff',
    });
    pBadgeTxt.textContent = priceBadgeText;
    svg.appendChild(pBadgeTxt);

    // ── Crosshair interaction ──
    const crossG = svgEl('g', { class: 'chart-crosshair', style: 'display:none' });
    const crossH = svgEl('line', {
        x1: plotL, y1: 0, x2: plotR, y2: 0,
        stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.5, 'stroke-dasharray': '4,3',
    });
    const crossV = svgEl('line', {
        x1: 0, y1: plotT, x2: 0, y2: plotB,
        stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.5, 'stroke-dasharray': '4,3',
    });
    const crossDot = svgEl('circle', {
        cx: 0, cy: 0, r: 3.5,
        fill: aboveColor, stroke: '#fff', 'stroke-width': 1.5,
    });
    // Price tag on right axis
    const crossPriceBg = svgEl('rect', {
        x: plotR + 1, y: 0, width: 46, height: 16, rx: 2,
        fill: 'hsl(220, 12%, 22%)',
    });
    const crossPriceTxt = svgEl('text', {
        x: plotR + 4, y: 0,
        'font-size': '9', 'font-weight': '600', fill: '#fff',
    });
    // Date tag at bottom
    const crossDateBg = svgEl('rect', {
        x: 0, y: plotB, width: 70, height: 16, rx: 2,
        fill: 'hsl(220, 12%, 22%)',
    });
    const crossDateTxt = svgEl('text', {
        x: 0, y: plotB + 11,
        'text-anchor': 'middle', 'font-size': '9', fill: '#fff',
    });
    crossG.appendChild(crossH);
    crossG.appendChild(crossV);
    crossG.appendChild(crossDot);
    crossG.appendChild(crossPriceBg);
    crossG.appendChild(crossPriceTxt);
    crossG.appendChild(crossDateBg);
    crossG.appendChild(crossDateTxt);
    svg.appendChild(crossG);

    const fmtHover = cfg.priceFormat || (v => v.toFixed(2));

    razyui(svg).on('mousemove', (e) => {
        const ctm = svg.getScreenCTM();
        if (!ctm) return;
        const inv = ctm.inverse();
        const mx = e.clientX * inv.a + e.clientY * inv.c + inv.e;
        const my = e.clientX * inv.b + e.clientY * inv.d + inv.f;

        if (mx < plotL || mx > plotR || my < plotT || my > plotB) {
            crossG.style.display = 'none';
            return;
        }
        crossG.style.display = '';

        // Snap to nearest data point
        const ratio = (mx - plotL) / plotW;
        const idx = Math.round(ratio * (closes.length - 1));
        const ci = Math.max(0, Math.min(closes.length - 1, idx));
        const px = toX(ci);
        const py = toY(closes[ci]);

        // Vertical + horizontal crosshair
        crossV.setAttribute('x1', px);
        crossV.setAttribute('x2', px);
        crossH.setAttribute('y1', my);
        crossH.setAttribute('y2', my);

        // Dot on data point
        const dotColor = closes[ci] >= baselineVal ? aboveColor : belowColor;
        crossDot.setAttribute('cx', px);
        crossDot.setAttribute('cy', py);
        crossDot.setAttribute('fill', dotColor);

        // Price tag (at cursor Y)
        const cursorPrice = scale.min + (1 - (my - plotT) / plotH) * (scale.max - scale.min);
        const priceText = fmtHover(cursorPrice);
        crossPriceTxt.textContent = priceText;
        crossPriceBg.setAttribute('y', my - 8);
        crossPriceBg.setAttribute('width', Math.max(36, priceText.length * 6 + 8));
        crossPriceTxt.setAttribute('y', my + 3);

        // Date tag
        if (dates[ci]) {
            crossDateTxt.textContent = dates[ci];
            const tw = dates[ci].length * 5 + 12;
            crossDateBg.setAttribute('x', px - tw / 2);
            crossDateBg.setAttribute('width', tw);
            crossDateTxt.setAttribute('x', px);
        }

        if (cfg.onHover) {
            cfg.onHover({ index: ci, date: dates[ci], price: closes[ci] });
        }
    });

    razyui(svg).on('mouseleave', () => {
        crossG.style.display = 'none';
    });

    ctx.container.append(svg);
}

export default installLite;
