/**
 * @fileoverview Chart Trading View feature — candlestick / OHLC financial chart.
 *
 * Lazy-loadable via `installTrading(ctx)`.
 * Adds the `'candlestick'` and `'ohlc'` chart types with:
 *   - Candlestick / OHLC bar rendering
 *   - Volume overlay (optional bottom sub-chart)
 *   - Crosshair with price / date tooltip
 *   - Time axis with dynamic label density
 *   - Price axis with auto-scaling
 *   - Zoom via mouse wheel / pinch
 *   - Pan via click-drag on chart area
 *
 * Data format (each dataset entry = one candle):
 *
 * Full object:
 *   `{ date, open, high, low, close, volume }`
 *
 * Short-key object:
 *   `{ d, o, h, l, c, v }`
 *
 * Tuple array (positional):
 *   `[date, open, high, low, close, volume?]`
 *
 * Columnar (on the dataset object):
 *   `{ columns: ['date','open','high','low','close','volume'],
 *      data: [ [...], ... ] }`
 *
 * Packed binary (ArrayBuffer, 28 bytes/candle):
 *   `[f64 timestamp, f32 open, f32 high, f32 low, f32 close, f32 volume]`
 *
 * Flat TypedArray (interleaved):
 *   `Float64Array([ts, o, h, l, c, v, ts, o, h, l, c, v, ...])`
 *
 * Typed-array columns (struct-of-arrays on the dataset):
 *   `{ t: Float64Array, o: Float32Array, h: Float32Array,
 *      l: Float32Array, c: Float32Array, v?: Float32Array }`
 *
 * Additional config:
 * ```
 * {
 *     type: 'candlestick',    // or 'ohlc'
 *     showVolume: true,       // volume bars at bottom
 *     showCrosshair: true,    // crosshair on hover
 *     candleWidth: 0.7,       // candle width ratio (0–1)
 *     volumeHeight: 0.2,     // volume area as fraction of chart
 *     priceFormat: (v) => v.toFixed(2),
 *     dateFormat: (d) => ...,
 *     visibleBars: 60,       // number of visible candles
 *     zoomStep: 5,           // bars added/removed per zoom tick
 *     enableZoom: true,      // enable scroll-wheel zoom (default true)
 *     enablePan: true,       // enable click-drag pan (default true)
 *     onCrosshair: (info) => {},
 *
 *     // Toolbar plugins — append custom buttons / dropdowns / selects
 *     toolbarPlugins: [
 *         { type: 'button',  label: 'Buy',  className: 'is-buy',
 *           onClick(e, ctrl, cfg) { ... } },
 *         { type: 'button',  label: 'Sell', className: 'is-sell',
 *           onClick(e, ctrl, cfg) { ... } },
 *         { type: 'separator' },
 *         { type: 'select',  label: 'Lot', value: '0.1',
 *           options: [{label:'0.1',value:'0.1'}, ...],
 *           onChange(value, ctrl, cfg) { ... } },
 *         { type: 'dropdown', label: 'Order', options: [...],
 *           onChange(value, ctrl, cfg) { ... } },
 *         { type: 'spacer' },
 *         { type: 'custom',  render(bar, ctx) { return el; } },
 *     ],
 * }
 * ```
 *
 * @module module/Chart/features/trading
 */

import razyui from '../../../index.js';
import Icons from '../../Icons.js';
import { svgEl, niceScale, smoothPath } from '../helpers.js';
import { renderCanvasTrading } from './canvas-trading.js';
import { PART } from '../constants.js';

// ── Constants ────────────────────────────────────

const DEFAULT_UP_COLOR   = 'hsl(145, 55%, 42%)';
const DEFAULT_DOWN_COLOR = 'hsl(0, 65%, 55%)';
const WICK_WIDTH = 1.5;

/** Default timeline intervals shown in the toolbar. */
const DEFAULT_TIMELINES = ['1m', '5m', '15m', '30m', '1h', '4h', '1D', '1W', '1M'];

// ── Data normalisation ───────────────────────────

/**
 * Normalise OHLCV data from any supported format into
 * the canonical `{ date, open, high, low, close, volume }` objects.
 *
 * Supported input formats:
 *
 * 1. **Full object**  (pass-through)
 *    `{ date, open, high, low, close, volume }`
 *
 * 2. **Short-key object**
 *    `{ d|t, o, h, l, c, v }`
 *
 * 3. **Tuple array** (positional)
 *    `[date, open, high, low, close, volume?]`
 *
 * 4. **Columnar object** on the dataset  (`ds.columns`)
 *    `{ columns: ['date','open','high','low','close','volume'],
 *      data: [ [...], ... ] }`
 *    (handled in `renderTrading` before calling this function)
 *
 * 5. **Packed binary** (ArrayBuffer / SharedArrayBuffer)
 *    Each candle = 28 bytes (with volume) or 24 bytes (without):
 *      Float64  timestamp (ms)  — 8 bytes
 *      Float32  open            — 4 bytes
 *      Float32  high            — 4 bytes
 *      Float32  low             — 4 bytes
 *      Float32  close           — 4 bytes
 *      Float32  volume          — 4 bytes  (optional)
 *
 * 6. **Flat TypedArray** (Float64Array / Float32Array)
 *    Interleaved values — every 6 elements = one candle:
 *    `[ts, o, h, l, c, v, ts, o, h, l, c, v, ...]`
 *    Or every 5 elements if `length % 5 === 0 && length % 6 !== 0`.
 *
 * 7. **Typed-array columns** on the dataset object
 *    `{ t: Float64Array, o: Float32Array, h: Float32Array,
 *       l: Float32Array, c: Float32Array, v?: Float32Array }`
 *    (handled in `renderTrading` before calling this function)
 *
 * @param {Array|ArrayBuffer|TypedArray} data — raw data
 * @returns {Array} — array of canonical candle objects
 */
export function normalizeOHLC(data) {
    // ── Format 5: Packed binary (ArrayBuffer) ──
    const hasSAB = typeof SharedArrayBuffer !== 'undefined';
    if (data instanceof ArrayBuffer || (hasSAB && data instanceof SharedArrayBuffer)) {
        const buf = (hasSAB && data instanceof SharedArrayBuffer)
            ? new ArrayBuffer(data.byteLength).transferFrom?.(data) || data
            : data;
        const byteLen = buf.byteLength;
        // Detect stride: 28 bytes (with volume) or 24 bytes (without)
        const STRIDE_V  = 28;  // f64 + 5×f32
        const STRIDE_NV = 24;  // f64 + 4×f32
        const hasVol = byteLen % STRIDE_V === 0;
        const stride = hasVol ? STRIDE_V : STRIDE_NV;
        const count  = Math.floor(byteLen / stride);
        const dv = new DataView(buf);
        const result = new Array(count);
        for (let i = 0; i < count; i++) {
            const off = i * stride;
            result[i] = {
                date:   new Date(dv.getFloat64(off, true)),
                open:   dv.getFloat32(off + 8, true),
                high:   dv.getFloat32(off + 12, true),
                low:    dv.getFloat32(off + 16, true),
                close:  dv.getFloat32(off + 20, true),
                volume: hasVol ? dv.getFloat32(off + 24, true) : 0,
            };
        }
        return result;
    }

    // ── Format 6: Flat TypedArray (Float64Array / Float32Array) ──
    if (ArrayBuffer.isView(data) && !(data instanceof DataView)) {
        const len = data.length;
        // Detect stride: 6 (with volume) or 5 (without)
        const stride = (len % 6 === 0) ? 6 : 5;
        const count = Math.floor(len / stride);
        const result = new Array(count);
        for (let i = 0; i < count; i++) {
            const off = i * stride;
            result[i] = {
                date:   new Date(data[off]),
                open:   data[off + 1],
                high:   data[off + 2],
                low:    data[off + 3],
                close:  data[off + 4],
                volume: stride === 6 ? data[off + 5] : 0,
            };
        }
        return result;
    }

    // Array formats
    if (!data?.length) return data;
    const first = data[0];

    // Already canonical (has 'open' key)
    if (first && typeof first === 'object' && !Array.isArray(first) && 'open' in first) {
        return data;
    }

    // Short-key object  { d|t, o, h, l, c, v }
    if (first && typeof first === 'object' && !Array.isArray(first) && 'o' in first) {
        return data.map(d => ({
            date:   d.d ?? d.t ?? '',
            open:   d.o,
            high:   d.h,
            low:    d.l,
            close:  d.c,
            volume: d.v ?? 0,
        }));
    }

    // Tuple array  [date, o, h, l, c]  or  [date, o, h, l, c, vol]
    if (Array.isArray(first) && first.length >= 5) {
        return data.map(a => ({
            date:   a[0],
            open:   a[1],
            high:   a[2],
            low:    a[3],
            close:  a[4],
            volume: a[5] ?? 0,
        }));
    }

    // Fallback — return as-is and let downstream handle it
    return data;
}

// ── Data aggregation ─────────────────────────────

/**
 * Parse an interval string like '5m', '1h', '1D', '1W', '1M'
 * and return a bucket-key function that maps a timestamp (ms) to
 * a grouping key.
 * @param {string} interval
 * @returns {(ts: number) => string|number}
 */
function bucketFn(interval) {
    const m = /^(\d+)(m|h|D|W|M)$/i.exec(interval);
    if (!m) return null;
    const n = parseInt(m[1], 10);
    const unit = m[2];
    switch (unit) {
        case 'm': return (ts) => Math.floor(ts / (n * 60000));
        case 'h': return (ts) => Math.floor(ts / (n * 3600000));
        case 'D': return (ts) => {
            const d = new Date(ts);
            // Floor to calendar day
            return `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
        };
        case 'W': return (ts) => {
            const d = new Date(ts);
            // ISO week number
            const jan1 = new Date(d.getFullYear(), 0, 1);
            const week = Math.ceil(((d - jan1) / 86400000 + jan1.getDay() + 1) / 7);
            return `${d.getFullYear()}-W${week}`;
        };
        case 'M': return (ts) => {
            const d = new Date(ts);
            return `${d.getFullYear()}-${d.getMonth() + 1}`;
        };
    }
    return null;
}

/**
 * Aggregate OHLCV data into a coarser interval.
 * Each entry is expected to have: date, open, high, low, close, volume.
 *
 * @param {Array} data  — array of candle objects
 * @param {string} interval — e.g. '5m', '1h', '1D', '1W', '1M'
 * @returns {Array} — aggregated candle objects
 */
function aggregateOHLC(data, interval) {
    if (!data.length) return data;
    const fn = bucketFn(interval);
    if (!fn) return data;

    const buckets = new Map();
    for (const d of data) {
        const ts = d.date instanceof Date
            ? d.date.getTime()
            : new Date(d.date).getTime();
        const key = fn(ts);
        if (!buckets.has(key)) {
            buckets.set(key, {
                date: d.date,
                open: d.open,
                high: d.high,
                low: d.low,
                close: d.close,
                volume: d.volume || 0,
            });
        } else {
            const b = buckets.get(key);
            if (d.high > b.high) b.high = d.high;
            if (d.low < b.low) b.low = d.low;
            b.close = d.close;
            b.volume += d.volume || 0;
        }
    }
    return [...buckets.values()];
}

// ── Heikin-Ashi transform ─────────────────────────

/**
 * Transform OHLCV data into Heikin-Ashi candles.
 * HA candles smooth out price noise, making trends easier to spot.
 *   HA-Close = (O + H + L + C) / 4
 *   HA-Open  = (prev HA-Open + prev HA-Close) / 2
 *   HA-High  = max(H, HA-Open, HA-Close)
 *   HA-Low   = min(L, HA-Open, HA-Close)
 *
 * @param {Array} data — array of candle objects with open/high/low/close
 * @returns {Array} — Heikin-Ashi candle objects
 */
function heikinAshi(data) {
    if (!data.length) return data;
    const result = [];
    let prev = null;
    for (const d of data) {
        const haClose = (d.open + d.high + d.low + d.close) / 4;
        const haOpen = prev
            ? (prev.open + prev.close) / 2
            : (d.open + d.close) / 2;
        const haHigh = Math.max(d.high, haOpen, haClose);
        const haLow = Math.min(d.low, haOpen, haClose);
        const ha = {
            date: d.date,
            open: +haOpen.toFixed(4), high: +haHigh.toFixed(4),
            low: +haLow.toFixed(4), close: +haClose.toFixed(4),
            volume: d.volume,
        };
        result.push(ha);
        prev = ha;
    }
    return result;
}

// ── Timeline toolbar ─────────────────────────────

/** Display name mapping for type-switcher buttons. */
const TYPE_LABELS = {
    candlestick:  'Candle',
    ohlc:         'OHLC',
    'heikin-ashi': 'Heikin-Ashi',
    'price-line': 'Line',
    baseline:     'Baseline',
};

/** SVG icon — candlestick chart type. */
const CHART_ICON = Icons.svg('chart-bar', { size: 14, strokeWidth: 1.5 });

/** SVG icon — clock. */
const CLOCK_ICON = Icons.svg('clock', { size: 14, strokeWidth: 1.5 });

/**
 * Create a dropdown trigger button + floating menu.
 * @returns {HTMLElement}
 */
function createDropdown(iconHtml, label, options, onSelect) {
    const wrapper = razyui.el('div', { className: 'chart-tb-dropdown', style: 'position:relative' });

    const trigger = razyui.el('button', {
        className: 'chart-tb-btn chart-tb-trigger',
        style: 'display:inline-flex;align-items:center;gap:4px;white-space:nowrap;flex-shrink:0;font-size:0.66rem;line-height:1.2;padding:3px 7px;border:1px solid color-mix(in srgb, var(--ch-border) 82%, var(--ch-bg) 18%);background:color-mix(in srgb, var(--ch-bg) 90%, var(--ch-border) 10%);border-radius:4px;color:var(--ch-text-muted);',
        innerHTML: `<span class="chart-tb-face" style="display:inline-flex;align-items:center;gap:4px;white-space:nowrap;flex-shrink:0;"><span class="chart-tb-icon" style="display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;">${iconHtml}</span><span class="chart-tb-label" style="white-space:nowrap;flex-shrink:0;">${label}</span><span class="chart-tb-caret" style="display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;">${Icons.svg('chevron-down', { size: 12, strokeWidth: 2 })}</span></span>`,
    });

    const menu = razyui.el('div', { className: 'chart-tb-menu' });
    PART.TB_MENU.apply(menu[0] || menu);

    options.forEach(({ label: optLabel, value, active }) => {
        const opt = razyui.el('button', {
            className: 'chart-tb-option' + (active ? ' is-active' : ''),
            textContent: optLabel,
        });
        PART.TB_OPTION.apply(opt[0] || opt);
        opt.on('click', () => {
            menu.removeClass('is-open');
            onSelect(value);
        });
        menu.append(opt);
    });

    trigger.on('click', (e) => {
        e.stopPropagation();
        razyui(document).find('.chart-tb-menu.is-open').each(m => {
            if (m !== menu[0]) razyui(m).removeClass('is-open');
        });
        menu.toggleClass('is-open');
    });

    razyui(document).on('click', () => menu.removeClass('is-open'));

    wrapper.append(trigger)
           .append(menu);
    return wrapper;
}

// ── Toolbar plugin helpers ─────────────────────

/**
 * Create a toolbar button from a plugin definition.
 * Supports: label, icon (SVG/HTML), className, title, disabled, onClick.
 *
 * @param {Object} plugin — { type:'button', label, icon, className, title, disabled, onClick }
 * @param {Object} ctx — chart context
 * @returns {HTMLElement}
 */
function createPluginButton(plugin, ctx) {
    const props = {
        className: 'chart-tb-btn chart-tb-plugin' + (plugin.className ? ` ${plugin.className}` : ''),
        style: 'display:inline-flex;align-items:center;gap:4px;white-space:nowrap;flex-shrink:0;font-size:0.66rem;line-height:1.2;padding:3px 7px;border:1px solid color-mix(in srgb, var(--ch-border) 82%, var(--ch-bg) 18%);background:color-mix(in srgb, var(--ch-bg) 90%, var(--ch-border) 10%);border-radius:4px;color:var(--ch-text-muted);',
        innerHTML: (plugin.icon ? `<span class="chart-tb-icon" style="display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;">${plugin.icon}</span>` : '') + `<span class="chart-tb-label" style="white-space:nowrap;flex-shrink:0;">${plugin.label || ''}</span>`,
    };
    if (plugin.title) props.title = plugin.title;
    if (plugin.disabled) props.disabled = true;
    const btn = razyui.el('button', props);
    btn.on('click', (e) => {
        if (typeof plugin.onClick === 'function') {
            const ctrl = { update: (c) => { Object.assign(ctx.config, c); ctx.rerender(); }, rerender: () => ctx.rerender() };
            plugin.onClick(e, ctrl, ctx.config);
        }
    });
    return btn;
}

/**
 * Create a toolbar dropdown from a plugin definition.
 *
 * @param {Object} plugin — { type:'dropdown', label, icon, options:[{label,value}], value, onChange }
 * @param {Object} ctx — chart context
 * @returns {HTMLElement}
 */
function createPluginDropdown(plugin, ctx) {
    return createDropdown(
        plugin.icon || '',
        plugin.label || '',
        (plugin.options || []).map(o => ({
            label: o.label ?? o.value,
            value: o.value,
            active: o.value === plugin.value,
        })),
        (value) => {
            if (typeof plugin.onChange === 'function') {
                const ctrl = { update: (c) => { Object.assign(ctx.config, c); ctx.rerender(); }, rerender: () => ctx.rerender() };
                plugin.onChange(value, ctrl, ctx.config);
            }
        }
    );
}

/**
 * Create a toolbar <select> box from a plugin definition.
 *
 * @param {Object} plugin — { type:'select', label, options:[{label,value}], value, className, onChange }
 * @param {Object} ctx — chart context
 * @returns {HTMLElement}
 */
function createPluginSelect(plugin, ctx) {
    const wrap = razyui.el('span', { className: 'chart-tb-select-wrap' + (plugin.className ? ` ${plugin.className}` : '') });

    if (plugin.label) {
        const lbl = razyui.el('span', { className: 'chart-tb-select-label', textContent: plugin.label });
        wrap.append(lbl);
    }

    const sel = razyui.el('select', { className: 'chart-tb-select' });
    (plugin.options || []).forEach(o => {
        const opt = razyui.el('option', {
            value: o.value, textContent: o.label ?? o.value,
            ...(o.value === plugin.value ? { selected: true } : {}),
        });
        sel.append(opt);
    });
    sel.on('change', () => {
        if (typeof plugin.onChange === 'function') {
            const ctrl = { update: (c) => { Object.assign(ctx.config, c); ctx.rerender(); }, rerender: () => ctx.rerender() };
            plugin.onChange(sel.val(), ctrl, ctx.config);
        }
    });
    wrap.append(sel);
    return wrap;
}

/**
 * Render toolbar plugin items (buttons, dropdowns, selects, separators, spacers).
 * Appends items to the given toolbar bar element.
 *
 * @param {HTMLElement} bar — toolbar container
 * @param {Array} plugins — array of plugin definitions
 * @param {Object} ctx — chart context
 */
function renderToolbarPlugins(bar, plugins, ctx) {
    if (!Array.isArray(plugins) || !plugins.length) return;
    for (const plugin of plugins) {
        switch (plugin.type) {
            case 'button':
                bar.append(createPluginButton(plugin, ctx));
                break;
            case 'dropdown':
                bar.append(createPluginDropdown(plugin, ctx));
                break;
            case 'select':
                bar.append(createPluginSelect(plugin, ctx));
                break;
            case 'separator': {
                bar.append(razyui.el('span', { className: 'chart-tb-sep' }));
                break;
            }
            case 'spacer': {
                bar.append(razyui.el('span', { className: 'chart-tb-spacer' }));
                break;
            }
            default: {
                // Custom render function: plugin.render(bar, ctx)
                if (typeof plugin.render === 'function') {
                    const el = plugin.render(bar, ctx);
                    if (el instanceof HTMLElement) bar.append(el);
                }
            }
        }
    }
}

/**
 * Render a compact single-row toolbar with dropdown selectors
 * for chart type and timeline interval.
 */
export function renderCompactToolbar(ctx, enableTypes, timelines, activeType, activeTimeline) {
    const bar = razyui.el('div', { className: 'chart-toolbar' });
    PART.TOOLBAR.apply(bar[0] || bar);

    if (Array.isArray(enableTypes) && enableTypes.length > 1) {
        bar.append(createDropdown(
            CHART_ICON,
            TYPE_LABELS[activeType] || activeType,
            enableTypes.map(t => ({ label: TYPE_LABELS[t] || t, value: t, active: t === activeType })),
            (t) => {
                if (ctx.config.type === t) return;
                ctx.config.type = t;
                ctx.config.yMin = null;
                ctx.config.yMax = null;
                ctx.rerender();
            }
        ));
    }

    if (Array.isArray(timelines) && timelines.length) {
        bar.append(createDropdown(
            CLOCK_ICON,
            activeTimeline,
            timelines.map(t => ({ label: t, value: t, active: t === activeTimeline })),
            (t) => {
                ctx.config.timeline = t;
                delete ctx.config._viewStart;
                ctx.rerender();
            }
        ));
    }

    // ── Plugin toolbar items ──
    const toolbarPlugins = ctx.config.toolbarPlugins;
    if (Array.isArray(toolbarPlugins) && toolbarPlugins.length) {
        // Add a separator between built-in and plugin items
        if (bar.children().length) {
            bar.append(razyui.el('span', { className: 'chart-tb-sep' }));
        }
        renderToolbarPlugins(bar, toolbarPlugins, ctx);
    }

    if (bar.children().length) ctx.container.append(bar);
}

// ── Installer ────────────────────────────────────

/**
 * Install trading view chart types onto the Chart context.
 * After calling this, `cfg.type = 'candlestick'` or `'ohlc'` in render()
 * will route to the trading renderer.
 *
 * @param {Object} ctx — chart context bridge
 */
export function installTrading(ctx) {
    ctx._tradingInstalled = true;
}

// ── Main renderer ────────────────────────────────

/**
 * Pre-compute the total height that sub-panel indicators (MACD, RSI, VI,
 * plugins) will need so that `renderTrading` can size the SVG correctly.
 */
function _calcPanelIndicatorHeight(cfg) {
    const GAP = 8;
    const sizes = [];
    const indicators = cfg.indicators || [];
    const plugins = cfg.indicatorPlugins || [];
    for (const ind of indicators) {
        if (ind.type === 'macd')       sizes.push(ind.panelHeight || 80);
        else if (ind.type === 'rsi')   sizes.push(ind.panelHeight || 60);
        else if (ind.type === 'vi')    sizes.push(ind.panelHeight || 60);
    }
    for (const p of plugins) {
        if (p.category !== 'overlay') sizes.push(p.panelHeight || 60);
    }
    if (!sizes.length) return 0;
    // Sum panel heights + gaps between panels (no trailing gap)
    return sizes.reduce((s, v) => s + v, 0) + (sizes.length - 1) * GAP;
}

/**
 * Render a candlestick or OHLC chart.
 *
 * @param {Object} ctx — chart context bridge
 */
export function renderTrading(ctx) {
    const cfg = ctx.config;
    const baseH = typeof cfg.height === 'number' ? cfg.height : 400;

    // Pre-compute total sub-panel indicator height so the SVG can
    // be tall enough to hold price area + volume + indicator panels + X-axis.
    const panelIndicatorH = _calcPanelIndicatorHeight(cfg);
    const svgH = baseH + panelIndicatorH;

    // Axis placement config
    const priceOnRight = cfg.priceAxis === 'right';
    const showPct      = cfg.showPercentage !== false;  // default true

    // Dynamic padding: each side needs room for its axis labels.
    // Price axis text ~45px, percentage axis text ~50px, blank side ~8px.
    const PRICE_PAD = 50;
    const PCT_PAD   = 55;
    const BLANK_PAD = 8;

    let padLeft, padRight;
    if (priceOnRight) {
        padLeft  = showPct ? PCT_PAD : BLANK_PAD;
        padRight = PRICE_PAD;
    } else {
        padLeft  = PRICE_PAD;
        padRight = showPct ? PCT_PAD : BLANK_PAD;
    }
    const pad = { ...cfg.padding, left: padLeft, right: padRight };

    // Measure actual container width so the viewBox fills it with no dead zones.
    // The container is already in the DOM (html('') just cleared its children),
    // so clientWidth reflects the true available width.
    const containerEl = ctx.container[0];
    const measured = containerEl ? containerEl.clientWidth : 0;
    const svgW = measured > 0 ? measured : 600;

    const svg = svgEl('svg', {
        viewBox: `0 0 ${svgW} ${svgH}`,
        class: 'chart-svg chart-trading',
        overflow: 'visible',
    });
    svg.style.width = '100%';
    svg.style.height = svgH + 'px';
    ctx.svg = svg;

    // ── Compact toolbar (chart type + timeline) ──
    const enableTypes = cfg.enableTypes;
    const timelines = cfg.timelines;
    if (timelines?.length) {
        const active = cfg.timeline || (timelines.includes('5m') ? '5m' : timelines[0]);
        if (!cfg.timeline) cfg.timeline = active;
    }
    renderCompactToolbar(ctx, enableTypes, timelines, cfg.type, cfg.timeline || null);

    const ds = cfg.datasets[0];
    // Binary / typed-array data may not have .length — check differently
    const hasData = ds?.data && (
        (ds.data.length > 0) ||
        (ds.data instanceof ArrayBuffer && ds.data.byteLength > 0) ||
        (ArrayBuffer.isView(ds.data) && ds.data.length > 0) ||
        (ds.t && ds.t.length > 0)  // typed-array columns on ds
    );
    if (!hasData) {
        ctx.container.append(svg);
        return;
    }

    // Normalise compact formats → canonical { date, open, high, low, close, volume }
    let rawData;

    // Format 7: Typed-array columns on the dataset
    // e.g. { t: Float64Array, o: Float32Array, h: Float32Array, ... }
    if (ds.t && ArrayBuffer.isView(ds.t)) {
        const len = ds.t.length;
        rawData = new Array(len);
        for (let i = 0; i < len; i++) {
            rawData[i] = {
                date:   new Date(ds.t[i]),
                open:   (ds.o || ds.open)?.[i]   ?? 0,
                high:   (ds.h || ds.high)?.[i]   ?? 0,
                low:    (ds.l || ds.low)?.[i]    ?? 0,
                close:  (ds.c || ds.close)?.[i]  ?? 0,
                volume: (ds.v || ds.volume)?.[i]  ?? 0,
            };
        }
    }
    // Format 4: Columnar (ds.columns + array-of-arrays)
    else if (Array.isArray(ds.columns) && ds.columns.length >= 5 && Array.isArray(ds.data[0])) {
        const ci = {};
        ds.columns.forEach((k, i) => { ci[k] = i; });
        rawData = ds.data.map(row => ({
            date:   row[ci.date   ?? ci.d ?? ci.t ?? 0],
            open:   row[ci.open   ?? ci.o ?? 1],
            high:   row[ci.high   ?? ci.h ?? 2],
            low:    row[ci.low    ?? ci.l ?? 3],
            close:  row[ci.close  ?? ci.c ?? 4],
            volume: row[ci.volume ?? ci.v ?? 5] ?? 0,
        }));
    }
    // Formats 1-3, 5-6 (handled by normalizeOHLC)
    else {
        rawData = normalizeOHLC(ds.data);
    }

    // Aggregate raw data by the selected timeline interval
    let allData = cfg.timeline
        ? aggregateOHLC(rawData, cfg.timeline)
        : rawData;

    // Apply Heikin-Ashi transformation when requested
    if (cfg.type === 'heikin-ashi') allData = heikinAshi(allData);

    const upColor   = ds.upColor   || cfg.upColor   || DEFAULT_UP_COLOR;
    const downColor = ds.downColor || cfg.downColor || DEFAULT_DOWN_COLOR;

    // Viewport range (for pan / zoom)
    const visibleBars = cfg.visibleBars || Math.min(allData.length, 60);
    const startIdx = Math.max(0, (cfg._viewStart ?? allData.length - visibleBars));
    const endIdx = Math.min(allData.length, startIdx + visibleBars);
    const viewData = allData.slice(startIdx, endIdx);

    if (!viewData.length) {
        ctx.container.append(svg);
        return;
    }

    // Layout regions
    const volumeH = cfg.showVolume !== false
        ? baseH * (cfg.volumeHeight || 0.2)
        : 0;
    const priceAreaTop = pad.top;
    const priceAreaH = baseH - pad.top - pad.bottom - volumeH;
    const volumeTop = priceAreaTop + priceAreaH + 4;
    const plotW = svgW - pad.left - pad.right;

    // ── Price scale ──
    let pMin = Infinity, pMax = -Infinity;
    let vMax = 0;
    for (const d of viewData) {
        if (d.low  < pMin) pMin = d.low;
        if (d.high > pMax) pMax = d.high;
        if (d.volume > vMax) vMax = d.volume;
    }
    if (cfg.yMin !== null) pMin = cfg.yMin;
    if (cfg.yMax !== null) pMax = cfg.yMax;

    const priceScale = niceScale(pMin, pMax, 6);
    const pRange = priceScale.max - priceScale.min || 1;
    const toY = (v) => priceAreaTop + priceAreaH - ((v - priceScale.min) / pRange) * priceAreaH;

    // ── Grid + price axis ──
    const gridG = svgEl('g', { class: 'chart-grid' });
    const axisG = svgEl('g', { class: 'chart-axis' });
    svg.appendChild(gridG);
    svg.appendChild(axisG);

    const fmtPrice = cfg.priceFormat || ((v) => Number(v).toFixed(2));

    // Reference open price for percentage axis (first visible candle)
    const refOpen = viewData[0].open;

    // ── Candle geometry (shared) ──
    const candleCount = viewData.length;
    const candleSpacing = plotW / candleCount;
    const candleW = candleSpacing * (cfg.candleWidth || 0.7);
    const isOHLC = cfg.type === 'ohlc';

    // Date formatting
    const fmtDate = cfg.dateFormat || ((d) => {
        if (d instanceof Date) {
            return d.getHours()
                ? `${d.getMonth() + 1}/${d.getDate()} ${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`
                : `${d.getMonth() + 1}/${d.getDate()}`;
        }
        if (typeof d === 'string') {
            if (d.includes('T')) {
                const dt = new Date(d);
                return `${dt.getMonth() + 1}/${dt.getDate()} ${String(dt.getHours()).padStart(2,'0')}:${String(dt.getMinutes()).padStart(2,'0')}`;
            }
            return d;
        }
        const dt = new Date(d);
        return `${dt.getMonth() + 1}/${dt.getDate()}`;
    });

    let isDailyPlus = /^\d+(D|W|M)$/i.test(cfg.timeline || '');
    if (!isDailyPlus && !cfg.timeline && viewData.length >= 2) {
        const gaps = [];
        for (let gi = 1; gi < Math.min(viewData.length, 20); gi++) {
            const t0 = new Date(viewData[gi - 1].date).getTime();
            const t1 = new Date(viewData[gi].date).getTime();
            if (!isNaN(t0) && !isNaN(t1)) gaps.push(t1 - t0);
        }
        if (gaps.length) {
            gaps.sort((a, b) => a - b);
            const median = gaps[Math.floor(gaps.length / 2)];
            if (median >= 18 * 3600000) isDailyPlus = true;
        }
    }

    const fmtAxisDate = cfg.axisDateFormat || ((d) => {
        const dt = d instanceof Date ? d : new Date(typeof d === 'string' ? d : d);
        if (isNaN(dt.getTime())) return typeof d === 'string' ? d : '';
        if (isDailyPlus) {
            const unit = (cfg.timeline || '').slice(-1).toUpperCase();
            if (unit === 'W' || unit === 'M') {
                return `${String(dt.getFullYear()).slice(-2)}-${String(dt.getMonth() + 1).padStart(2,'0')}`;
            }
            return `${dt.getMonth() + 1}/${dt.getDate()}`;
        }
        return `${String(dt.getHours()).padStart(2,'0')}:${String(dt.getMinutes()).padStart(2,'0')}`;
    });

    // ═══ Canvas fast-path ═══
    // Canvas replaces per-candle SVG DOM elements with immediate-mode
    // 2D drawing — dramatically faster pan/zoom with large datasets.
    if (cfg.useCanvas !== false) {
        ctx.svg = null;
        cfg._rendered = true;
        return renderCanvasTrading(ctx, {
            svgW, svgH, baseH, pad, allData, upColor, downColor,
            isOHLC, isDailyPlus, fmtPrice, fmtDate, fmtAxisDate,
            priceOnRight, showPct,
        });
    }

    if (cfg.grid !== false) {
        priceScale.steps.forEach(v => {
            const y = toY(v);
            if (y >= priceAreaTop && y <= priceAreaTop + priceAreaH) {
                gridG.appendChild(svgEl('line', {
                    x1: pad.left, y1: y, x2: pad.left + plotW, y2: y,
                    stroke: ctx.css('--rui-border'), 'stroke-width': 0.5, 'stroke-dasharray': '3,3',
                }));

                // Price axis (configurable side)
                const priceX = priceOnRight
                    ? svgW - pad.right + 4
                    : pad.left - 4;
                const priceAnchor = priceOnRight ? 'start' : 'end';
                const priceTxt = svgEl('text', {
                    x: priceX, y: y + 3,
                    'text-anchor': priceAnchor, 'font-size': '10',
                    fill: ctx.css('--rui-text-muted'),
                });
                priceTxt.textContent = fmtPrice(v);
                axisG.appendChild(priceTxt);

                // Percentage axis (opposite side, optional)
                if (showPct && refOpen) {
                    const pct = ((v - refOpen) / refOpen) * 100;
                    const pctX = priceOnRight
                        ? pad.left - 4
                        : svgW - pad.right + 4;
                    const pctAnchor = priceOnRight ? 'end' : 'start';
                    const pctTxt = svgEl('text', {
                        x: pctX, y: y + 3,
                        'text-anchor': pctAnchor, 'font-size': '10',
                        fill: pct >= 0 ? upColor : downColor,
                    });
                    pctTxt.textContent = `${pct >= 0 ? '+' : ''}${pct.toFixed(1)}%`;
                    axisG.appendChild(pctTxt);
                }
            }
        });
    }

    const dataG = svgEl('g', { class: 'chart-data chart-candles' });
    svg.appendChild(dataG);

    // Date axis labels (sampled)
    const maxDateLabels = Math.floor(plotW / 60);
    const labelStep = Math.max(1, Math.ceil(candleCount / maxDateLabels));

    viewData.forEach((d, i) => {
        const cx = pad.left + candleSpacing * i + candleSpacing / 2;
        const isUp = d.close >= d.open;
        const color = isUp ? upColor : downColor;

        const highY = toY(d.high);
        const lowY = toY(d.low);
        const openY = toY(d.open);
        const closeY = toY(d.close);
        const bodyTop = Math.min(openY, closeY);
        const bodyH = Math.max(1, Math.abs(closeY - openY));

        if (isOHLC) {
            // OHLC bars: vertical line + left tick (open) + right tick (close)
            const ohlcG = svgEl('g', {
                class: 'chart-ohlc', 'data-ds': 0, 'data-idx': startIdx + i,
            });

            // Wick
            ohlcG.appendChild(svgEl('line', {
                x1: cx, y1: highY, x2: cx, y2: lowY,
                stroke: color, 'stroke-width': WICK_WIDTH,
            }));
            // Open tick (left)
            ohlcG.appendChild(svgEl('line', {
                x1: cx - candleW / 2, y1: openY, x2: cx, y2: openY,
                stroke: color, 'stroke-width': WICK_WIDTH,
            }));
            // Close tick (right)
            ohlcG.appendChild(svgEl('line', {
                x1: cx, y1: closeY, x2: cx + candleW / 2, y2: closeY,
                stroke: color, 'stroke-width': WICK_WIDTH,
            }));

            dataG.appendChild(ohlcG);
        } else {
            // Candlestick: wick line + body rect
            const candleG = svgEl('g', {
                class: 'chart-candle', 'data-ds': 0, 'data-idx': startIdx + i,
            });

            // Wick
            candleG.appendChild(svgEl('line', {
                x1: cx, y1: highY, x2: cx, y2: lowY,
                stroke: color, 'stroke-width': WICK_WIDTH,
            }));

            // Body
            candleG.appendChild(svgEl('rect', {
                x: cx - candleW / 2, y: bodyTop,
                width: candleW, height: bodyH,
                rx: 1,
                fill: isUp ? 'none' : color,
                stroke: color,
                'stroke-width': 1.2,
            }));

            dataG.appendChild(candleG);

            // Entry animation (skip on rerender to avoid flash)
            if (cfg.animate && !cfg._rendered) {
                candleG.style.opacity = '0';
                candleG.style.transition = `opacity ${cfg.duration || 600}ms ease-out`;
                const delay = (i / candleCount) * (cfg.duration || 600) * 0.5;
                setTimeout(() => { candleG.style.opacity = '1'; }, delay);
            }
        }

        // Date labels — placed just below the price/volume area
        if (i % labelStep === 0) {
            const txt = svgEl('text', {
                x: cx, y: baseH - pad.bottom / 2,
                'text-anchor': 'middle', 'dominant-baseline': 'central',
                'font-size': '10', fill: ctx.css('--rui-text-muted'),
            });
            txt.textContent = fmtAxisDate(d.date);
            axisG.appendChild(txt);
        }
    });

    // ── Date / year-crossing separator lines ──
    // Intraday intervals → draw day-crossing lines when the calendar date changes.
    // All intervals       → draw year-crossing lines when the year changes.
    for (let i = 1; i < viewData.length; i++) {
        const prevDate = new Date(viewData[i - 1].date);
        const currDate = new Date(viewData[i].date);
        if (isNaN(prevDate.getTime()) || isNaN(currDate.getTime())) continue;

        const yearCrossing = prevDate.getFullYear() !== currDate.getFullYear();
        const dayCrossing  = !isDailyPlus && (
            prevDate.getFullYear() !== currDate.getFullYear() ||
            prevDate.getMonth()    !== currDate.getMonth()    ||
            prevDate.getDate()     !== currDate.getDate()
        );

        if (yearCrossing || dayCrossing) {
            const cx = pad.left + candleSpacing * i;
            const opacity = yearCrossing ? '0.35' : '0.18';
            gridG.appendChild(svgEl('line', {
                x1: cx, y1: priceAreaTop, x2: cx, y2: priceAreaTop + priceAreaH,
                stroke: ctx.css('--rui-text-muted'), 'stroke-width': 1,
                'stroke-opacity': opacity,
                class: yearCrossing ? 'chart-year-line' : 'chart-date-line',
            }));
            // Label: year for year-crossing, mm/dd for day-crossing
            const label = yearCrossing
                ? String(currDate.getFullYear())
                : `${currDate.getMonth() + 1}/${currDate.getDate()}`;
            const labelTxt = svgEl('text', {
                x: cx + 4, y: priceAreaTop + 12,
                'font-size': '9', 'font-weight': '600',
                fill: ctx.css('--rui-text-muted'), 'fill-opacity': yearCrossing ? '0.5' : '0.4',
            });
            labelTxt.textContent = label;
            gridG.appendChild(labelTxt);
        }
    }

    // ── Volume overlay ──
    if (cfg.showVolume !== false && vMax > 0) {
        const volG = svgEl('g', { class: 'chart-volume' });
        svg.appendChild(volG);

        // Volume axis separator
        volG.appendChild(svgEl('line', {
            x1: pad.left, y1: volumeTop - 2,
            x2: pad.left + plotW, y2: volumeTop - 2,
            stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
        }));

        const volAreaH = volumeH - 8;

        viewData.forEach((d, i) => {
            const cx = pad.left + candleSpacing * i + candleSpacing / 2;
            const isUp = d.close >= d.open;
            const color = isUp ? upColor : downColor;
            const volH = (d.volume / vMax) * volAreaH;
            const volY = volumeTop + volAreaH - volH;

            const rect = svgEl('rect', {
                x: cx - candleW / 2, y: volY,
                width: candleW, height: volH,
                fill: color, 'fill-opacity': '0.35',
                class: 'chart-vol-bar',
            });

            if (cfg.animate && !cfg._rendered) {
                rect.setAttribute('height', '0');
                rect.setAttribute('y', String(volumeTop + volAreaH));
                rect.style.transition = `height ${cfg.duration || 600}ms ease-out, y ${cfg.duration || 600}ms ease-out`;
                const delay = (i / candleCount) * (cfg.duration || 600) * 0.3;
                setTimeout(() => {
                    rect.setAttribute('height', String(volH));
                    rect.setAttribute('y', String(volY));
                }, delay);
            }

            volG.appendChild(rect);
        });
    }

    // ── Current price line ──
    // Persistent dashed line at last close price with a colored price badge.
    if (cfg.showCurrentPrice !== false) {
        const lastCandle = viewData[viewData.length - 1];
        const isLastUp = lastCandle.close >= lastCandle.open;
        const lastColor = isLastUp ? upColor : downColor;
        const lastY = toY(lastCandle.close);

        // Dashed line spanning full plot width
        svg.appendChild(svgEl('line', {
            x1: pad.left, y1: lastY, x2: svgW - pad.right, y2: lastY,
            stroke: lastColor, 'stroke-width': 1,
            'stroke-dasharray': '4,2', 'stroke-opacity': '0.7',
            class: 'chart-current-price-line',
        }));

        // Price badge on the price-axis side
        const badgeH = 16;
        let badgeX, badgeW, badgeTxtX, badgeTxtAnchor;
        if (priceOnRight) {
            badgeW = pad.right - 2;
            badgeX = svgW - pad.right + 1;
            badgeTxtX = svgW - 4;
            badgeTxtAnchor = 'end';
        } else {
            badgeW = pad.left - 2;
            badgeX = 1;
            badgeTxtX = pad.left - 4;
            badgeTxtAnchor = 'end';
        }
        svg.appendChild(svgEl('rect', {
            x: badgeX, y: lastY - badgeH / 2,
            width: badgeW, height: badgeH, rx: 2,
            fill: lastColor, class: 'chart-current-price-badge',
        }));
        const badgeTxt = svgEl('text', {
            x: badgeTxtX, y: lastY + 3.5,
            'text-anchor': badgeTxtAnchor,
            'font-size': '9', 'font-weight': '600', fill: '#fff',
        });
        badgeTxt.textContent = fmtPrice(lastCandle.close);
        svg.appendChild(badgeTxt);
    }

    // ── Annotations (markers, lines, events) ──
    if (cfg.annotations) {
        renderAnnotations(svg, cfg.annotations, viewData, {
            pad, plotW, priceAreaTop, priceAreaH, candleSpacing, startIdx,
            svgW, toY, fmtPrice,
        }, ctx);
    }

    // ── OHLC header overlay (top-left of chart area) ──
    // Permanently shows the last candle's O/H/L/C values inside the SVG.
    const headerG = svgEl('g', { class: 'chart-ohlc-header' });
    {
        const lastD = viewData[viewData.length - 1];
        const change = lastD.close - lastD.open;
        const isUp = change >= 0;
        const color = isUp ? upColor : downColor;
        const headerX = pad.left + 4;
        const headerY = pad.top + 12;
        const fs = '10';
        const mutedFill = ctx.css('--rui-text-muted');

        const items = [
            { label: 'O', value: fmtPrice(lastD.open) },
            { label: 'H', value: fmtPrice(lastD.high) },
            { label: 'L', value: fmtPrice(lastD.low) },
            { label: 'C', value: fmtPrice(lastD.close) },
        ];
        if (lastD.volume != null) {
            items.push({ label: 'Vol', value: lastD.volume.toLocaleString() });
        }
        let xOff = headerX;
        for (const { label, value } of items) {
            const lbl = svgEl('text', {
                x: xOff, y: headerY, 'font-size': fs, fill: mutedFill,
            });
            lbl.textContent = label + ' ';
            headerG.appendChild(lbl);
            xOff += label.length * 6 + 4;

            const val = svgEl('text', {
                x: xOff, y: headerY, 'font-size': fs, 'font-weight': '600', fill: color,
            });
            val.textContent = value;
            headerG.appendChild(val);
            xOff += value.length * 5.5 + 10;
        }
    }
    svg.appendChild(headerG);

    // ── Crosshair ──
    if (cfg.showCrosshair !== false) {
        const crossG = svgEl('g', { class: 'chart-crosshair', style: 'display:none' });
        const crossH = svgEl('line', {
            x1: pad.left, y1: 0, x2: pad.left + plotW, y2: 0,
            stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.5, 'stroke-dasharray': '4,3',
        });
        const crossV = svgEl('line', {
            x1: 0, y1: priceAreaTop, x2: 0, y2: priceAreaTop + priceAreaH,
            stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.5, 'stroke-dasharray': '4,3',
        });
        // Price tag on whichever side the price axis is
        const tagOnRight = priceOnRight;
        const priceTag = svgEl('rect', {
            x: tagOnRight ? svgW - pad.right : 0,
            y: 0,
            width: tagOnRight ? pad.right : pad.left,
            height: 16,
            rx: 2, fill: 'hsl(220, 12%, 22%)',
        });
        const priceTxt = svgEl('text', {
            x: tagOnRight ? svgW - 4 : pad.left - 4,
            y: 12,
            'text-anchor': 'end', 'font-size': '10', fill: '#fff',
        });
        // Date tag on X-axis at crosshair position
        const dateTag = svgEl('rect', {
            x: 0, y: baseH - pad.bottom, width: 70, height: 16,
            rx: 2, fill: 'hsl(220, 12%, 22%)',
        });
        const dateTxt = svgEl('text', {
            x: 0, y: baseH - pad.bottom + 11,
            'text-anchor': 'middle', 'font-size': '9', fill: '#fff',
        });

        crossG.appendChild(crossH);
        crossG.appendChild(crossV);
        crossG.appendChild(priceTag);
        crossG.appendChild(priceTxt);
        crossG.appendChild(dateTag);
        crossG.appendChild(dateTxt);
        svg.appendChild(crossG);

        // Highlighted candle tracking
        let highlightedCandle = null;

        // Mouse move handler — uses getScreenCTM for accurate coordinate mapping
        const handleCrosshair = (e) => {
            const ctm = svg.getScreenCTM();
            if (!ctm) return;
            const inv = ctm.inverse();
            const mx = e.clientX * inv.a + e.clientY * inv.c + inv.e;
            const my = e.clientX * inv.b + e.clientY * inv.d + inv.f;

            if (mx < pad.left || mx > pad.left + plotW ||
                my < priceAreaTop || my > priceAreaTop + priceAreaH) {
                crossG.style.display = 'none';
                if (highlightedCandle) {
                    highlightedCandle.style.filter = '';
                    highlightedCandle = null;
                }
                return;
                return;
            }

            crossG.style.display = '';

            // Snap X to nearest candle center
            let candleIdx = Math.floor((mx - pad.left) / candleSpacing);
            candleIdx = Math.max(0, Math.min(candleCount - 1, candleIdx));
            const snappedX = pad.left + candleIdx * candleSpacing + candleSpacing / 2;

            crossH.setAttribute('y1', my);
            crossH.setAttribute('y2', my);
            crossV.setAttribute('x1', snappedX);
            crossV.setAttribute('x2', snappedX);
            priceTag.setAttribute('y', my - 8);
            priceTxt.setAttribute('y', my + 3);

            const price = priceScale.min + (1 - (my - priceAreaTop) / priceAreaH) * pRange;
            priceTxt.textContent = fmtPrice(price);

            // Date tag at bottom X-axis
            if (candleIdx >= 0 && candleIdx < viewData.length) {
                const dateLabel = fmtAxisDate(viewData[candleIdx].date);
                dateTxt.textContent = dateLabel;
                const tw = dateLabel.length * 5 + 12;
                dateTag.setAttribute('x', snappedX - tw / 2);
                dateTag.setAttribute('width', tw);
                dateTxt.setAttribute('x', snappedX);
            }

            // Highlight hovered candle
            const candleEls = dataG.children;
            if (candleIdx >= 0 && candleIdx < candleEls.length) {
                if (highlightedCandle && highlightedCandle !== candleEls[candleIdx]) {
                    highlightedCandle.style.filter = '';
                }
                highlightedCandle = candleEls[candleIdx];
                highlightedCandle.style.filter = 'brightness(1.3)';
            }

            // Update OHLC header for hovered candle
            if (candleIdx >= 0 && candleIdx < viewData.length) {
                const hd = viewData[candleIdx];
                const hChange = hd.close - hd.open;
                const hColor = hChange >= 0 ? upColor : downColor;
                const hItems = [
                    { label: 'O', value: fmtPrice(hd.open) },
                    { label: 'H', value: fmtPrice(hd.high) },
                    { label: 'L', value: fmtPrice(hd.low) },
                    { label: 'C', value: fmtPrice(hd.close) },
                ];
                if (hd.volume != null) hItems.push({ label: 'Vol', value: hd.volume.toLocaleString() });
                // Replace header content
                while (headerG.firstChild) headerG.removeChild(headerG.firstChild);
                let hx = pad.left + 4;
                for (const { label, value } of hItems) {
                    const lbl = svgEl('text', {
                        x: hx, y: pad.top + 12, 'font-size': '10', fill: ctx.css('--rui-text-muted'),
                    });
                    lbl.textContent = label + ' ';
                    headerG.appendChild(lbl);
                    hx += label.length * 6 + 4;
                    const val = svgEl('text', {
                        x: hx, y: pad.top + 12, 'font-size': '10', 'font-weight': '600', fill: hColor,
                    });
                    val.textContent = value;
                    headerG.appendChild(val);
                    hx += value.length * 5.5 + 10;
                }
                // Indicator values rows (auto-wrap when exceeding plot width)
                ctx._indicatorRows = 0;
                if (ctx._indicatorSeries?.length) {
                    const maxX = pad.left + plotW - 10;
                    let ix = pad.left + 4;
                    let row = 0;
                    for (const series of ctx._indicatorSeries) {
                        const sv = series.values[candleIdx];
                        if (sv == null) continue;
                        const fmt = series.fmt || fmtPrice;
                        const fmtVal = fmt(sv);
                        const labelW = series.label.length * 6.2 + 6;
                        const valW = fmtVal.length * 6 + 12;
                        const itemW = labelW + valW;
                        // Wrap to next row if this item would overflow
                        if (ix + itemW > maxX && ix > pad.left + 4) {
                            row++;
                            ix = pad.left + 4;
                        }
                        const iy = pad.top + 24 + row * 13;
                        const lbl = svgEl('text', {
                            x: ix, y: iy, 'font-size': '10', fill: ctx.css('--rui-text-muted'),
                        });
                        lbl.textContent = series.label;
                        headerG.appendChild(lbl);
                        ix += labelW;
                        const val = svgEl('text', {
                            x: ix, y: iy, 'font-size': '10', 'font-weight': '600', fill: series.color,
                        });
                        val.textContent = fmtVal;
                        headerG.appendChild(val);
                        ix += valW;
                    }
                    ctx._indicatorRows = row + 1;
                }
            }

            // Show tooltip for hovered candle
            if (candleIdx >= 0 && candleIdx < viewData.length) {
                const d = viewData[candleIdx];
                if (ctx.tooltip) {
                    const change = d.close - d.open;
                    const changePct = ((change / d.open) * 100).toFixed(2);
                    const changeSign = change >= 0 ? '+' : '';
                    ctx.tooltip.html(
                        `<strong>${fmtDate(d.date)}</strong><br>` +
                        `O: ${fmtPrice(d.open)}  H: ${fmtPrice(d.high)}<br>` +
                        `L: ${fmtPrice(d.low)}  C: ${fmtPrice(d.close)}<br>` +
                        (d.volume ? `Vol: ${d.volume.toLocaleString()}<br>` : '') +
                        `<span style="color:${change >= 0 ? upColor : downColor}">${changeSign}${fmtPrice(change)} (${changeSign}${changePct}%)</span>`
                    );
                    ctx.tooltip.addClass('is-visible');

                    // Position tooltip near cursor, flip to avoid overflow
                    const containerRect = (ctx.container[0] || ctx.container).getBoundingClientRect();
                    const tipEl = ctx.tooltip[0] || ctx.tooltip.el;
                    const tipW = tipEl ? tipEl.offsetWidth : 140;
                    const tipH = tipEl ? tipEl.offsetHeight : 100;

                    let tl = e.clientX - containerRect.left + 16;
                    let tt = e.clientY - containerRect.top - 8;
                    if (tl + tipW > containerRect.width) tl = e.clientX - containerRect.left - tipW - 16;
                    if (tt + tipH > containerRect.height) tt = containerRect.height - tipH - 4;
                    if (tt < 0) tt = 4;
                    ctx.tooltip.css({ left: tl + 'px', top: tt + 'px' });
                }

                if (typeof cfg.onCrosshair === 'function') {
                    cfg.onCrosshair({
                        date: d.date, open: d.open, high: d.high,
                        low: d.low, close: d.close, volume: d.volume,
                        price, index: startIdx + candleIdx,
                    });
                }
            }
        };

        razyui(svg).on('mousemove', handleCrosshair);
        razyui(svg).on('mouseleave', () => {
            crossG.style.display = 'none';
            if (highlightedCandle) {
                highlightedCandle.style.filter = '';
                highlightedCandle = null;
            }
            if (ctx.tooltip) ctx.tooltip.removeClass('is-visible');
        });
    }

    // ── Y-axis drag zones (cursor hint) ──
    // Transparent rects over axis areas with ns-resize cursor.
    svg.appendChild(svgEl('rect', {
        x: 0, y: priceAreaTop, width: pad.left, height: priceAreaH,
        fill: 'transparent', style: 'cursor:ns-resize',
        class: 'chart-axis-zone',
    }));
    svg.appendChild(svgEl('rect', {
        x: svgW - pad.right, y: priceAreaTop, width: pad.right, height: priceAreaH,
        fill: 'transparent', style: 'cursor:ns-resize',
        class: 'chart-axis-zone',
    }));

    // ── Pan / Zoom wiring ──
    setupPanZoom(ctx, svg, allData, viewData, startIdx, endIdx, visibleBars, pad, plotW, candleSpacing, priceAreaTop, priceAreaH, svgH);

    cfg._rendered = true;

    // Return layout info so indicator overlays can be drawn afterwards
    return {
        svg, viewData, pad, plotW, priceAreaTop, priceAreaH,
        priceScale, candleSpacing, startIdx, svgW, baseH,
        toY, fmtPrice, allData,
    };
}

// ── Annotations ──────────────────────────────────

/**
 * Render chart annotations — markers, price lines, vertical lines,
 * trendlines, and event flags.
 *
 * Config: `cfg.annotations` array of annotation objects:
 *
 * Marker (point on chart):
 *   { type: 'marker', date, price, label?, color?, shape?, size? }
 *   shape: 'circle' (default) | 'triangle-up' | 'triangle-down' | 'diamond' | 'square'
 *
 * Horizontal price line:
 *   { type: 'hline', price, label?, color?, dash?, width? }
 *
 * Vertical date line:
 *   { type: 'vline', date, label?, color?, dash?, width? }
 *
 * Trendline (between two points):
 *   { type: 'trendline', from: {date, price}, to: {date, price}, color?, dash?, width?, label? }
 *
 * Event flag (small label above/below a candle):
 *   { type: 'event', date, label, color?, position? ('top'|'bottom') }
 *
 * Range highlight:
 *   { type: 'range', from: date, to: date, color?, opacity? }
 *
 * @param {SVGElement} svg
 * @param {Array} annotations
 * @param {Array} viewData
 * @param {Object} layout — { pad, plotW, priceAreaTop, priceAreaH, candleSpacing, startIdx, toY, fmtPrice }
 * @param {Object} ctx
 */
function renderAnnotations(svg, annotations, viewData, layout, ctx) {
    if (!Array.isArray(annotations) || !annotations.length) return;

    const { pad, plotW, priceAreaTop, priceAreaH, candleSpacing, startIdx, svgW } = layout;
    const toY = layout.toY;
    const fmtPrice = layout.fmtPrice;
    const annoG = svgEl('g', { class: 'chart-annotations' });

    /** Find the X position for a given date value in the visible data. */
    function dateToX(date) {
        const target = date instanceof Date ? date.getTime()
            : typeof date === 'number' ? date
            : new Date(date).getTime();
        for (let i = 0; i < viewData.length; i++) {
            const d = viewData[i].date;
            const ts = d instanceof Date ? d.getTime() : new Date(d).getTime();
            if (ts >= target) {
                // Snap to nearest candle
                if (i > 0) {
                    const prevTs = viewData[i - 1].date instanceof Date
                        ? viewData[i - 1].date.getTime()
                        : new Date(viewData[i - 1].date).getTime();
                    if (target - prevTs < ts - target) {
                        return pad.left + (i - 1) * candleSpacing + candleSpacing / 2;
                    }
                }
                return pad.left + i * candleSpacing + candleSpacing / 2;
            }
        }
        // Past the end — place at last candle
        return pad.left + (viewData.length - 1) * candleSpacing + candleSpacing / 2;
    }

    for (const ann of annotations) {
        switch (ann.type) {
            case 'marker': {
                const x = dateToX(ann.date);
                const y = toY(ann.price);
                const color = ann.color || 'hsl(45, 85%, 55%)';
                const size = ann.size || 6;
                const shape = ann.shape || 'circle';
                const g = svgEl('g', { class: 'chart-ann-marker' });

                if (shape === 'circle') {
                    g.appendChild(svgEl('circle', { cx: x, cy: y, r: size, fill: color, 'fill-opacity': '0.85' }));
                } else if (shape === 'triangle-up') {
                    const pts = `${x},${y - size} ${x - size},${y + size * 0.6} ${x + size},${y + size * 0.6}`;
                    g.appendChild(svgEl('polygon', { points: pts, fill: color, 'fill-opacity': '0.85' }));
                } else if (shape === 'triangle-down') {
                    const pts = `${x},${y + size} ${x - size},${y - size * 0.6} ${x + size},${y - size * 0.6}`;
                    g.appendChild(svgEl('polygon', { points: pts, fill: color, 'fill-opacity': '0.85' }));
                } else if (shape === 'diamond') {
                    const pts = `${x},${y - size} ${x + size},${y} ${x},${y + size} ${x - size},${y}`;
                    g.appendChild(svgEl('polygon', { points: pts, fill: color, 'fill-opacity': '0.85' }));
                } else if (shape === 'square') {
                    g.appendChild(svgEl('rect', { x: x - size / 2, y: y - size / 2, width: size, height: size, fill: color, 'fill-opacity': '0.85', rx: 1 }));
                }

                if (ann.label) {
                    const lbl = svgEl('text', {
                        x, y: y - size - 4,
                        'text-anchor': 'middle', 'font-size': '9', 'font-weight': '600',
                        fill: color,
                    });
                    lbl.textContent = ann.label;
                    g.appendChild(lbl);
                }
                annoG.appendChild(g);
                break;
            }

            case 'hline': {
                const y = toY(ann.price);
                const color = ann.color || 'hsl(45, 85%, 55%)';
                const dash = ann.dash || '6,3';
                const width = ann.width || 1;
                annoG.appendChild(svgEl('line', {
                    x1: pad.left, y1: y, x2: pad.left + plotW, y2: y,
                    stroke: color, 'stroke-width': width, 'stroke-dasharray': dash,
                    'stroke-opacity': '0.8', class: 'chart-ann-hline',
                }));
                if (ann.label) {
                    const lbl = svgEl('text', {
                        x: pad.left + plotW + 4, y: y + 3,
                        'font-size': '9', 'font-weight': '600', fill: color,
                    });
                    lbl.textContent = ann.label || fmtPrice(ann.price);
                    annoG.appendChild(lbl);
                }
                break;
            }

            case 'vline': {
                const x = dateToX(ann.date);
                const color = ann.color || 'hsl(270, 55%, 56%)';
                const dash = ann.dash || '6,3';
                const width = ann.width || 1;
                annoG.appendChild(svgEl('line', {
                    x1: x, y1: priceAreaTop, x2: x, y2: priceAreaTop + priceAreaH,
                    stroke: color, 'stroke-width': width, 'stroke-dasharray': dash,
                    'stroke-opacity': '0.8', class: 'chart-ann-vline',
                }));
                if (ann.label) {
                    const lbl = svgEl('text', {
                        x, y: priceAreaTop - 4,
                        'text-anchor': 'middle', 'font-size': '9', fill: color,
                    });
                    lbl.textContent = ann.label;
                    annoG.appendChild(lbl);
                }
                break;
            }

            case 'trendline': {
                if (!ann.from || !ann.to) break;
                const x1 = dateToX(ann.from.date);
                const y1 = toY(ann.from.price);
                const x2 = dateToX(ann.to.date);
                const y2 = toY(ann.to.price);
                const color = ann.color || 'hsl(216, 72%, 56%)';
                const dash = ann.dash || '';
                const width = ann.width || 1.5;
                annoG.appendChild(svgEl('line', {
                    x1, y1, x2, y2,
                    stroke: color, 'stroke-width': width,
                    ...(dash ? { 'stroke-dasharray': dash } : {}),
                    'stroke-linecap': 'round', class: 'chart-ann-trendline',
                }));
                if (ann.label) {
                    const mx = (x1 + x2) / 2;
                    const my = (y1 + y2) / 2;
                    const lbl = svgEl('text', {
                        x: mx, y: my - 6,
                        'text-anchor': 'middle', 'font-size': '9', 'font-weight': '600',
                        fill: color,
                    });
                    lbl.textContent = ann.label;
                    annoG.appendChild(lbl);
                }
                break;
            }

            case 'event': {
                const x = dateToX(ann.date);
                const color = ann.color || 'hsl(45, 85%, 55%)';
                const pos = ann.position || 'top';
                const y = pos === 'top' ? priceAreaTop + 6 : priceAreaTop + priceAreaH - 6;
                const flagH = 14;
                const text = ann.label || '';
                const tw = text.length * 5 + 8;

                const g = svgEl('g', { class: 'chart-ann-event' });
                // Flag pole
                g.appendChild(svgEl('line', {
                    x1: x, y1: pos === 'top' ? priceAreaTop : priceAreaTop + priceAreaH,
                    x2: x, y2: y,
                    stroke: color, 'stroke-width': 1, 'stroke-opacity': '0.5',
                }));
                // Flag background
                g.appendChild(svgEl('rect', {
                    x: x - tw / 2, y: pos === 'top' ? y - flagH : y,
                    width: tw, height: flagH, rx: 2,
                    fill: color, 'fill-opacity': '0.9',
                }));
                // Flag text
                const lbl = svgEl('text', {
                    x, y: pos === 'top' ? y - flagH / 2 + 3.5 : y + flagH / 2 + 3.5,
                    'text-anchor': 'middle', 'font-size': '8', 'font-weight': '700',
                    fill: '#fff',
                });
                lbl.textContent = text;
                g.appendChild(lbl);
                annoG.appendChild(g);
                break;
            }

            case 'range': {
                const x1 = dateToX(ann.from);
                const x2 = dateToX(ann.to);
                const color = ann.color || 'hsl(216, 72%, 56%)';
                const opacity = ann.opacity ?? 0.08;
                annoG.appendChild(svgEl('rect', {
                    x: Math.min(x1, x2), y: priceAreaTop,
                    width: Math.abs(x2 - x1), height: priceAreaH,
                    fill: color, 'fill-opacity': opacity,
                    class: 'chart-ann-range',
                }));
                break;
            }
        }
    }

    svg.appendChild(annoG);
}

// ── Timeline Map (mini-map navigator) ────────────

/**
 * Render an interactive timeline map below the chart showing the full
 * dataset as a mini area chart with a draggable viewport window.
 *
 * Config:
 * ```
 * {
 *     timelineMap: true,     // enable/disable (default false)
 *     timelineMapHeight: 48, // px height of the minimap (default 48)
 * }
 * ```
 *
 * @param {Object} ctx
 * @param {Object} layout — from renderTrading()
 */
export function renderTimelineMap(ctx, layout) {
    const cfg = ctx.config;
    const { allData, pad, svgW } = layout;
    if (!allData || allData.length < 2) return;

    const bg = ctx.css('--rui-bg-inset') || ctx.css('--rui-bg') || '#f5f7fb';
    const border = ctx.css('--rui-border') || 'hsl(216, 14%, 85%)';
    const accent = ctx.css('--rui-accent') || 'hsl(216,72%,56%)';
    const muted = ctx.css('--rui-text-muted') || 'hsl(216, 10%, 55%)';

    const mapH = cfg.timelineMapHeight || 48;
    const plotL = pad.left;
    const plotR = svgW - pad.right;
    const plotW = plotR - plotL;

    const totalBars = allData.length;

    function idxToX(idx) {
        return plotL + (idx / Math.max(totalBars - 1, 1)) * plotW;
    }
    function xToIdx(x) {
        const ratio = Math.max(0, Math.min(1, (x - plotL) / plotW));
        return Math.round(ratio * (totalBars - 1));
    }

    // ── Build / rebuild the SVG visual (chart area only, no events) ──
    const rawWrap = ctx._timelineMapEl || razyui.el('div')[0];
    const wrap = razyui(rawWrap);
    wrap.attr('class', 'chart-timeline-map');
    rawWrap.style.cssText = `position:relative;width:100%;height:${mapH}px;margin-top:2px;cursor:crosshair;user-select:none;-webkit-user-select:none;touch-action:none;`;
    wrap.html('');
    ctx._timelineMapEl = rawWrap;

    const mSvg = svgEl('svg', {
        viewBox: `0 0 ${svgW} ${mapH}`,
        class: 'chart-timeline-map-svg',
    });
    mSvg.style.cssText = `width:100%;height:${mapH}px;display:block;`;

    // Background
    mSvg.appendChild(svgEl('rect', {
        x: 0, y: 0, width: svgW, height: mapH,
        class: 'chart-map-bg',
        fill: bg,
        stroke: border,
        'stroke-width': 1,
    }));

    // Mini area chart
    const closes = allData.map(d => d.close ?? d.value ?? 0);
    let cMin = Infinity, cMax = -Infinity;
    for (const c of closes) { if (c < cMin) cMin = c; if (c > cMax) cMax = c; }
    const cRange = cMax - cMin || 1;
    const mPad = 4;

    const points = [];
    for (let i = 0; i < closes.length; i++) {
        const x = plotL + (i / (closes.length - 1)) * plotW;
        const y = mPad + (mapH - mPad * 2) - ((closes[i] - cMin) / cRange) * (mapH - mPad * 2);
        points.push({ x, y });
    }

    const pathD = points.length > 2 ? smoothPath(points) : `M${points[0].x},${points[0].y}L${points[1].x},${points[1].y}`;
    const areaD = pathD + `L${points[points.length - 1].x},${mapH}L${points[0].x},${mapH}Z`;
    mSvg.appendChild(svgEl('path', {
        d: areaD, class: 'chart-map-area', fill: accent, 'fill-opacity': 0.12,
    }));
    mSvg.appendChild(svgEl('path', {
        d: pathD, class: 'chart-map-line', fill: 'none', stroke: accent, 'stroke-width': 1.5,
    }));

    // Dim overlays + window + grips (stored on wrap for in-place updates)
    const dimLeft = svgEl('rect', { x: 0, y: 0, width: 0, height: mapH, class: 'chart-map-dim', fill: muted, 'fill-opacity': 0.08 });
    const dimRight = svgEl('rect', { x: 0, y: 0, width: 0, height: mapH, class: 'chart-map-dim', fill: muted, 'fill-opacity': 0.08 });
    const winRect = svgEl('rect', { x: 0, y: 0.5, width: 0, height: mapH - 1, rx: 2, class: 'chart-map-window', fill: accent, 'fill-opacity': 0.08, stroke: accent, 'stroke-width': 1 });
    const gripL = svgEl('line', { x1: 0, y1: mapH * 0.3, x2: 0, y2: mapH * 0.7, class: 'chart-map-grip', stroke: muted, 'stroke-width': 1.5 });
    const gripR = svgEl('line', { x1: 0, y1: mapH * 0.3, x2: 0, y2: mapH * 0.7, class: 'chart-map-grip', stroke: muted, 'stroke-width': 1.5 });
    mSvg.appendChild(dimLeft);
    mSvg.appendChild(dimRight);
    mSvg.appendChild(winRect);
    mSvg.appendChild(gripL);
    mSvg.appendChild(gripR);
    wrap.append(mSvg);

    // ── Store refs on ctx for the interaction handler ──
    ctx._mapState = {
        svgW, mapH, plotL, plotR, plotW, totalBars,
        idxToX, xToIdx,
        dimLeft, dimRight, winRect, gripL, gripR,
    };

    // Sync window position from current config
    _updateMapVisuals(ctx);

    // ── Bind pointer events ONCE (idempotent) ──
    if (!rawWrap._mapBound) {
        rawWrap._mapBound = true;
        _bindMapPointerEvents(ctx, wrap);
    }

    // Append if not in DOM
    if (!rawWrap.parentNode) {
        ctx.container.append(wrap);
    }
}

/** Update the map window visuals from cfg._viewStart / cfg.visibleBars. */
function _updateMapVisuals(ctx) {
    const cfg = ctx.config;
    const s = ctx._mapState;
    if (!s) return;

    const visibleBars = cfg.visibleBars || 60;
    const startIdx = cfg._viewStart ?? Math.max(0, s.totalBars - visibleBars);
    const winL = Math.max(s.plotL, s.idxToX(startIdx));
    const winR = Math.min(s.plotR, s.idxToX(Math.min(startIdx + visibleBars, s.totalBars)));

    s.winL = winL;
    s.winR = winR;
    s.winRect.setAttribute('x', winL);
    s.winRect.setAttribute('width', Math.max(0, winR - winL));
    s.dimLeft.setAttribute('width', Math.max(0, winL));
    s.dimRight.setAttribute('x', winR);
    s.dimRight.setAttribute('width', Math.max(0, s.svgW - winR));
    s.gripL.setAttribute('x1', winL); s.gripL.setAttribute('x2', winL);
    s.gripR.setAttribute('x1', winR); s.gripR.setAttribute('x2', winR);
}

/**
 * Bind pointer events on the wrapper div — called only once.
 * Uses setPointerCapture so drag continues even if pointer
 * leaves the element. No AbortController needed — the div
 * and its listeners persist for the chart's lifetime.
 */
function _bindMapPointerEvents(ctx, wrap) {
    const cfg = ctx.config;
    const HANDLE_PX = 12; // pixel hit zone for edge handles

    let dragMode = null; // 'pan' | 'left' | 'right'
    let dragStartX = 0;
    let dragWinL = 0;
    let dragWinR = 0;
    let rafId = 0;

    /** Convert pointer clientX to SVG-space X. */
    function toSvgX(e) {
        const rect = wrap.getRect();
        if (!rect.width) return 0;
        const s = ctx._mapState;
        return (e.clientX - rect.left) / rect.width * s.svgW;
    }

    /** HANDLE_PX in SVG coordinate space */
    function handleZone() {
        const rect = wrap.getRect();
        if (!rect.width) return 12;
        return HANDLE_PX / rect.width * ctx._mapState.svgW;
    }

    function storeRange(newStart, newBars) {
        const s = ctx._mapState;
        newBars = Math.max(10, Math.min(s.totalBars, newBars));
        newStart = Math.max(0, Math.min(s.totalBars - newBars, newStart));
        cfg.visibleBars = newBars;
        cfg._viewStart = newStart;
    }

    function scheduleRerender() {
        cancelAnimationFrame(rafId);
        rafId = requestAnimationFrame(() => {
            if (typeof ctx._canvasRedraw === 'function') ctx._canvasRedraw();
            else if (typeof ctx.rerender === 'function') ctx.rerender();
        });
    }

    // ── Pointer down ──
    wrap.on('pointerdown', (e) => {
        e.preventDefault();
        const s = ctx._mapState;
        if (!s) return;

        const mx = toSvgX(e);
        const minWinW = (10 / Math.max(s.totalBars - 1, 1)) * s.plotW;

        // Determine mode based on click position
        const hz = handleZone();
        if (Math.abs(mx - s.winL) < hz) {
            dragMode = 'left';
        } else if (Math.abs(mx - s.winR) < hz) {
            dragMode = 'right';
        } else if (mx > s.winL && mx < s.winR) {
            dragMode = 'pan';
        } else {
            // Click outside → jump center, then start pan
            const winW = s.winR - s.winL;
            let newL = mx - winW / 2;
            newL = Math.max(s.plotL, Math.min(s.plotR - winW, newL));
            s.winL = newL;
            s.winR = newL + winW;
            _updateMapVisuals(ctx);
            storeRange(s.xToIdx(s.winL), s.xToIdx(s.winR) - s.xToIdx(s.winL));
            dragMode = 'pan';
        }

        ctx._mapDragging = true;
        dragStartX = mx;
        dragWinL = s.winL;
        dragWinR = s.winR;
        wrap[0].setPointerCapture(e.pointerId);
        wrap.css('cursor', dragMode === 'pan' ? 'grabbing' : 'ew-resize');
    });

    // ── Pointer move ──
    wrap.on('pointermove', (e) => {
        if (!dragMode) {
            // Hover cursor hint
            const s = ctx._mapState;
            if (!s) return;
            const mx = toSvgX(e);
            const hz = handleZone();
            if (Math.abs(mx - s.winL) < hz || Math.abs(mx - s.winR) < hz) {
                wrap.css('cursor', 'ew-resize');
            } else if (mx > s.winL && mx < s.winR) {
                wrap.css('cursor', 'grab');
            } else {
                wrap.css('cursor', 'crosshair');
            }
            return;
        }

        e.preventDefault();
        const s = ctx._mapState;
        if (!s) return;

        const mx = toSvgX(e);
        const dx = mx - dragStartX;
        const minWinW = (10 / Math.max(s.totalBars - 1, 1)) * s.plotW;

        if (dragMode === 'pan') {
            const winW = dragWinR - dragWinL;
            let newL = dragWinL + dx;
            newL = Math.max(s.plotL, Math.min(s.plotR - winW, newL));
            s.winL = newL;
            s.winR = newL + winW;
        } else if (dragMode === 'left') {
            s.winL = Math.max(s.plotL, Math.min(dragWinR - minWinW, dragWinL + dx));
        } else if (dragMode === 'right') {
            s.winR = Math.min(s.plotR, Math.max(dragWinL + minWinW, dragWinR + dx));
        }

        // Update map visuals in-place
        s.winRect.setAttribute('x', s.winL);
        s.winRect.setAttribute('width', Math.max(0, s.winR - s.winL));
        s.dimLeft.setAttribute('width', Math.max(0, s.winL));
        s.dimRight.setAttribute('x', s.winR);
        s.dimRight.setAttribute('width', Math.max(0, s.svgW - s.winR));
        s.gripL.setAttribute('x1', s.winL); s.gripL.setAttribute('x2', s.winL);
        s.gripR.setAttribute('x1', s.winR); s.gripR.setAttribute('x2', s.winR);

        storeRange(s.xToIdx(s.winL), s.xToIdx(s.winR) - s.xToIdx(s.winL));
        scheduleRerender();
    });

    // ── Pointer up ──
    wrap.on('pointerup', (e) => {
        if (!dragMode) return;
        wrap[0].releasePointerCapture(e.pointerId);
        dragMode = null;
        ctx._mapDragging = false;
        wrap.css('cursor', 'crosshair');
        cancelAnimationFrame(rafId);
        // Canvas fast-path; SVG falls through to full rerender
        if (typeof ctx._canvasRedraw === 'function') ctx._canvasRedraw();
        else if (typeof ctx.rerender === 'function') ctx.rerender();
    });

    // Also handle cancel (e.g. system gesture)
    wrap.on('pointercancel', (e) => {
        if (!dragMode) return;
        dragMode = null;
        ctx._mapDragging = false;
        wrap.css('cursor', 'crosshair');
        cancelAnimationFrame(rafId);
    });
}

// ── Pan & Zoom ───────────────────────────────────

/**
 * Wire up mouse-wheel zoom, click-drag pan (tick-by-tick), and
 * axis-drag Y-scale on the trading chart.
 *
 * Uses an AbortController so every re-render automatically tears down
 * the previous set of listeners — no stacking.
 */
function setupPanZoom(ctx, svg, allData, viewData, startIdx, endIdx, visibleBars, pad, plotW, candleSpacing, priceAreaTop, priceAreaH, svgH) {
    const cfg = ctx.config;
    const zoomStep = cfg.zoomStep || 5;
    const svgW = parseFloat(svg.getAttribute('viewBox').split(' ')[2]);

    // ── Tear down listeners from previous render ──
    if (cfg._panZoomAC) cfg._panZoomAC.abort();
    const ac = new AbortController();
    cfg._panZoomAC = ac;
    const sig = { signal: ac.signal };

    /** Convert a client-space mouse event to SVG-space coords. */
    function toSVG(e) {
        const ctm = svg.getScreenCTM();
        if (!ctm) return { x: 0, y: 0 };
        const inv = ctm.inverse();
        return {
            x: e.clientX * inv.a + e.clientY * inv.c + inv.e,
            y: e.clientX * inv.b + e.clientY * inv.d + inv.f,
        };
    }

    /** Screen-pixels per one candle bar (accounts for SVG scaling). */
    function screenPxPerBar() {
        const ctm = svg.getScreenCTM();
        // ctm.a = horizontal scale (SVG-units → CSS-pixels)
        return ctm ? candleSpacing * ctm.a : candleSpacing;
    }

    // ── Wheel zoom (bound to container so toolbar area also responds) ──
    const host = ctx.container[0] || svg;
    razyui(host).on('wheel', (e) => {
        if (cfg.enableZoom === false) return;
        // Always prevent default scroll — even at zoom limits — so the page
        // doesn't jump when the cursor is over the chart.
        e.preventDefault();
        e.stopPropagation();
        const delta = e.deltaY > 0 ? zoomStep : -zoomStep;
        const newVisible = Math.max(10, Math.min(allData.length, visibleBars + delta));
        if (newVisible === visibleBars) return;

        cfg.visibleBars = newVisible;
        const { x: svgX } = toSVG(e);
        const mx = Math.max(0, Math.min(1, (svgX - pad.left) / plotW));
        const center = startIdx + Math.floor(visibleBars * mx);
        cfg._viewStart = Math.max(0, Math.min(allData.length - newVisible, center - Math.floor(newVisible * mx)));

        if (typeof ctx.rerender === 'function') ctx.rerender();
    }, { passive: false, signal: ac.signal });

    // ── Shared drag state — persisted on cfg so a mid-drag rerender
    //    doesn't lose the ongoing pan / yscale operation. ──
    let mode = cfg._dragMode || null;
    let dragStartX = cfg._dragStartX || 0;
    let dragStartY = cfg._dragStartY || 0;
    let dragViewStart = cfg._dragViewStart ?? 0;
    let lastBarDelta = cfg._lastBarDelta || 0;

    // Restore cursor if we're mid-drag after a rerender
    if (mode === 'pan') svg.style.cursor = 'grabbing';
    else if (mode === 'yscale') svg.style.cursor = 'ns-resize';

    // ── Mousedown — decide mode ──
    razyui(svg).on('mousedown', (e) => {
        if (e.button !== 0) return;
        if (cfg.enablePan === false) return;
        e.preventDefault();
        const { x: sx } = toSVG(e);

        if (sx < pad.left || sx > pad.left + plotW) {
            mode = 'yscale';
            dragStartY = e.clientY;
            cfg._dragMode = 'yscale';
            cfg._dragStartY = e.clientY;
            svg.style.cursor = 'ns-resize';
        } else {
            mode = 'pan';
            dragStartX = e.clientX;
            dragViewStart = cfg._viewStart ?? startIdx;
            lastBarDelta = 0;
            cfg._dragMode = 'pan';
            cfg._dragStartX = e.clientX;
            cfg._dragViewStart = dragViewStart;
            cfg._lastBarDelta = 0;
            svg.style.cursor = 'grabbing';
        }
    }, sig);

    // ── Mousemove ──
    razyui(document).on('mousemove', (e) => {
        if (!mode) return;

        if (mode === 'pan') {
            const pxPB = screenPxPerBar();
            const dx = e.clientX - dragStartX;
            const barsDelta = Math.round(-dx / pxPB);

            if (barsDelta !== lastBarDelta) {
                lastBarDelta = barsDelta;
                cfg._lastBarDelta = barsDelta;
                const newStart = Math.max(0, Math.min(allData.length - visibleBars, dragViewStart + barsDelta));
                if (newStart !== cfg._viewStart) {
                    cfg._viewStart = newStart;
                    if (typeof ctx.rerender === 'function') ctx.rerender();
                }
            }
        } else if (mode === 'yscale') {
            const dy = e.clientY - dragStartY;
            dragStartY = e.clientY;
            cfg._dragStartY = e.clientY;

            const scaleFactor = 1 + dy * 0.001;

            let pMin = cfg.yMin;
            let pMax = cfg.yMax;
            if (pMin == null || pMax == null) {
                let dMin = Infinity, dMax = -Infinity;
                for (const d of viewData) {
                    if (d.low < dMin) dMin = d.low;
                    if (d.high > dMax) dMax = d.high;
                }
                if (pMin == null) pMin = dMin;
                if (pMax == null) pMax = dMax;
            }

            const mid = (pMin + pMax) / 2;
            const half = (pMax - pMin) / 2;
            const newHalf = Math.max(half * scaleFactor, 0.01);
            cfg.yMin = mid - newHalf;
            cfg.yMax = mid + newHalf;

            if (typeof ctx.rerender === 'function') ctx.rerender();
        }
    }, sig);

    // ── Mouseup ──
    razyui(document).on('mouseup', () => {
        mode = null;
        cfg._dragMode = null;
        svg.style.cursor = '';
    }, sig);

    // ── Double-click on axis to reset Y-scale ──
    razyui(svg).on('dblclick', (e) => {
        const { x: sx } = toSVG(e);
        if (sx < pad.left || sx > pad.left + plotW) {
            cfg.yMin = null;
            cfg.yMax = null;
            if (typeof ctx.rerender === 'function') ctx.rerender();
        }
    }, sig);
}

export default installTrading;
