/**
 * @fileoverview Chart component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/Chart.def
 */

import { PART } from './Chart/constants.js';

/**
 * The definition object for the Chart component.
 * Contains metadata, design tokens, state machine configuration, template slots, and custom element details.
 * 
 * @type {Object}
 */
export const ChartDef = {
    /** @type {string} The name of the component. */
    name: 'Chart',
    
    /** @type {string} The custom element tag name. */
    tag: 'rui-chart',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    /**
     * Design tokens for styling the Chart component.
     * Defines CSS variables and their default values or references.
     */
    tokens: {
        prefix: 'ch',
        tokens: {
            'gap':               { value: '0.5rem',           description: 'Chart section gap' },
            'legend-gap':        { value: '0.5rem 1rem',      description: 'Legend gap' },
            'legend-padding':    { value: '0.25rem 0.5rem',   description: 'Legend padding' },
            'legend-font-size':  { value: '0.78rem',          description: 'Legend font size' },
            'swatch-size':       { value: '10px',             description: 'Legend swatch size' },
            'swatch-radius':     { ref: 'radius.sm',          description: 'Legend swatch radius' },
            'tooltip-font-size': { value: '0.75rem',          description: 'Tooltip font size' },
            'tooltip-padding':   { value: '0.25rem 0.5rem',   description: 'Tooltip padding' },
            'tooltip-radius':    { ref: 'radius.sm',          description: 'Tooltip border radius' },
            'tooltip-max-width': { value: '240px',            description: 'Tooltip max width' },
            'tooltip-line-height': { value: '1.5',            description: 'Tooltip line height' },
            'bg':                { ref: 'color.bg',           description: 'Background' },
            'border':            { ref: 'color.border',       description: 'Border color' },
            'font-stack':        { ref: 'font.family',        description: 'Font family' },
            'hue':               { value: '216',              description: 'Base HSL hue for palette' },
            'shadow':            { ref: 'shadow.default',     description: 'Shadow' },
            'space-md':          { value: '1rem',             description: 'Medium spacing' },
            'space-xs':          { value: '0.25rem',          description: 'Extra-small spacing' },
            'text':              { ref: 'color.text',         description: 'Text color' },
            'text-muted':        { ref: 'color.text-muted',   description: 'Muted text color' },
            'text-secondary':    { ref: 'color.text-secondary', description: 'Secondary text' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    /**
     * State machine configuration for managing the chart's rendering state.
     */
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { RENDER: 'rendering' },
            },
            rendering: {
                on: { DONE: 'idle' },
            },
        },
        effects: {},
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    /**
     * Template slots defining the structure and classes of the chart elements.
     */
    template: {
        slots: {
            container: { element: 'div',  classes: ['chart'] },
            svg:       { element: 'svg',  classes: ['chart-svg'] },
            legend:    { element: 'div',  classes: ['chart-legend'] },
            tooltip:   { element: 'div',  classes: ['chart-tooltip'] },
        },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.SVG]: PART.SVG,
        [PART.LEGEND]: PART.LEGEND,
        [PART.LEGEND_ITEM]: PART.LEGEND_ITEM,
        [PART.LEGEND_SWATCH]: PART.LEGEND_SWATCH,
        [PART.TOOLTIP]: PART.TOOLTIP,
        [PART.TOOLBAR]: PART.TOOLBAR,
        [PART.TB_BTN]: PART.TB_BTN,
        [PART.TB_MENU]: PART.TB_MENU,
        [PART.TB_OPTION]: PART.TB_OPTION,
    },

    styles: {},

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    /**
     * Custom element metadata for registering the component.
     */
    ce: {
        tag: 'rui-chart',
        observedAttrs: ['type', 'data', 'options'],
        attrMap: {
            type:    'type',
            data:    'data',
            options: 'options',
        },
    },
};

export default ChartDef;
