/**
 * @fileoverview Chart indicator plugins — technical analysis overlays.
 *
 * Lazy-loadable via `installIndicators(ctx)`.
 * Provides built-in indicators and a plugin API:
 *
 * Built-in indicators:
 *   - **MACD**  (Moving Average Convergence Divergence)
 *   - **RSI**   (Relative Strength Index)
 *   - **VI**    (Volume Index / On-Balance Volume trend)
 *   - **SMA**   (Simple Moving Average — overlay on price)
 *   - **EMA**   (Exponential Moving Average — overlay on price)
 *   - **BB**    (Bollinger Bands — overlay on price)
 *   - **VWAP**  (Volume Weighted Average Price — overlay on price)
 *
 * Indicators are categorised:
 *   - `'overlay'` — drawn on the price chart (SMA, EMA, BB, VWAP)
 *   - `'panel'`   — drawn in a separate sub-chart below (MACD, RSI, VI)
 *
 * Config:
 * ```
 * {
 *     indicators: [
 *         { type: 'sma', period: 20, color: 'hsl(216, 72%, 56%)' },
 *         { type: 'ema', period: 50, color: 'hsl(28, 80%, 52%)'  },
 *         { type: 'bb',  period: 20, stdDev: 2 },
 *         { type: 'macd', fast: 12, slow: 26, signal: 9 },
 *         { type: 'rsi',  period: 14 },
 *         { type: 'vi',   period: 20 },
 *     ],
 *
 *     // Plugin custom indicators:
 *     indicatorPlugins: [
 *         {
 *             type: 'custom-momentum',  // unique type ID
 *             category: 'panel',        // 'panel' or 'overlay'
 *             label: 'Custom Momentum', // panel label
 *             panelHeight: 80,          // panel height (px)
 *             compute(data, cfg) {
 *                 // data = OHLCV slice, return computed values
 *                 return data.map(d => d.close - d.open);
 *             },
 *             render(ctx, panelG, values, layout, cfg) {
 *                 // layout.helpers has: svgEl, smoothPath,
 *                 //   sma, ema, macd, rsi, bollingerBands,
 *                 //   toY, closes, viewData
 *                 const { svgEl, smoothPath } = layout.helpers;
 *                 // draw with svgEl / smoothPath ...
 *             },
 *         }
 *     ],
 * }
 * ```
 *
 * @module module/Chart/features/indicators
 */

import { svgEl, niceScale, smoothPath } from '../helpers.js';

// ══════════════════════════════════════════
//  Math helpers
// ══════════════════════════════════════════

/**
 * Simple Moving Average.
 * @param {number[]} data — close prices
 * @param {number} period
 * @returns {(number|null)[]}
 */
export function sma(data, period) {
    const result = [];
    for (let i = 0; i < data.length; i++) {
        if (i < period - 1) { result.push(null); continue; }
        let sum = 0;
        for (let j = i - period + 1; j <= i; j++) sum += data[j];
        result.push(sum / period);
    }
    return result;
}

/**
 * Exponential Moving Average.
 * @param {number[]} data
 * @param {number} period
 * @returns {(number|null)[]}
 */
export function ema(data, period) {
    const k = 2 / (period + 1);
    const result = [];
    let prev = null;
    for (let i = 0; i < data.length; i++) {
        if (i < period - 1) { result.push(null); continue; }
        if (prev === null) {
            // Seed with SMA
            let sum = 0;
            for (let j = i - period + 1; j <= i; j++) sum += data[j];
            prev = sum / period;
        } else {
            prev = data[i] * k + prev * (1 - k);
        }
        result.push(prev);
    }
    return result;
}

/**
 * Bollinger Bands.
 * @param {number[]} data — close prices
 * @param {number} period
 * @param {number} stdDev — number of standard deviations
 * @returns {{ upper: (number|null)[], middle: (number|null)[], lower: (number|null)[] }}
 */
export function bollingerBands(data, period, stdDev = 2) {
    const mid = sma(data, period);
    const upper = [];
    const lower = [];
    for (let i = 0; i < data.length; i++) {
        if (mid[i] === null) { upper.push(null); lower.push(null); continue; }
        let variance = 0;
        for (let j = i - period + 1; j <= i; j++) {
            variance += (data[j] - mid[i]) ** 2;
        }
        const sd = Math.sqrt(variance / period);
        upper.push(mid[i] + stdDev * sd);
        lower.push(mid[i] - stdDev * sd);
    }
    return { upper, middle: mid, lower };
}

/**
 * MACD (Moving Average Convergence Divergence).
 * @param {number[]} data — close prices
 * @param {number} fast — fast EMA period (default 12)
 * @param {number} slow — slow EMA period (default 26)
 * @param {number} signal — signal EMA period (default 9)
 * @returns {{ macd: (number|null)[], signal: (number|null)[], histogram: (number|null)[] }}
 */
export function macd(data, fast = 12, slow = 26, signal = 9) {
    const fastEma = ema(data, fast);
    const slowEma = ema(data, slow);
    const macdLine = data.map((_, i) => {
        if (fastEma[i] === null || slowEma[i] === null) return null;
        return fastEma[i] - slowEma[i];
    });

    // Signal line = EMA of MACD line (only non-null values)
    const validMacd = macdLine.filter(v => v !== null);
    const sigVals = ema(validMacd, signal);

    // Map signal values back to original indices
    const signalLine = [];
    let si = 0;
    for (let i = 0; i < macdLine.length; i++) {
        if (macdLine[i] === null) { signalLine.push(null); continue; }
        signalLine.push(sigVals[si] ?? null);
        si++;
    }

    const histogram = macdLine.map((v, i) => {
        if (v === null || signalLine[i] === null) return null;
        return v - signalLine[i];
    });

    return { macd: macdLine, signal: signalLine, histogram };
}

/**
 * RSI (Relative Strength Index).
 * @param {number[]} data — close prices
 * @param {number} period (default 14)
 * @returns {(number|null)[]}
 */
export function rsi(data, period = 14) {
    const result = [];
    if (data.length < period + 1) {
        return data.map(() => null);
    }

    // Calculate initial average gain/loss
    let avgGain = 0, avgLoss = 0;
    for (let i = 1; i <= period; i++) {
        const change = data[i] - data[i - 1];
        if (change > 0) avgGain += change;
        else avgLoss += Math.abs(change);
        result.push(null);
    }
    avgGain /= period;
    avgLoss /= period;

    // First RSI
    result[0] = null; // pad first
    const rs0 = avgLoss === 0 ? 100 : avgGain / avgLoss;
    result.push(100 - 100 / (1 + rs0));

    // Subsequent RSI
    for (let i = period + 1; i < data.length; i++) {
        const change = data[i] - data[i - 1];
        const gain = change > 0 ? change : 0;
        const loss = change < 0 ? Math.abs(change) : 0;
        avgGain = (avgGain * (period - 1) + gain) / period;
        avgLoss = (avgLoss * (period - 1) + loss) / period;
        const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
        result.push(100 - 100 / (1 + rs));
    }

    return result;
}

/**
 * Volume Index (On-Balance Volume simplified trend).
 * @param {Array} data — OHLCV objects
 * @param {number} period — smoothing period
 * @returns {(number|null)[]}
 */
export function volumeIndex(data, period = 20) {
    // Cumulative OBV
    const obv = [0];
    for (let i = 1; i < data.length; i++) {
        if (data[i].close > data[i - 1].close) {
            obv.push(obv[i - 1] + (data[i].volume || 0));
        } else if (data[i].close < data[i - 1].close) {
            obv.push(obv[i - 1] - (data[i].volume || 0));
        } else {
            obv.push(obv[i - 1]);
        }
    }
    // Smooth with SMA
    return sma(obv, period);
}

/**
 * VWAP (Volume Weighted Average Price).
 * Cumulative (TP × Volume) / cumulative Volume, where TP = (H+L+C)/3.
 * Resets each session — for simplicity this computes a rolling VWAP across
 * the entire visible dataset (intraday reset would require session boundaries).
 *
 * @param {Array} data — OHLCV objects
 * @returns {(number|null)[]}
 */
export function vwap(data) {
    const result = [];
    let cumTPV = 0;
    let cumVol = 0;
    for (let i = 0; i < data.length; i++) {
        const d = data[i];
        const tp = (d.high + d.low + d.close) / 3;
        const vol = d.volume || 0;
        cumTPV += tp * vol;
        cumVol += vol;
        result.push(cumVol > 0 ? cumTPV / cumVol : null);
    }
    return result;
}

// ══════════════════════════════════════════
//  Installer
// ══════════════════════════════════════════

/**
 * Install indicator capabilities onto the Chart context.
 * @param {Object} ctx
 */
export function installIndicators(ctx) {
    ctx._indicatorsInstalled = true;
}

// ══════════════════════════════════════════
//  Rendering
// ══════════════════════════════════════════

/**
 * Render all configured indicators onto a trading chart.
 * Should be called AFTER renderTrading() to add overlays and panels.
 *
 * @param {Object} ctx
 * @param {SVGElement} svg — the trading chart SVG
 * @param {Array} viewData — visible OHLCV data slice
 * @param {Object} layout — { pad, plotW, priceAreaTop, priceAreaH, priceScale, candleSpacing, startIdx }
 */
export function renderIndicators(ctx, svg, viewData, layout) {
    const cfg = ctx.config;
    const indicators = cfg.indicators || [];
    const plugins = cfg.indicatorPlugins || [];
    const allIndicators = [...indicators];

    if (!allIndicators.length && !plugins.length) return;

    // Store computed indicator values for crosshair display
    ctx._indicatorSeries = [];

    // Compute indicators from the FULL dataset so values at viewport edges
    // are accurate (e.g. SMA(20) needs 20 bars before the first visible bar).
    const allData = layout.allData || viewData;
    const allCloses = allData.map(d => d.close);
    const { pad, plotW, priceAreaTop, priceAreaH, priceScale, candleSpacing, startIdx } = layout;
    const viewLen = viewData.length;
    const pRange = priceScale.max - priceScale.min || 1;
    const toY = (v) => priceAreaTop + priceAreaH - ((v - priceScale.min) / pRange) * priceAreaH;

    /** Slice a full-length indicator array to the visible viewport range. */
    const sliceView = (arr) => arr.slice(startIdx, startIdx + viewLen);

    // ── Overlay indicators (drawn on price chart) ──
    for (const ind of allIndicators) {
        if (ind.type === 'sma' || ind.type === 'ema') {
            const allVals = ind.type === 'ema' ? ema(allCloses, ind.period || 20) : sma(allCloses, ind.period || 20);
            const viewVals = sliceView(allVals);
            renderMALine(ctx, svg, viewVals, ind, layout, toY);
            ctx._indicatorSeries.push({
                label: `${ind.type.toUpperCase()}(${ind.period || 20})`,
                color: ind.color || (ind.type === 'ema' ? 'hsl(28, 80%, 52%)' : 'hsl(216, 72%, 56%)'),
                values: viewVals,
            });
        } else if (ind.type === 'bb') {
            const allBB = bollingerBands(allCloses, ind.period || 20, ind.stdDev || 2);
            const viewUpper = sliceView(allBB.upper);
            const viewMiddle = sliceView(allBB.middle);
            const viewLower = sliceView(allBB.lower);
            renderBollingerBands(ctx, svg, viewUpper, viewMiddle, viewLower, ind, layout, toY);
            const color = ind.color || 'hsl(270, 55%, 56%)';
            ctx._indicatorSeries.push({ label: `BB↑(${ind.period || 20})`, color, values: viewUpper });
            ctx._indicatorSeries.push({ label: `BB(${ind.period || 20})`, color, values: viewMiddle });
            ctx._indicatorSeries.push({ label: `BB↓(${ind.period || 20})`, color, values: viewLower });
        } else if (ind.type === 'vwap') {
            const allVwap = vwap(allData);
            const viewVwap = sliceView(allVwap);
            renderVWAPLine(ctx, svg, viewVwap, ind, layout, toY);
            ctx._indicatorSeries.push({
                label: 'VWAP', color: ind.color || 'hsl(45, 85%, 50%)',
                values: viewVwap,
            });
        }
    }

    // ── Panel indicators (drawn in sub-charts below the X-axis) ──
    // layout.baseH is the original chart height (price + volume + X-axis).
    // Indicator panels start right below that.
    const baseH = layout.baseH || (typeof cfg.height === 'number' ? cfg.height : 400);
    let panelOffset = baseH;

    for (const ind of allIndicators) {
        if (ind.type === 'macd') {
            const panelH = ind.panelHeight || 80;
            const fast = ind.fast || 12, slow = ind.slow || 26, sig = ind.signal || 9;
            const mResult = macd(allCloses, fast, slow, sig);
            const viewMacd = sliceView(mResult.macd);
            const viewSig = sliceView(mResult.signal);
            const viewHist = sliceView(mResult.histogram);
            renderMACDPanel(ctx, svg, viewMacd, viewSig, viewHist, ind, layout, panelOffset, panelH);
            ctx._indicatorSeries.push({
                label: `MACD(${fast},${slow},${sig})`, color: ind.macdColor || 'hsl(216, 72%, 56%)',
                values: viewMacd, fmt: v => v.toFixed(2),
            });
            ctx._indicatorSeries.push({
                label: 'Sig', color: ind.signalColor || 'hsl(340, 65%, 55%)',
                values: viewSig, fmt: v => v.toFixed(2),
            });
            ctx._indicatorSeries.push({
                label: 'Hist', color: 'hsl(216, 50%, 50%)',
                values: viewHist, fmt: v => v.toFixed(2),
            });
            panelOffset += panelH + 8;
        } else if (ind.type === 'rsi') {
            const panelH = ind.panelHeight || 60;
            const allRsi = rsi(allCloses, ind.period || 14);
            const viewRsi = sliceView(allRsi);
            renderRSIPanel(ctx, svg, viewRsi, ind, layout, panelOffset, panelH);
            ctx._indicatorSeries.push({
                label: `RSI(${ind.period || 14})`, color: ind.color || 'hsl(270, 55%, 56%)',
                values: viewRsi, fmt: v => v.toFixed(1),
            });
            panelOffset += panelH + 8;
        } else if (ind.type === 'vi') {
            const panelH = ind.panelHeight || 60;
            const allVI = volumeIndex(allData, ind.period || 20);
            const viewVI = sliceView(allVI);
            renderVIPanel(ctx, svg, viewVI, ind, layout, panelOffset, panelH);
            ctx._indicatorSeries.push({
                label: `VI(${ind.period || 20})`, color: ind.color || 'hsl(175, 55%, 40%)',
                values: viewVI, fmt: v => v.toFixed(0),
            });
            panelOffset += panelH + 8;
        }
    }

    // ── Plugin indicators ──
    for (const plugin of plugins) {
        if (typeof plugin.compute !== 'function' || typeof plugin.render !== 'function') continue;
        // Plugin receives allData for full-range computation
        const values = plugin.compute(allData, plugin, { startIdx, viewLen });
        const viewValues = Array.isArray(values) ? values.slice(startIdx, startIdx + viewLen) : values;
        if (Array.isArray(viewValues)) {
            ctx._indicatorSeries.push({
                label: plugin.label || plugin.type || 'Plugin',
                color: plugin.color || ctx.css('--rui-text'),
                values: viewValues, fmt: plugin.fmt,
            });
        }
        const panelH = plugin.panelHeight || 60;

        // Build rich helpers object for plugin authors
        const helpers = {
            svgEl,
            smoothPath,
            sma, ema, bollingerBands,
            macd, rsi, volumeIndex, vwap,
            toY,           // price-to-Y coordinate converter
            allCloses,     // full close-price array
            viewData,      // visible OHLCV slice
            allData,       // full OHLCV array
            startIdx, viewLen,
            sliceView,     // helper to slice full-range arrays to viewport
        };

        if (plugin.category === 'overlay') {
            plugin.render(ctx, svg, viewValues, { ...layout, toY, helpers }, plugin);
        } else {
            const panelG = svgEl('g', { class: `chart-indicator-${plugin.type}` });

            // Panel separator line
            panelG.appendChild(svgEl('line', {
                x1: pad.left, y1: panelOffset, x2: pad.left + plotW, y2: panelOffset,
                stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
            }));

            // Panel label
            if (plugin.label) {
                const label = svgEl('text', {
                    x: pad.left + 4, y: panelOffset + 12,
                    'font-size': '9', fill: ctx.css('--rui-text-muted'),
                });
                label.textContent = plugin.label;
                panelG.appendChild(label);
            }

            svg.appendChild(panelG);
            plugin.render(ctx, panelG, viewValues, { ...layout, panelTop: panelOffset, panelH, helpers }, plugin);
            panelOffset += panelH + 8;
        }
    }
}

// ── MA Line (SMA / EMA overlay) ──

function renderMALine(ctx, svg, values, ind, layout, toY) {
    const color = ind.color || (ind.type === 'ema' ? 'hsl(28, 80%, 52%)' : 'hsl(216, 72%, 56%)');
    const { pad, candleSpacing } = layout;

    const points = [];
    values.forEach((v, i) => {
        if (v === null) return;
        points.push({
            x: pad.left + candleSpacing * i + candleSpacing / 2,
            y: toY(v),
        });
    });

    if (points.length < 2) return;

    const d = points.length > 2 ? smoothPath(points) : `M${points[0].x},${points[0].y}L${points[1].x},${points[1].y}`;
    const line = svgEl('path', {
        d,
        fill: 'none', stroke: color, 'stroke-width': '1.5',
        'stroke-linejoin': 'round', 'stroke-linecap': 'round',
        class: `chart-indicator-line chart-${ind.type}`,
        'stroke-opacity': '0.8',
    });
    svg.appendChild(line);
}

// ── Bollinger Bands (overlay) ──

function renderBollingerBands(ctx, svg, upper, middle, lower, ind, layout, toY) {
    const { pad, candleSpacing } = layout;
    const color = ind.color || 'hsl(270, 55%, 56%)';

    // Upper & lower band fill
    const upperPts = [], lowerPts = [], midPts = [];
    for (let i = 0; i < upper.length; i++) {
        if (upper[i] === null) continue;
        const x = pad.left + candleSpacing * i + candleSpacing / 2;
        upperPts.push({ x, y: toY(upper[i]) });
        lowerPts.push({ x, y: toY(lower[i]) });
        midPts.push({ x, y: toY(middle[i]) });
    }

    if (upperPts.length < 2) return;

    // Fill area between upper and lower
    const upperD = upperPts.length > 2 ? smoothPath(upperPts) : `M${upperPts[0].x},${upperPts[0].y}` + upperPts.slice(1).map(p => `L${p.x},${p.y}`).join('');
    const lowerReversed = [...lowerPts].reverse();
    const lowerD = lowerReversed.map(p => `L${p.x},${p.y}`).join('');

    const fill = svgEl('path', {
        d: upperD + lowerD + 'Z',
        fill: color, 'fill-opacity': '0.06',
        class: 'chart-bb-fill',
    });
    svg.appendChild(fill);

    // Upper line
    svg.appendChild(svgEl('path', {
        d: upperD,
        fill: 'none', stroke: color, 'stroke-width': '1', 'stroke-opacity': '0.5',
        'stroke-dasharray': '4,2', class: 'chart-bb-upper',
    }));

    // Lower line
    const lowerLineD = lowerPts.length > 2
        ? smoothPath(lowerPts)
        : `M${lowerPts[0].x},${lowerPts[0].y}` + lowerPts.slice(1).map(p => `L${p.x},${p.y}`).join('');
    svg.appendChild(svgEl('path', {
        d: lowerLineD,
        fill: 'none', stroke: color, 'stroke-width': '1', 'stroke-opacity': '0.5',
        'stroke-dasharray': '4,2', class: 'chart-bb-lower',
    }));

    // Middle line (SMA)
    const midD = midPts.length > 2 ? smoothPath(midPts) : `M${midPts[0].x},${midPts[0].y}` + midPts.slice(1).map(p => `L${p.x},${p.y}`).join('');
    svg.appendChild(svgEl('path', {
        d: midD,
        fill: 'none', stroke: color, 'stroke-width': '1.2', 'stroke-opacity': '0.7',
        class: 'chart-bb-mid',
    }));
}

// ── VWAP Line (overlay) ──

function renderVWAPLine(ctx, svg, values, ind, layout, toY) {
    const color = ind.color || 'hsl(45, 85%, 50%)';
    const { pad, candleSpacing } = layout;

    const points = [];
    values.forEach((v, i) => {
        if (v === null) return;
        points.push({
            x: pad.left + candleSpacing * i + candleSpacing / 2,
            y: toY(v),
        });
    });

    if (points.length < 2) return;

    const d = points.length > 2 ? smoothPath(points) : `M${points[0].x},${points[0].y}L${points[1].x},${points[1].y}`;
    const line = svgEl('path', {
        d,
        fill: 'none', stroke: color, 'stroke-width': '1.8',
        'stroke-linejoin': 'round', 'stroke-linecap': 'round',
        class: 'chart-indicator-line chart-vwap',
        'stroke-opacity': '0.85',
    });
    svg.appendChild(line);

    // VWAP label near last point
    const last = points[points.length - 1];
    const label = svgEl('text', {
        x: last.x + 4, y: last.y - 4,
        'font-size': '8', 'font-weight': '600', fill: color,
    });
    label.textContent = 'VWAP';
    svg.appendChild(label);
}

// ── MACD Panel ──

function renderMACDPanel(ctx, svg, macdVals, signalVals, histVals, ind, layout, panelTop, panelH) {
    const fast = ind.fast || 12;
    const slow = ind.slow || 26;
    const signal = ind.signal || 9;
    const { pad, plotW, candleSpacing } = layout;

    const g = svgEl('g', { class: 'chart-indicator-macd' });

    // Panel label
    const label = svgEl('text', {
        x: pad.left + 4, y: panelTop + 12,
        'font-size': '9', fill: ctx.css('--rui-text-muted'),
    });
    label.textContent = `MACD (${fast},${slow},${signal})`;
    g.appendChild(label);

    // Panel separator
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: panelTop, x2: pad.left + plotW, y2: panelTop,
        stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
    }));

    // Scale for MACD values
    const allV = macdVals.filter(v => v !== null);
    const sigV = signalVals.filter(v => v !== null);
    const hstV = histVals.filter(v => v !== null);
    const all = [...allV, ...sigV, ...hstV];
    if (!all.length) { svg.appendChild(g); return; }

    const vMin = Math.min(...all);
    const vMax = Math.max(...all);
    const vRange = vMax - vMin || 1;
    const plotArea = panelH - 20;
    const toMY = (v) => panelTop + 16 + plotArea - ((v - vMin) / vRange) * plotArea;
    const zeroY = toMY(0);

    // Histogram bars
    histVals.forEach((v, i) => {
        if (v === null) return;
        const cx = pad.left + candleSpacing * i + candleSpacing / 2;
        const barW = candleSpacing * 0.5;
        const y = toMY(v);
        const h = Math.abs(y - zeroY);
        g.appendChild(svgEl('rect', {
            x: cx - barW / 2, y: v >= 0 ? y : zeroY,
            width: barW, height: h,
            fill: v >= 0 ? 'hsl(145, 55%, 42%)' : 'hsl(0, 65%, 55%)',
            'fill-opacity': '0.5',
        }));
    });

    // MACD line
    const macdPts = [];
    macdVals.forEach((v, i) => {
        if (v === null) return;
        macdPts.push({ x: pad.left + candleSpacing * i + candleSpacing / 2, y: toMY(v) });
    });
    if (macdPts.length > 1) {
        const d = macdPts.length > 2 ? smoothPath(macdPts) : `M${macdPts[0].x},${macdPts[0].y}L${macdPts[1].x},${macdPts[1].y}`;
        g.appendChild(svgEl('path', {
            d, fill: 'none', stroke: ind.macdColor || 'hsl(216, 72%, 56%)',
            'stroke-width': '1.5', class: 'chart-macd-line',
        }));
    }

    // Signal line
    const sigPts = [];
    signalVals.forEach((v, i) => {
        if (v === null) return;
        sigPts.push({ x: pad.left + candleSpacing * i + candleSpacing / 2, y: toMY(v) });
    });
    if (sigPts.length > 1) {
        const d = sigPts.length > 2 ? smoothPath(sigPts) : `M${sigPts[0].x},${sigPts[0].y}L${sigPts[1].x},${sigPts[1].y}`;
        g.appendChild(svgEl('path', {
            d, fill: 'none', stroke: ind.signalColor || 'hsl(340, 65%, 55%)',
            'stroke-width': '1.2', 'stroke-dasharray': '3,2', class: 'chart-macd-signal',
        }));
    }

    // Zero line
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: zeroY, x2: pad.left + plotW, y2: zeroY,
        stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.5, 'stroke-opacity': '0.4',
    }));

    svg.appendChild(g);
}

// ── RSI Panel ──

function renderRSIPanel(ctx, svg, values, ind, layout, panelTop, panelH) {
    const period = ind.period || 14;
    const { pad, plotW, candleSpacing } = layout;

    const g = svgEl('g', { class: 'chart-indicator-rsi' });

    // Label
    const label = svgEl('text', {
        x: pad.left + 4, y: panelTop + 12,
        'font-size': '9', fill: ctx.css('--rui-text-muted'),
    });
    label.textContent = `RSI (${period})`;
    g.appendChild(label);

    // Separator
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: panelTop, x2: pad.left + plotW, y2: panelTop,
        stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
    }));

    const plotArea = panelH - 20;
    const toRY = (v) => panelTop + 16 + plotArea - (v / 100) * plotArea;

    // Overbought / oversold zones
    const obLevel = ind.overbought || 70;
    const osLevel = ind.oversold || 30;

    // Zone fill (30–70)
    g.appendChild(svgEl('rect', {
        x: pad.left, y: toRY(obLevel),
        width: plotW, height: toRY(osLevel) - toRY(obLevel),
        fill: ctx.css('--rui-text-muted'), 'fill-opacity': '0.04',
    }));

    // Overbought line
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: toRY(obLevel), x2: pad.left + plotW, y2: toRY(obLevel),
        stroke: 'hsl(0, 65%, 55%)', 'stroke-width': 0.5, 'stroke-dasharray': '3,3', 'stroke-opacity': '0.5',
    }));
    // Oversold line
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: toRY(osLevel), x2: pad.left + plotW, y2: toRY(osLevel),
        stroke: 'hsl(145, 55%, 42%)', 'stroke-width': 0.5, 'stroke-dasharray': '3,3', 'stroke-opacity': '0.5',
    }));

    // 50 center line
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: toRY(50), x2: pad.left + plotW, y2: toRY(50),
        stroke: ctx.css('--rui-text-muted'), 'stroke-width': 0.5, 'stroke-opacity': '0.3',
    }));

    // RSI line
    const pts = [];
    values.forEach((v, i) => {
        if (v === null) return;
        pts.push({ x: pad.left + candleSpacing * i + candleSpacing / 2, y: toRY(v) });
    });

    if (pts.length > 1) {
        const d = pts.length > 2 ? smoothPath(pts) : `M${pts[0].x},${pts[0].y}L${pts[1].x},${pts[1].y}`;
        g.appendChild(svgEl('path', {
            d, fill: 'none',
            stroke: ind.color || 'hsl(270, 55%, 56%)',
            'stroke-width': '1.5', class: 'chart-rsi-line',
        }));
    }

    // Scale labels
    [obLevel, 50, osLevel].forEach(v => {
        const txt = svgEl('text', {
            x: pad.left + plotW + 4, y: toRY(v) + 3,
            'font-size': '9', fill: ctx.css('--rui-text-muted'),
        });
        txt.textContent = v;
        g.appendChild(txt);
    });

    svg.appendChild(g);
}

// ── Volume Index Panel ──

function renderVIPanel(ctx, svg, values, ind, layout, panelTop, panelH) {
    const period = ind.period || 20;
    const { pad, plotW, candleSpacing } = layout;

    const g = svgEl('g', { class: 'chart-indicator-vi' });

    // Label
    const label = svgEl('text', {
        x: pad.left + 4, y: panelTop + 12,
        'font-size': '9', fill: ctx.css('--rui-text-muted'),
    });
    label.textContent = `Vol Index (${period})`;
    g.appendChild(label);

    // Separator
    g.appendChild(svgEl('line', {
        x1: pad.left, y1: panelTop, x2: pad.left + plotW, y2: panelTop,
        stroke: ctx.css('--rui-border'), 'stroke-width': 0.5,
    }));

    const validVals = values.filter(v => v !== null);
    if (!validVals.length) { svg.appendChild(g); return; }

    const vMin = Math.min(...validVals);
    const vMax = Math.max(...validVals);
    const vRange = vMax - vMin || 1;
    const plotArea = panelH - 20;
    const toVY = (v) => panelTop + 16 + plotArea - ((v - vMin) / vRange) * plotArea;

    // Fill area
    const pts = [];
    values.forEach((v, i) => {
        if (v === null) return;
        pts.push({ x: pad.left + candleSpacing * i + candleSpacing / 2, y: toVY(v) });
    });

    if (pts.length > 1) {
        const d = pts.length > 2 ? smoothPath(pts) : `M${pts[0].x},${pts[0].y}L${pts[1].x},${pts[1].y}`;
        const baseline = panelTop + 16 + plotArea;

        // Area fill
        g.appendChild(svgEl('path', {
            d: d + `L${pts[pts.length - 1].x},${baseline}L${pts[0].x},${baseline}Z`,
            fill: ind.color || 'hsl(175, 55%, 40%)', 'fill-opacity': '0.1',
        }));

        // Line
        g.appendChild(svgEl('path', {
            d, fill: 'none',
            stroke: ind.color || 'hsl(175, 55%, 40%)',
            'stroke-width': '1.5', class: 'chart-vi-line',
        }));
    }

    svg.appendChild(g);
}

export default installIndicators;
