/**
 * @fileoverview Chart view — DOM/SVG construction and rendering for every chart type.
 *
 * All render* / draw* functions receive the chart instance context (ctx)
 * which exposes private fields through a thin accessor object built in index.js.
 *
 * Supported chart types:
 *   bar, hbar, line, area, stacked-area, pie, donut, radar,
 *   gauge, sankey, scatter, bubble, inline-bar, inline-line
 *
 * @module module/Chart/view
 */

import { PALETTE, PART } from './constants.js';
import { svgEl, niceScale, smoothPath, polarToCart, lerp } from './helpers.js';
import { bindHover } from './events.js';

/**
 * Create an SVG, append it to the container, measure its actual rendered
 * dimensions, then set the viewBox to match.  Returns { svg, w, h }.
 *
 * @param {Object}  ctx        chart context
 * @param {number}  defaultH   fallback height when container has no explicit size
 * @param {string}  cssClass   SVG class name(s)
 * @param {boolean} square     if true, make viewBox square (min of w/h)
 */
function layoutSvg(ctx, defaultH = 300, cssClass = 'chart-svg', square = false) {
    const cfg = ctx.config;
    const svg = svgEl('svg', {
        preserveAspectRatio: 'xMidYMid meet',
        class: cssClass,
    });
    svg.style.width = typeof cfg.width === 'number' ? cfg.width + 'px' : cfg.width;
    svg.style.height = '100%';
    svg.style.display = 'block';
    ctx.svg = svg;
    ctx.container.append(svg);

    // Measure actual rendered size after the browser lays it out
    const rect = svg.getBoundingClientRect();
    let w = Math.round(rect.width) || 600;
    let h = Math.round(rect.height);
    if (!h || h <= 0) h = typeof cfg.height === 'number' ? cfg.height : defaultH;

    if (square) {
        const side = Math.min(w, h);
        w = side;
        h = side;
        svg.style.maxWidth = side + 'px';
    }

    svg.setAttribute('viewBox', `0 0 ${w} ${h}`);
    svg.style.height = h + 'px';
    return { svg, w, h };
}

// ─────────────────────────────────────────
//  Top-level render dispatcher
// ─────────────────────────────────────────

/**
 * Clear previous chart and re-render based on cfg.type.
 * @param {Object} ctx — chart context accessor
 */
export function render(ctx) {
    cleanup(ctx);
    const cfg = ctx.config;

    ctx.container.addClass('chart').html('');
    PART.CONTAINER.apply(ctx.container);

    // Normalize datasets (inline)
    cfg.datasets = cfg.datasets.map((ds, i) => ({
        label: ds.label || `Dataset ${i + 1}`,
        data: ds.data || [],
        color: ds.color || PALETTE[i % PALETTE.length],
        borderColor: ds.borderColor || ds.color || PALETTE[i % PALETTE.length],
    }));

    const type = cfg.type;
    if (type === 'pie' || type === 'donut') {
        renderPie(ctx);
    } else if (type === 'radar') {
        renderRadar(ctx);
    } else if (type === 'gauge') {
        renderGauge(ctx);
    } else if (type === 'sankey') {
        renderSankey(ctx);
    } else if (type === 'scatter' || type === 'bubble') {
        renderXY(ctx);
    } else if (type === 'inline-bar') {
        renderInlineBar(ctx);
    } else if (type === 'inline-line') {
        renderInlineLine(ctx);
    } else {
        renderCartesian(ctx);
    }

    // Legend (skip for inline types)
    if (cfg.legend && type !== 'inline-bar' && type !== 'inline-line') {
        const showLegend = type === 'pie' || type === 'donut' || type === 'sankey'
            || (type !== 'gauge' && cfg.datasets.length > 1);
        if (showLegend) renderLegend(ctx);
    }

    // Tooltip element
    if (cfg.tooltip) {
        const razyui = ctx.razyui;
        ctx.tooltip = razyui.spell('div.chart-tooltip', true);
        PART.TOOLTIP.apply(ctx.tooltip);
        ctx.container.append(ctx.tooltip);
    }
}

/**
 * Cleanup animation controllers.
 * @param {Object} ctx
 */
export function cleanup(ctx) {
    ctx.animControllers.forEach(c => { if (c?.destroy) c.destroy(); });
    ctx.animControllers = [];
}

// ─────────────────────────────────────────
//  Cartesian charts (bar, hbar, line, area, stacked-area)
// ─────────────────────────────────────────

function renderCartesian(ctx) {
    const cfg = ctx.config;
    const pad = cfg.padding;
    const { svg, w: svgW, h: svgH } = layoutSvg(ctx, 300);

    const plotW = svgW - pad.left - pad.right;
    const plotH = svgH - pad.top - pad.bottom;
    const labels = cfg.labels;
    const datasets = cfg.datasets;
    const isHBar = cfg.type === 'hbar';

    // Compute Y range
    let allValues = datasets.flatMap(d => d.data);
    if ((cfg.stacked && (cfg.type === 'bar' || cfg.type === 'hbar')) || cfg.type === 'stacked-area') {
        const stackMax = labels.map((_, i) =>
            datasets.reduce((sum, d) => sum + (d.data[i] || 0), 0)
        );
        allValues = stackMax;
    }
    let dataMin = Math.min(0, ...allValues);
    let dataMax = Math.max(0, ...allValues);
    if (cfg.yMin !== null) dataMin = cfg.yMin;
    if (cfg.yMax !== null) dataMax = cfg.yMax;

    const scale = niceScale(dataMin, dataMax);
    const yMin = scale.min;
    const yMax = scale.max;
    const yRange = yMax - yMin || 1;

    const toY = (v) => pad.top + plotH - ((v - yMin) / yRange) * plotH;
    const toX = (v) => pad.left + ((v - yMin) / yRange) * plotW;

    // ── Grid + Axes ──
    const gridG = svgEl('g', { class: 'chart-grid' });
    svg.appendChild(gridG);

    if (cfg.grid) {
        scale.steps.forEach(v => {
            if (isHBar) {
                const x = toX(v);
                gridG.appendChild(svgEl('line', {
                    x1: x, y1: pad.top, x2: x, y2: pad.top + plotH,
                    stroke: ctx.css('--rui-border'), 'stroke-width': 1,
                }));
            } else {
                const y = toY(v);
                gridG.appendChild(svgEl('line', {
                    x1: pad.left, y1: y, x2: pad.left + plotW, y2: y,
                    stroke: ctx.css('--rui-border'), 'stroke-width': 1,
                }));
            }
        });
    }

    // Axis labels
    const axisG = svgEl('g', { class: 'chart-axis' });
    svg.appendChild(axisG);

    scale.steps.forEach(v => {
        if (isHBar) {
            const x = toX(v);
            const txt = svgEl('text', {
                x, y: pad.top + plotH + 16,
                'text-anchor': 'middle', 'font-size': '11', fill: ctx.css('--rui-text-muted'),
            });
            txt.textContent = v;
            axisG.appendChild(txt);
        } else {
            const y = toY(v);
            const txt = svgEl('text', {
                x: pad.left - 8, y: y + 4,
                'text-anchor': 'end', 'font-size': '11', fill: ctx.css('--rui-text-muted'),
            });
            txt.textContent = v;
            axisG.appendChild(txt);
        }
    });

    // Category labels
    const catCount = labels.length || 1;
    if (isHBar) {
        const barAreaH = plotH / catCount;
        labels.forEach((lbl, i) => {
            const cy = pad.top + barAreaH * i + barAreaH / 2;
            const txt = svgEl('text', {
                x: pad.left - 8, y: cy + 4,
                'text-anchor': 'end', 'font-size': '11', fill: ctx.css('--rui-text-secondary'),
            });
            txt.textContent = lbl;
            axisG.appendChild(txt);
        });
    } else {
        const barAreaW = plotW / catCount;
        labels.forEach((lbl, i) => {
            const cx = pad.left + barAreaW * i + barAreaW / 2;
            const txt = svgEl('text', {
                x: cx, y: pad.top + plotH + 20,
                'text-anchor': 'middle', 'font-size': '11', fill: ctx.css('--rui-text-secondary'),
            });
            txt.textContent = lbl;
            axisG.appendChild(txt);
        });
    }

    // ── Data rendering ──
    const dataG = svgEl('g', { class: 'chart-data' });
    svg.appendChild(dataG);

    if (cfg.type === 'bar') {
        drawBars(ctx, dataG, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg);
    } else if (cfg.type === 'hbar') {
        drawHBars(ctx, dataG, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg);
    } else if (cfg.type === 'line' || cfg.type === 'area') {
        drawLines(ctx, dataG, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg);
    } else if (cfg.type === 'stacked-area') {
        drawStackedArea(ctx, dataG, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg);
    }
}

// ── Bar chart ──

function drawBars(ctx, g, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg) {
    const catCount = labels.length || 1;
    const barAreaW = plotW / catCount;
    const barPad = Math.max(2, barAreaW * 0.15);
    const dsCount = cfg.stacked ? 1 : datasets.length;
    const barW = (barAreaW - barPad * 2) / dsCount;
    const zeroY = pad.top + plotH - ((0 - yMin) / yRange) * plotH;

    const stackBases = labels.map(() => 0);

    datasets.forEach((ds, di) => {
        ds.data.forEach((val, ci) => {
            let x, y, h;
            if (cfg.stacked) {
                const base = stackBases[ci];
                const topVal = base + val;
                y = pad.top + plotH - ((topVal - yMin) / yRange) * plotH;
                const baseY = pad.top + plotH - ((base - yMin) / yRange) * plotH;
                h = baseY - y;
                x = pad.left + barAreaW * ci + barPad;
                stackBases[ci] = topVal;
            } else {
                const valY = pad.top + plotH - ((val - yMin) / yRange) * plotH;
                y = val >= 0 ? valY : zeroY;
                h = Math.abs(valY - zeroY);
                x = pad.left + barAreaW * ci + barPad + barW * di;
            }

            const rect = svgEl('rect', {
                x, y, width: barW, height: Math.max(0, h),
                rx: 2,
                fill: ds.color,
                class: 'chart-bar',
                'data-ds': di, 'data-idx': ci,
            });

            // Entry animation
            if (cfg.animate) {
                const finalH = Math.max(0, h);
                const finalY = y;
                rect.setAttribute('height', '0');
                rect.setAttribute('y', String(zeroY));
                rect.style.transition = `height ${cfg.duration}ms ${cfg.easing}, y ${cfg.duration}ms ${cfg.easing}`;
                requestAnimationFrame(() => {
                    requestAnimationFrame(() => {
                        rect.setAttribute('height', String(finalH));
                        rect.setAttribute('y', String(finalY));
                    });
                });
            }

            bindHover(ctx, rect, { datasetIndex: di, index: ci, value: val, label: labels[ci] });
            g.appendChild(rect);

            // Value label
            if (cfg.showValues) {
                const valTxt = svgEl('text', {
                    x: x + barW / 2,
                    y: y - 4,
                    'text-anchor': 'middle',
                    'font-size': '10',
                    fill: ctx.css('--rui-text-secondary'),
                    class: 'chart-value',
                });
                valTxt.textContent = val;
                if (cfg.animate) {
                    valTxt.style.opacity = '0';
                    valTxt.style.transition = `opacity ${cfg.duration}ms ${cfg.easing}`;
                    setTimeout(() => { valTxt.style.opacity = '1'; }, cfg.duration * 0.7);
                }
                g.appendChild(valTxt);
            }
        });
    });
}

// ── Horizontal bar chart ──

function drawHBars(ctx, g, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg) {
    const catCount = labels.length || 1;
    const barAreaH = plotH / catCount;
    const barPad = Math.max(2, barAreaH * 0.15);
    const dsCount = cfg.stacked ? 1 : datasets.length;
    const barH = (barAreaH - barPad * 2) / dsCount;
    const zeroX = pad.left + ((0 - yMin) / yRange) * plotW;

    const stackBases = labels.map(() => 0);

    datasets.forEach((ds, di) => {
        ds.data.forEach((val, ci) => {
            let x, y, w;
            if (cfg.stacked) {
                const base = stackBases[ci];
                const topVal = base + val;
                x = pad.left + ((base - yMin) / yRange) * plotW;
                const endX = pad.left + ((topVal - yMin) / yRange) * plotW;
                w = endX - x;
                y = pad.top + barAreaH * ci + barPad;
                stackBases[ci] = topVal;
            } else {
                const valX = pad.left + ((val - yMin) / yRange) * plotW;
                x = val >= 0 ? zeroX : valX;
                w = Math.abs(valX - zeroX);
                y = pad.top + barAreaH * ci + barPad + barH * di;
            }

            const rect = svgEl('rect', {
                x, y, width: Math.max(0, w), height: barH,
                rx: 2,
                fill: ds.color,
                class: 'chart-bar',
                'data-ds': di, 'data-idx': ci,
            });

            if (cfg.animate) {
                const finalW = Math.max(0, w);
                rect.setAttribute('width', '0');
                rect.setAttribute('x', String(zeroX));
                rect.style.transition = `width ${cfg.duration}ms ${cfg.easing}, x ${cfg.duration}ms ${cfg.easing}`;
                requestAnimationFrame(() => {
                    requestAnimationFrame(() => {
                        rect.setAttribute('width', String(finalW));
                        rect.setAttribute('x', String(x));
                    });
                });
            }

            bindHover(ctx, rect, { datasetIndex: di, index: ci, value: val, label: labels[ci] });
            g.appendChild(rect);
        });
    });
}

// ── Line / Area chart ──

function drawLines(ctx, g, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg) {
    const catCount = labels.length || 1;
    const stepX = plotW / Math.max(1, catCount - 1);
    const isArea = cfg.type === 'area';
    const baseY = pad.top + plotH;

    datasets.forEach((ds, di) => {
        const points = ds.data.map((val, i) => ({
            x: pad.left + stepX * i,
            y: pad.top + plotH - ((val - yMin) / yRange) * plotH,
        }));

        if (points.length === 0) return;

        // Area fill
        if (isArea) {
            const areaPath = svgEl('path', {
                fill: ds.color,
                'fill-opacity': '0.15',
                class: 'chart-area',
            });
            const first = points[0];
            const last = points[points.length - 1];
            let d;
            if (cfg.smooth && points.length > 2) {
                d = smoothPath(points);
                d += `L${last.x},${baseY}L${first.x},${baseY}Z`;
            } else {
                d = `M${first.x},${first.y}`;
                for (let i = 1; i < points.length; i++) d += `L${points[i].x},${points[i].y}`;
                d += `L${last.x},${baseY}L${first.x},${baseY}Z`;
            }
            areaPath.setAttribute('d', d);

            if (cfg.animate) {
                areaPath.style.opacity = '0';
                areaPath.style.transition = `opacity ${cfg.duration}ms ${cfg.easing}`;
                requestAnimationFrame(() => {
                    requestAnimationFrame(() => { areaPath.style.opacity = '1'; });
                });
            }
            g.appendChild(areaPath);
        }

        // Line
        const linePath = svgEl('path', {
            fill: 'none',
            stroke: ds.borderColor,
            'stroke-width': '2.5',
            'stroke-linejoin': 'round',
            'stroke-linecap': 'round',
            class: 'chart-line',
        });

        let d;
        if (cfg.smooth && points.length > 2) {
            d = smoothPath(points);
        } else {
            d = `M${points[0].x},${points[0].y}`;
            for (let i = 1; i < points.length; i++) d += `L${points[i].x},${points[i].y}`;
        }
        linePath.setAttribute('d', d);

        // Animate line with stroke-dasharray
        if (cfg.animate) {
            const len = linePath.getTotalLength?.() || 1000;
            linePath.style.strokeDasharray = len;
            linePath.style.strokeDashoffset = len;
            linePath.style.transition = `stroke-dashoffset ${cfg.duration}ms ${cfg.easing}`;
            // Need to append first for getTotalLength
            g.appendChild(linePath);
            const actualLen = linePath.getTotalLength();
            linePath.style.strokeDasharray = actualLen;
            linePath.style.strokeDashoffset = actualLen;
            requestAnimationFrame(() => {
                requestAnimationFrame(() => {
                    linePath.style.strokeDashoffset = '0';
                });
            });
        } else {
            g.appendChild(linePath);
        }

        // Data points (dots)
        if (points.length > 100) {
            // Optimization: Use a single <path> for many dots to reduce DOM nodes
            let d = '';
            const r = 3.5;
            points.forEach(pt => {
                d += `M ${pt.x},${pt.y} m -${r},0 a ${r},${r} 0 1,0 ${r*2},0 a ${r},${r} 0 1,0 -${r*2},0 `;
            });
            const dotsPath = svgEl('path', {
                d,
                fill: ctx.css('--rui-bg'),
                stroke: ds.borderColor,
                'stroke-width': '2',
                class: 'chart-dots-path',
            });
            if (cfg.animate) {
                dotsPath.style.opacity = '0';
                dotsPath.style.transition = `opacity 0.2s ${cfg.easing}`;
                setTimeout(() => { dotsPath.style.opacity = '1'; }, cfg.duration * 0.8);
            }
            g.appendChild(dotsPath);
        } else {
            points.forEach((pt, ci) => {
                const dot = svgEl('circle', {
                    cx: pt.x, cy: pt.y, r: 3.5,
                    fill: ctx.css('--rui-bg'),
                    stroke: ds.borderColor,
                    'stroke-width': '2',
                    class: 'chart-dot',
                    'data-ds': di, 'data-idx': ci,
                });

                if (cfg.animate) {
                    dot.style.opacity = '0';
                    dot.style.transition = `opacity 0.2s ${cfg.easing}`;
                    setTimeout(() => { dot.style.opacity = '1'; }, cfg.duration * 0.8);
                }

                bindHover(ctx, dot, { datasetIndex: di, index: ci, value: ds.data[ci], label: labels[ci] });
                g.appendChild(dot);
            });
        }
    });
}

// ─────────────────────────────────────────
//  Stacked Area chart
// ─────────────────────────────────────────

function drawStackedArea(ctx, g, datasets, labels, pad, plotW, plotH, yMin, yRange, cfg) {
    const catCount = labels.length || 1;
    const stepX = plotW / Math.max(1, catCount - 1);

    const cumulative = labels.map(() => 0);
    const prevY = labels.map(() => pad.top + plotH - ((0 - yMin) / yRange) * plotH);

    datasets.forEach((ds, di) => {
        const data = ds.data || [];
        const newCum = data.map((val, i) => cumulative[i] + (val || 0));

        const topPts = newCum.map((val, i) => ({
            x: pad.left + stepX * i,
            y: pad.top + plotH - ((val - yMin) / yRange) * plotH,
        }));

        if (topPts.length === 0) return;

        // Top edge
        let topD;
        if (cfg.smooth && topPts.length > 2) {
            topD = smoothPath(topPts);
        } else {
            topD = `M${topPts[0].x},${topPts[0].y}`;
            for (let i = 1; i < topPts.length; i++) topD += `L${topPts[i].x},${topPts[i].y}`;
        }

        // Bottom edge (right to left, smooth to match prev layer top)
        let bottomD = '';
        if (cfg.smooth && topPts.length > 2) {
            const bottomPts = [];
            for (let i = topPts.length - 1; i >= 0; i--) {
                bottomPts.push({ x: pad.left + stepX * i, y: prevY[i] });
            }
            bottomD = smoothPath(bottomPts).replace(/^M/, 'L');
        } else {
            for (let i = topPts.length - 1; i >= 0; i--) {
                bottomD += `L${pad.left + stepX * i},${prevY[i]}`;
            }
        }

        const d = topD + bottomD + 'Z';

        // Filled area — opaque with white separation stroke
        const area = svgEl('path', {
            d, fill: ds.color, 'fill-opacity': '0.85',
            stroke: ctx.css('--rui-bg'), 'stroke-width': '1.2',
            'stroke-linejoin': 'round',
            class: 'chart-stacked-area',
        });

        if (cfg.animate) {
            area.style.opacity = '0';
            area.style.transition = `opacity ${cfg.duration}ms ${cfg.easing}`;
            requestAnimationFrame(() => {
                requestAnimationFrame(() => { area.style.opacity = '1'; });
            });
        }

        g.appendChild(area);

        // Invisible hover targets per data point (no visible dots)
        topPts.forEach((pt, ci) => {
            const hit = svgEl('circle', {
                cx: pt.x, cy: pt.y, r: 8,
                fill: 'transparent', stroke: 'none',
                class: 'chart-hit', 'data-ds': di, 'data-idx': ci,
            });
            bindHover(ctx, hit, {
                datasetIndex: di, index: ci, value: data[ci], label: labels[ci],
            });
            g.appendChild(hit);
        });

        // Update accumulators
        newCum.forEach((v, i) => {
            cumulative[i] = v;
            prevY[i] = topPts[i].y;
        });
    });
}

// ─────────────────────────────────────────
//  Inline Timeline Bar (sparkline bar chart)
// ─────────────────────────────────────────

function renderInlineBar(ctx) {
    const cfg = ctx.config;
    const data = cfg.datasets[0]?.data || [];
    const maxBars = cfg.maxBars || 30;
    const visible = data.slice(-maxBars);
    const w = typeof cfg.width === 'number' ? cfg.width : 200;
    const h = typeof cfg.height === 'number' ? cfg.height : 40;
    const color = cfg.datasets[0]?.color || PALETTE[0];

    const svg = svgEl('svg', {
        viewBox: `0 0 ${w} ${h}`,
        preserveAspectRatio: 'none',
        class: 'chart-svg chart-svg-inline-bar',
    });
    svg.style.width = typeof cfg.width === 'number' ? w + 'px' : cfg.width;
    svg.style.height = h + 'px';
    svg.style.display = 'block';
    ctx.svg = svg;

    const maxVal = Math.max(1, ...visible);
    const gap = 1;
    const barW = Math.max(1, (w - gap * (maxBars - 1)) / maxBars);

    // Render from right, filling backwards so newest is on the right
    visible.forEach((val, i) => {
        const barH = Math.max(1, (val / maxVal) * (h - 2));
        const x = w - (visible.length - i) * (barW + gap);
        const y = h - barH;
        const rect = svgEl('rect', {
            x, y, width: barW, height: barH, rx: 1,
            fill: color, class: 'chart-inline-bar',
        });
        svg.appendChild(rect);
    });

    ctx.container.append(svg);
}

// ─────────────────────────────────────────
//  Inline Timeline Line (sparkline line chart)
// ─────────────────────────────────────────

function renderInlineLine(ctx) {
    const cfg = ctx.config;
    const data = cfg.datasets[0]?.data || [];
    const maxPoints = cfg.maxPoints || 30;
    const visible = data.slice(-maxPoints);
    const w = typeof cfg.width === 'number' ? cfg.width : 200;
    const h = typeof cfg.height === 'number' ? cfg.height : 40;
    const color = cfg.datasets[0]?.color || PALETTE[0];
    const pad = 2;

    const svg = svgEl('svg', {
        viewBox: `0 0 ${w} ${h}`,
        preserveAspectRatio: 'none',
        class: 'chart-svg chart-svg-inline-line',
    });
    svg.style.width = typeof cfg.width === 'number' ? w + 'px' : cfg.width;
    svg.style.height = h + 'px';
    svg.style.display = 'block';
    ctx.svg = svg;

    if (visible.length < 2) {
        ctx.container.append(svg);
        return;
    }

    const maxVal = Math.max(1, ...visible);
    const minVal = Math.min(0, ...visible);
    const range = (maxVal - minVal) || 1;
    const stepX = (w - pad * 2) / Math.max(1, maxPoints - 1);
    const offset = maxPoints - visible.length;

    const pts = visible.map((v, i) => ({
        x: pad + (offset + i) * stepX,
        y: pad + (h - pad * 2) - ((v - minVal) / range) * (h - pad * 2),
    }));

    // Smooth path
    const lineD = smoothPath(pts);

    // Area fill (line → bottom edge → close)
    const areaD = lineD
        + `L${pts[pts.length - 1].x},${h}`
        + `L${pts[0].x},${h}Z`;

    const area = svgEl('path', {
        d: areaD, fill: color, 'fill-opacity': '0.15',
        class: 'chart-inline-area',
    });
    svg.appendChild(area);

    const line = svgEl('path', {
        d: lineD, fill: 'none',
        stroke: color, 'stroke-width': '1.5', 'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
        class: 'chart-inline-line',
    });
    svg.appendChild(line);

    // Tip dot at latest value
    const last = pts[pts.length - 1];
    const dot = svgEl('circle', {
        cx: last.x, cy: last.y, r: 2.5,
        fill: color, class: 'chart-inline-dot',
    });
    svg.appendChild(dot);

    ctx.container.append(svg);
}

// ─────────────────────────────────────────
//  Pie / Donut
// ─────────────────────────────────────────

function renderPie(ctx) {
    const cfg = ctx.config;
    const { svg, w: svgW, h: svgH } = layoutSvg(ctx, 300, 'chart-svg chart-svg-pie', true);

    const cx = svgW / 2;
    const cy = svgH / 2;
    const radius = Math.min(svgW, svgH) / 2 - 20;
    const isDonut = cfg.type === 'donut';
    const inner = isDonut
        ? (cfg.donutWidth > 0
            ? (cfg.donutWidth < 1 ? radius * (1 - cfg.donutWidth) : Math.max(0, radius - cfg.donutWidth))
            : radius * 0.6)
        : 0;

    // Flatten: if every dataset has exactly one data point, combine them into one series
    const allSingleValue = cfg.datasets.length > 1 && cfg.datasets.every(d => (d.data || []).length === 1);
    const data = allSingleValue
        ? cfg.datasets.map(d => d.data[0])
        : (cfg.datasets[0] || { data: [] }).data || [];
    const labels = allSingleValue
        ? cfg.datasets.map(d => d.label)
        : (cfg.labels || []);
    const total = data.reduce((s, v) => s + Math.max(0, v), 0) || 1;

    const pieG = svgEl('g', { class: 'chart-pie' });
    let cumAngle = 0;

    data.forEach((val, i) => {
        const sliceAngle = (Math.max(0, val) / total) * 360;
        const startAngle = cumAngle;
        const endAngle = cumAngle + sliceAngle;
        cumAngle = endAngle;

        const color = allSingleValue ? cfg.datasets[i].color : PALETTE[i % PALETTE.length];

        // Arc path
        const start = polarToCart(cx, cy, radius, startAngle);
        const end = polarToCart(cx, cy, radius, endAngle);
        const largeArc = sliceAngle > 180 ? 1 : 0;

        let d;
        if (isDonut) {
            const innerStart = polarToCart(cx, cy, inner, startAngle);
            const innerEnd = polarToCart(cx, cy, inner, endAngle);
            d = `M${start.x},${start.y}A${radius},${radius},0,${largeArc},1,${end.x},${end.y}` +
                `L${innerEnd.x},${innerEnd.y}A${inner},${inner},0,${largeArc},0,${innerStart.x},${innerStart.y}Z`;
        } else {
            d = `M${cx},${cy}L${start.x},${start.y}A${radius},${radius},0,${largeArc},1,${end.x},${end.y}Z`;
        }

        const slice = svgEl('path', {
            d,
            fill: color,
            class: 'chart-slice',
            'data-idx': i,
        });

        // Animate: scale from center
        if (cfg.animate) {
            slice.style.transformOrigin = `${cx}px ${cy}px`;
            slice.style.transform = 'scale(0)';
            slice.style.opacity = '0';
            slice.style.transition = `transform ${cfg.duration}ms ${cfg.easing}, opacity ${cfg.duration * 0.6}ms ${cfg.easing}`;
            const delay = (i / data.length) * cfg.duration * 0.4;
            setTimeout(() => {
                slice.style.transform = 'scale(1)';
                slice.style.opacity = '1';
            }, delay);
        }

        bindHover(ctx, slice, {
            datasetIndex: 0, index: i, value: val,
            label: labels[i] || `Slice ${i + 1}`,
            percent: ((val / total) * 100).toFixed(1) + '%',
        });
        pieG.appendChild(slice);
    });

    svg.appendChild(pieG);
}

// ─────────────────────────────────────────
//  Radar
// ─────────────────────────────────────────

function renderRadar(ctx) {
    const cfg = ctx.config;
    const { svg, w: svgW, h: svgH } = layoutSvg(ctx, 300, 'chart-svg chart-svg-radar', true);

    const cx = svgW / 2;
    const cy = svgH / 2;
    const radius = Math.min(svgW, svgH) / 2 - 30;
    const labels = cfg.labels;
    const n = labels.length || 1;
    const angleStep = 360 / n;

    // Determine max data value
    const allVals = cfg.datasets.flatMap(d => d.data);
    const maxVal = Math.max(...allVals, 1);

    // Grid rings
    const gridG = svgEl('g', { class: 'chart-radar-grid' });
    for (let ring = 1; ring <= 4; ring++) {
        const r = (ring / 4) * radius;
        const points = [];
        for (let i = 0; i < n; i++) {
            points.push(polarToCart(cx, cy, r, angleStep * i));
        }
        const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join('') + 'Z';
        gridG.appendChild(svgEl('path', {
            d, fill: 'none', stroke: ctx.css('--rui-border'), 'stroke-width': '1',
        }));
    }

    // Axis spokes + labels
    for (let i = 0; i < n; i++) {
        const end = polarToCart(cx, cy, radius, angleStep * i);
        gridG.appendChild(svgEl('line', {
            x1: cx, y1: cy, x2: end.x, y2: end.y,
            stroke: ctx.css('--rui-border'), 'stroke-width': '1',
        }));
        const lblPt = polarToCart(cx, cy, radius + 14, angleStep * i);
        const txt = svgEl('text', {
            x: lblPt.x, y: lblPt.y + 4,
            'text-anchor': 'middle', 'font-size': '11', fill: ctx.css('--rui-text-secondary'),
        });
        txt.textContent = labels[i];
        gridG.appendChild(txt);
    }
    svg.appendChild(gridG);

    // Data polygons
    cfg.datasets.forEach((ds, di) => {
        const points = ds.data.map((val, i) => {
            const r = (val / maxVal) * radius;
            return polarToCart(cx, cy, r, angleStep * i);
        });

        const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join('') + 'Z';

        // Fill
        const fill = svgEl('path', {
            d, fill: ds.color, 'fill-opacity': '0.15',
            stroke: ds.borderColor, 'stroke-width': '2',
            class: 'chart-radar-area',
        });

        if (cfg.animate) {
            fill.style.transformOrigin = `${cx}px ${cy}px`;
            fill.style.transform = 'scale(0)';
            fill.style.transition = `transform ${cfg.duration}ms ${cfg.easing}`;
            requestAnimationFrame(() => {
                requestAnimationFrame(() => { fill.style.transform = 'scale(1)'; });
            });
        }

        svg.appendChild(fill);

        // Dots
        points.forEach((pt, ci) => {
            const dot = svgEl('circle', {
                cx: pt.x, cy: pt.y, r: 3.5,
                fill: ctx.css('--rui-bg'), stroke: ds.borderColor, 'stroke-width': '2',
                class: 'chart-dot',
            });
            bindHover(ctx, dot, { datasetIndex: di, index: ci, value: ds.data[ci], label: labels[ci] });
            svg.appendChild(dot);
        });
    });
}

// ─────────────────────────────────────────
//  Scatter / Bubble
// ─────────────────────────────────────────

function renderXY(ctx) {
    const cfg = ctx.config;
    const pad = cfg.padding;
    const { svg, w: svgW, h: svgH } = layoutSvg(ctx, 300);

    const plotW = svgW - pad.left - pad.right;
    const plotH = svgH - pad.top - pad.bottom;
    const datasets = cfg.datasets;
    const isBubble = cfg.type === 'bubble';

    // Compute X / Y ranges from data points
    let allX = [], allY = [], allR = [];
    datasets.forEach(ds => {
        ds.data = (ds.data || []).map(pt => {
            if (Array.isArray(pt)) return { x: pt[0], y: pt[1], r: pt[2] };
            return pt;
        });
        ds.data.forEach(pt => {
            if (!pt || typeof pt !== 'object') return;
            allX.push(pt.x);
            allY.push(pt.y);
            if (isBubble && pt.r !== undefined) allR.push(pt.r);
        });
    });

    if (allX.length === 0) { return; }

    const xScale = niceScale(
        cfg.xMin ?? Math.min(...allX),
        cfg.xMax ?? Math.max(...allX)
    );
    const yScale = niceScale(
        cfg.yMin ?? Math.min(0, ...allY),
        cfg.yMax ?? Math.max(...allY)
    );

    const xMin = xScale.min, xMax = xScale.max, xRange = xMax - xMin || 1;
    const yMin = yScale.min, yMax = yScale.max, yRange = yMax - yMin || 1;

    const toX = v => pad.left + ((v - xMin) / xRange) * plotW;
    const toY = v => pad.top + plotH - ((v - yMin) / yRange) * plotH;

    // Max bubble radius scaling
    const maxR = allR.length ? Math.max(...allR) : 1;
    const maxBubblePx = Math.min(plotW, plotH) * 0.08;

    // Grid
    const gridG = svgEl('g', { class: 'chart-grid' });
    svg.appendChild(gridG);

    if (cfg.grid) {
        yScale.steps.forEach(v => {
            const y = toY(v);
            gridG.appendChild(svgEl('line', {
                x1: pad.left, y1: y, x2: pad.left + plotW, y2: y,
                stroke: ctx.css('--rui-border'), 'stroke-width': 1,
            }));
        });
        xScale.steps.forEach(v => {
            const x = toX(v);
            gridG.appendChild(svgEl('line', {
                x1: x, y1: pad.top, x2: x, y2: pad.top + plotH,
                stroke: ctx.css('--rui-border'), 'stroke-width': 1,
            }));
        });
    }

    // Axis labels
    const axisG = svgEl('g', { class: 'chart-axis' });
    svg.appendChild(axisG);

    yScale.steps.forEach(v => {
        const y = toY(v);
        const txt = svgEl('text', {
            x: pad.left - 8, y: y + 4,
            'text-anchor': 'end', 'font-size': '11', fill: ctx.css('--rui-text-muted'),
        });
        txt.textContent = v;
        axisG.appendChild(txt);
    });

    xScale.steps.forEach(v => {
        const x = toX(v);
        const txt = svgEl('text', {
            x, y: pad.top + plotH + 16,
            'text-anchor': 'middle', 'font-size': '11', fill: ctx.css('--rui-text-muted'),
        });
        txt.textContent = v;
        axisG.appendChild(txt);
    });

    // Data points
    const dataG = svgEl('g', { class: 'chart-data' });
    svg.appendChild(dataG);

    datasets.forEach((ds, di) => {
        const data = ds.data || [];
        if (data.length > 100 && !isBubble) {
            // Optimization: Use a single <path> for many dots to reduce DOM nodes
            let d = '';
            const r = 4;
            data.forEach((pt) => {
                if (!pt || typeof pt !== 'object') return;
                const cx = toX(pt.x);
                const cy = toY(pt.y);
                d += `M ${cx},${cy} m -${r},0 a ${r},${r} 0 1,0 ${r*2},0 a ${r},${r} 0 1,0 -${r*2},0 `;
            });
            const dotsPath = svgEl('path', {
                d,
                fill: ds.color,
                stroke: ds.borderColor,
                'stroke-width': '2',
                class: 'chart-dots-path',
            });
            if (cfg.animate) {
                dotsPath.style.opacity = '0';
                dotsPath.style.transition = `opacity ${cfg.duration * 0.5}ms ${cfg.easing}`;
                setTimeout(() => { dotsPath.style.opacity = '1'; }, cfg.duration * 0.5);
            }
            dataG.appendChild(dotsPath);
        } else {
            data.forEach((pt, ci) => {
                if (!pt || typeof pt !== 'object') return;
                const cx = toX(pt.x);
                const cy = toY(pt.y);
                const r = isBubble
                    ? Math.max(4, ((pt.r || 1) / maxR) * maxBubblePx)
                    : 4;

                const dot = svgEl('circle', {
                    cx, cy, r,
                    fill: ds.color,
                    'fill-opacity': isBubble ? '0.55' : '1',
                    stroke: ds.borderColor,
                    'stroke-width': isBubble ? '1.5' : '2',
                    class: isBubble ? 'chart-bubble' : 'chart-dot',
                    'data-ds': di, 'data-idx': ci,
                });

                if (cfg.animate) {
                    dot.style.opacity = '0';
                    dot.style.transform = 'scale(0)';
                    dot.style.transformOrigin = `${cx}px ${cy}px`;
                    dot.style.transition = `opacity ${cfg.duration * 0.5}ms ${cfg.easing}, transform ${cfg.duration}ms ${cfg.easing}`;
                    const delay = (ci / (data.length || 1)) * cfg.duration * 0.5;
                    setTimeout(() => {
                        dot.style.opacity = '1';
                        dot.style.transform = 'scale(1)';
                    }, delay);
                }

                const info = {
                    datasetIndex: di, index: ci,
                    value: pt.y, label: `(${pt.x}, ${pt.y})`,
                    x: pt.x, y: pt.y,
                };
                if (isBubble) info.r = pt.r;
                bindHover(ctx, dot, info);
                dataG.appendChild(dot);
            });
        }
    });
}

// ─────────────────────────────────────────
//  Gauge
// ─────────────────────────────────────────

function renderGauge(ctx) {
    const cfg = ctx.config;
    const razyui = ctx.razyui;
    const { svg, w: measuredW, h: svgH } = layoutSvg(ctx, 200, 'chart-svg chart-svg-gauge');
    const svgW = Math.max(Math.round(svgH * 1.8), 300);
    svg.setAttribute('viewBox', `0 0 ${svgW} ${svgH}`);
    svg.style.maxWidth = svgW + 'px';

    const cx = svgW / 2;
    const cy = svgH - 16;
    const outerR = Math.min(svgW / 2 - 20, svgH - 30);
    const innerR = outerR * 0.7;

    const gMin = cfg.min ?? 0;
    const gMax = cfg.max ?? 100;
    const range = gMax - gMin || 1;
    const value = razyui.clamp(cfg.value ?? 0, gMin, gMax);

    // Map value to angle: 270° (left / min) → 450° (right / max)
    const valToAngle = (v) => 270 + ((v - gMin) / range) * 180;
    const activeAngle = valToAngle(value);

    const segments = cfg.segments || [
        { min: gMin, max: gMin + range / 3, color: 'hsl(120,55%,45%)' },
        { min: gMin + range / 3, max: gMin + range * 2 / 3, color: 'hsl(45,85%,55%)' },
        { min: gMin + range * 2 / 3, max: gMax, color: 'hsl(0,65%,55%)' },
    ];

    const gaugeG = svgEl('g', { class: 'chart-gauge' });

    // Segment arcs (background)
    segments.forEach(seg => {
        const a1 = valToAngle(Math.max(seg.min, gMin));
        const a2 = valToAngle(Math.min(seg.max, gMax));
        const s1 = polarToCart(cx, cy, outerR, a1);
        const e1 = polarToCart(cx, cy, outerR, a2);
        const s2 = polarToCart(cx, cy, innerR, a1);
        const e2 = polarToCart(cx, cy, innerR, a2);
        const large = (a2 - a1) > 180 ? 1 : 0;

        const d = `M${s1.x},${s1.y}A${outerR},${outerR},0,${large},1,${e1.x},${e1.y}` +
            `L${e2.x},${e2.y}A${innerR},${innerR},0,${large},0,${s2.x},${s2.y}Z`;

        gaugeG.appendChild(svgEl('path', {
            d, fill: seg.color, 'fill-opacity': '0.2', class: 'chart-gauge-segment',
        }));
    });

    // Active fill arc
    const activeColor = (segments.find(s => value >= s.min && value <= s.max) || segments[segments.length - 1]).color;

    if (value > gMin) {
        const startAngle = 270;
        const s1 = polarToCart(cx, cy, outerR, startAngle);
        const e1 = polarToCart(cx, cy, outerR, activeAngle);
        const s2 = polarToCart(cx, cy, innerR, startAngle);
        const e2 = polarToCart(cx, cy, innerR, activeAngle);
        const sweep = activeAngle - startAngle;
        const large = sweep > 180 ? 1 : 0;

        const d = `M${s1.x},${s1.y}A${outerR},${outerR},0,${large},1,${e1.x},${e1.y}` +
            `L${e2.x},${e2.y}A${innerR},${innerR},0,${large},0,${s2.x},${s2.y}Z`;

        const fill = svgEl('path', {
            d, fill: activeColor, class: 'chart-gauge-fill',
        });

        if (cfg.animate) {
            fill.style.opacity = '0';
            fill.style.transition = `opacity ${cfg.duration}ms ${cfg.easing}`;
            requestAnimationFrame(() => {
                requestAnimationFrame(() => { fill.style.opacity = '1'; });
            });
        }
        gaugeG.appendChild(fill);
    }

    // Needle
    const needlePt = polarToCart(cx, cy, outerR * 0.88, activeAngle);
    const needle = svgEl('line', {
        x1: cx, y1: cy, x2: needlePt.x, y2: needlePt.y,
        stroke: ctx.css('--rui-text'), 'stroke-width': '2.5', 'stroke-linecap': 'round',
        class: 'chart-gauge-needle',
    });

    if (cfg.animate) {
        const startPt = polarToCart(cx, cy, outerR * 0.88, 270);
        needle.setAttribute('x2', startPt.x);
        needle.setAttribute('y2', startPt.y);
        const dur = cfg.duration;
        const t0 = performance.now();
        const tick = () => {
            const t = Math.min(1, (performance.now() - t0) / dur);
            const et = 1 - Math.pow(1 - t, 3); // ease-out cubic
            const a = lerp(270, activeAngle, et);
            const pt = polarToCart(cx, cy, outerR * 0.88, a);
            needle.setAttribute('x2', pt.x);
            needle.setAttribute('y2', pt.y);
            if (t < 1) requestAnimationFrame(tick);
        };
        requestAnimationFrame(tick);
    }

    gaugeG.appendChild(needle);
    gaugeG.appendChild(svgEl('circle', { cx, cy, r: 5, fill: ctx.css('--rui-text') }));

    // Value text
    const valTxt = svgEl('text', {
        x: cx, y: cy - outerR * 0.35,
        'text-anchor': 'middle', 'font-size': Math.round(outerR * 0.22),
        'font-weight': '600', fill: activeColor, class: 'chart-gauge-value',
    });
    valTxt.textContent = razyui.isFn(cfg.formatValue) ? cfg.formatValue(value) : value;
    gaugeG.appendChild(valTxt);

    if (cfg.gaugeLabel) {
        const lbl = svgEl('text', {
            x: cx, y: cy - outerR * 0.35 + Math.round(outerR * 0.16),
            'text-anchor': 'middle', 'font-size': '12', fill: ctx.css('--rui-text-muted'),
        });
        lbl.textContent = cfg.gaugeLabel;
        gaugeG.appendChild(lbl);
    }

    // Min / Max labels
    const minTxt = svgEl('text', {
        x: cx - outerR - 2, y: cy + 14,
        'text-anchor': 'middle', 'font-size': '11', fill: ctx.css('--rui-text-muted'),
    });
    minTxt.textContent = gMin;
    gaugeG.appendChild(minTxt);

    const maxTxt = svgEl('text', {
        x: cx + outerR + 2, y: cy + 14,
        'text-anchor': 'middle', 'font-size': '11', fill: ctx.css('--rui-text-muted'),
    });
    maxTxt.textContent = gMax;
    gaugeG.appendChild(maxTxt);

    svg.appendChild(gaugeG);
}

// ─────────────────────────────────────────
//  Sankey
// ─────────────────────────────────────────

function renderSankey(ctx) {
    const cfg = ctx.config;
    const pad = cfg.padding;
    const { svg, w: svgW, h: svgH } = layoutSvg(ctx, 300, 'chart-svg chart-svg-sankey');

    const plotW = svgW - pad.left - pad.right;
    const plotH = svgH - pad.top - pad.bottom;

    const nodes = cfg.nodes || [];
    const links = cfg.links || [];
    if (nodes.length === 0 || links.length === 0) {
        return;
    }

    // Build adjacency
    const nodeMap = new Map();
    nodes.forEach((n, i) => {
        nodeMap.set(n.id, { ...n, index: i, inLinks: [], outLinks: [], col: -1, value: 0 });
    });

    links.forEach(link => {
        const src = nodeMap.get(link.source);
        const tgt = nodeMap.get(link.target);
        if (src && tgt) {
            src.outLinks.push(link);
            tgt.inLinks.push(link);
        }
    });

    // Assign columns via BFS from sources
    const sources = [...nodeMap.values()].filter(n => n.inLinks.length === 0);
    if (sources.length === 0) sources.push(nodeMap.values().next().value);

    const queue = sources.map(n => { n.col = 0; return n; });
    let maxCol = 0;
    while (queue.length) {
        const node = queue.shift();
        node.outLinks.forEach(link => {
            const target = nodeMap.get(link.target);
            if (target && target.col < node.col + 1) {
                target.col = node.col + 1;
                maxCol = Math.max(maxCol, target.col);
                queue.push(target);
            }
        });
    }

    // Compute node values
    nodeMap.forEach(node => {
        const inVal = node.inLinks.reduce((s, l) => s + (l.value || 0), 0);
        const outVal = node.outLinks.reduce((s, l) => s + (l.value || 0), 0);
        node.value = Math.max(inVal, outVal) || 1;
    });

    // Group by column
    const columns = [];
    for (let c = 0; c <= maxCol; c++) {
        columns.push([...nodeMap.values()].filter(n => n.col === c));
    }

    // Position nodes
    const nodeWidth = Math.min(18, plotW / (maxCol + 1) * 0.2);
    const colSpacing = maxCol > 0 ? (plotW - nodeWidth) / maxCol : 0;

    columns.forEach((col, ci) => {
        const totalValue = col.reduce((s, n) => s + n.value, 0);
        const gap = Math.min(8, (plotH - totalValue) / Math.max(1, col.length - 1));
        const availH = plotH - gap * Math.max(0, col.length - 1);
        let y = pad.top;

        col.forEach(node => {
            const h = Math.max(4, (node.value / totalValue) * availH);
            node.x = pad.left + ci * colSpacing;
            node.y = y;
            node.h = h;
            node.w = nodeWidth;
            y += h + gap;
        });
    });

    // Draw links
    const linkG = svgEl('g', { class: 'chart-sankey-links' });
    svg.appendChild(linkG);

    const outOffsets = new Map();
    const inOffsets = new Map();
    nodeMap.forEach(n => {
        outOffsets.set(n.id, 0);
        inOffsets.set(n.id, 0);
    });

    links.forEach((link, li) => {
        const src = nodeMap.get(link.source);
        const tgt = nodeMap.get(link.target);
        if (!src || !tgt) return;

        const srcOutTotal = src.outLinks.reduce((s, l) => s + (l.value || 0), 0) || 1;
        const tgtInTotal = tgt.inLinks.reduce((s, l) => s + (l.value || 0), 0) || 1;
        const linkH_src = (link.value / srcOutTotal) * src.h;
        const linkH_tgt = (link.value / tgtInTotal) * tgt.h;
        const srcYOff = outOffsets.get(link.source);
        const tgtYOff = inOffsets.get(link.target);

        const x0 = src.x + src.w;
        const y0 = src.y + srcYOff;
        const x1 = tgt.x;
        const y1 = tgt.y + tgtYOff;
        const mx = (x0 + x1) / 2;

        const d = `M${x0},${y0}C${mx},${y0},${mx},${y1},${x1},${y1}` +
            `L${x1},${y1 + linkH_tgt}C${mx},${y1 + linkH_tgt},${mx},${y0 + linkH_src},${x0},${y0 + linkH_src}Z`;

        const color = link.color || src.color || PALETTE[li % PALETTE.length];
        const path = svgEl('path', {
            d, fill: color, 'fill-opacity': '0.3',
            class: 'chart-sankey-link', 'data-idx': li,
        });

        if (cfg.animate) {
            path.style.opacity = '0';
            path.style.transition = `opacity ${cfg.duration}ms ${cfg.easing}`;
            setTimeout(() => { path.style.opacity = '1'; }, li * 50);
        }

        bindHover(ctx, path, {
            datasetIndex: 0, index: li, value: link.value,
            label: `${src.label || src.id} → ${tgt.label || tgt.id}`,
        });
        linkG.appendChild(path);

        outOffsets.set(link.source, srcYOff + linkH_src);
        inOffsets.set(link.target, tgtYOff + linkH_tgt);
    });

    // Draw nodes
    const nodeG = svgEl('g', { class: 'chart-sankey-nodes' });
    svg.appendChild(nodeG);

    let ni = 0;
    nodeMap.forEach(node => {
        const color = node.color || PALETTE[ni % PALETTE.length];

        const rect = svgEl('rect', {
            x: node.x, y: node.y, width: node.w, height: node.h,
            rx: 2, fill: color, class: 'chart-sankey-node',
        });

        if (cfg.animate) {
            rect.style.opacity = '0';
            rect.style.transition = `opacity ${cfg.duration * 0.5}ms ${cfg.easing}`;
            setTimeout(() => { rect.style.opacity = '1'; }, ni * 30);
        }

        bindHover(ctx, rect, {
            datasetIndex: 0, index: ni, value: node.value,
            label: node.label || node.id,
        });
        nodeG.appendChild(rect);

        // Node label
        const lbl = svgEl('text', {
            x: node.x + node.w + 6,
            y: node.y + node.h / 2 + 4,
            'font-size': '11', fill: ctx.css('--rui-text'),
            class: 'chart-sankey-label',
        });
        if (node.col === maxCol) {
            lbl.setAttribute('x', node.x - 6);
            lbl.setAttribute('text-anchor', 'end');
        }
        lbl.textContent = node.label || node.id;
        nodeG.appendChild(lbl);

        ni++;
    });
}

// ─────────────────────────────────────────
//  Legend
// ─────────────────────────────────────────

/**
 * Render the chart legend below the chart.
 * @param {Object} ctx — chart context accessor
 */
export function renderLegend(ctx) {
    const cfg = ctx.config;
    const razyui = ctx.razyui;
    const legend = razyui.spell('div.chart-legend', true);
    PART.LEGEND.apply(legend);

    let items;
    if (cfg.type === 'pie' || cfg.type === 'donut') {
        items = cfg.labels.map((lbl, i) => ({ label: lbl, color: PALETTE[i % PALETTE.length] }));
    } else if (cfg.type === 'sankey') {
        items = (cfg.nodes || []).map((n, i) => ({ label: n.label || n.id, color: n.color || PALETTE[i % PALETTE.length] }));
    } else {
        items = cfg.datasets.map(ds => ({ label: ds.label, color: ds.color }));
    }

    items.forEach(item => {
        const entry = razyui.spell('span.chart-legend-item', true);
        entry.html(`<span class="chart-legend-swatch" style="background:${item.color}"></span>${item.label}`);
        legend.append(entry);
    });

    ctx.container.append(legend);
}
