/**
 * @fileoverview Chart component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — palette, defaults, SVG namespace
 *   helpers.js   — scale, geometry, SVG element factory, path smoothing
 *   state.js     — dataset normalisation
 *   view.js      — DOM/SVG construction for every chart type
 *   events.js    — centralised hover / click / tooltip binding
 *
 * @module module/Chart
 */

import { default as razyui, Elements } from '../../index.js';

import { DEFAULTS, DEFAULT_PADDING, TRADING_TYPES, LITE_TYPES, PART } from './constants.js';
import { mergeConfig }                 from './helpers.js';
import { render, cleanup }             from './view.js';
import {
    installTrading, renderTrading,
    installIndicators, renderIndicators,
    installLite, renderLite, renderBaseline,
    renderCompactToolbar, renderTimelineMap,
    installDatafeed, activateDatafeed, fetchHistory,
} from './features/index.js';

/**
 * Chart — SVG-based charting module for RazyUI v2
 *
 * Renders responsive SVG charts with entry animations powered by
 * razyui.animate() and CSS transitions.
 *
 * Supported types:
 *   'bar'          — vertical bar chart
 *   'hbar'         — horizontal bar chart
 *   'line'         — line chart with optional area fill
 *   'area'         — filled area chart (line + fill)
 *   'stacked-area' — stacked area chart
 *   'pie'          — pie chart
 *   'donut'        — donut (ring) chart
 *   'radar'        — radar / spider chart
 *   'gauge'        — gauge / dial chart
 *   'sankey'       — sankey flow diagram
 *   'scatter'      — scatter plot
 *   'bubble'       — bubble chart
 *   'inline-bar'   — sparkline bar chart
 *   'inline-line'  — sparkline line chart
 *
 * @param {string|Element} selector — CSS selector or DOM element
 * @param {Object}         [config] — chart configuration
 */
const Chart = class {

    #container = null;  // Elements wrapper
    #el        = null;  // raw DOM element
    #svg       = null;
    #config    = {};
    #tooltip   = null;
    #destroyed = false;
    #animControllers = [];

    // Feature flags
    #tradingInstalled    = false;
    #indicatorsInstalled = false;
    #liteInstalled       = false;
    #datafeedInstalled   = false;
    #datafeedCtrl        = null;
    #ctxObj              = null;   // cached context — same object across all rerenders

    /** Read a CSS variable from the chart host element (for SVG fills/strokes). */
    #css(varName) {
        return getComputedStyle(this.#el).getPropertyValue(varName).trim();
    }

    /**
     * Build a thin context object that view / events functions can use
     * to access private chart state without exposing #fields directly.
     *
     * IMPORTANT: the object is cached so that ad-hoc properties set on
     * `ctx` (e.g. `_mapState`, `_mapDragging`, `_timelineMapEl`,
     * `_indicatorSeries`) survive across rerenders.
     */
    #ctx() {
        if (this.#ctxObj) return this.#ctxObj;
        const self = this;
        this.#ctxObj = {
            get razyui()          { return razyui; },
            get container()       { return self.#container; },
            get config()          { return self.#config; },
            get tooltip()         { return self.#tooltip; },
            set tooltip(v)        { self.#tooltip = v; },
            get svg()             { return self.#svg; },
            set svg(v)            { self.#svg = v; },
            get animControllers() { return self.#animControllers; },
            set animControllers(v){ self.#animControllers = v; },
            css(varName)          { return self.#css(varName); },
            rerender()            { self.#installFeatures(); self.#render(); },
        };
        return this.#ctxObj;
    }

    constructor(selector, config = {}) {
        const el = razyui(selector)[0];
        if (!el) { console.warn('Chart: element not found \u2192', selector); return; }

        this.#el = el;
        this.#container = new Elements(el);
        this.#config = this.#mergeConfig(config);

        if (config.renderContext) {
            this.#container.addClass(`is-${config.renderContext}`);
        }

        // Install lazy-loadable features based on config
        this.#installFeatures();

        this.#render();
    }

    #mergeConfig(config) {
        return mergeConfig(DEFAULTS, DEFAULT_PADDING, config);
    }

    /**
     * Install feature modules based on chart type, enableTypes, and config.
     * Features are only installed once.
     *
     * `enableTypes` allows pre-installing multiple feature modules at init
     * so that runtime type-switching (e.g. candlestick ↔ ohlc ↔ heikin-ashi)
     * is instant with no lazy-load delay.
     */
    #installFeatures() {
        const ctx = this.#ctx();
        const type = this.#config.type;

        // Collect all types that need their feature modules installed:
        // the current type + any listed in enableTypes.
        const needed = new Set([type]);
        const enabled = this.#config.enableTypes;
        if (Array.isArray(enabled)) enabled.forEach(t => needed.add(t));

        for (const t of needed) {
            // Trading feature (candlestick / ohlc / heikin-ashi)
            if (TRADING_TYPES.includes(t) && !this.#tradingInstalled) {
                installTrading(ctx);
                this.#tradingInstalled = true;
            }
            // Lite price-line / baseline feature
            if (LITE_TYPES.includes(t) && !this.#liteInstalled) {
                installLite(ctx);
                this.#liteInstalled = true;
            }
        }

        // Indicators (when indicators config is present)
        if ((this.#config.indicators?.length || this.#config.indicatorPlugins?.length)
            && !this.#indicatorsInstalled) {
            installIndicators(ctx);
            this.#indicatorsInstalled = true;
        }

        // Datafeed (when liveFeed or historyFeed is configured)
        if ((this.#config.liveFeed || this.#config.historyFeed)
            && !this.#datafeedInstalled) {
            installDatafeed(ctx);
            this.#datafeedInstalled = true;
        }
    }

    /**
     * Render a compact dropdown toolbar for lite chart types.
     * Trading charts render their own via renderCompactToolbar inside renderTrading.
     */
    #renderTypeSwitcher(ctx) {
        const enableTypes = this.#config.enableTypes;
        if (!Array.isArray(enableTypes) || enableTypes.length <= 1) return;
        renderCompactToolbar(ctx, enableTypes, null, this.#config.type, null);
    }

    #renderPending = false;

    // ─────────────────────────────────────
    //  Render (delegates to view.js)
    // ─────────────────────────────────────

    #scheduleRender() {
        if (this.#renderPending) return;
        this.#renderPending = true;
        requestAnimationFrame(() => {
            this.#renderPending = false;
            if (this.#destroyed) return;
            this.#render();
        });
    }

    #render() {
        const ctx = this.#ctx();
        const type = this.#config.type;

        // ── Trading chart types (candlestick / ohlc / heikin-ashi) ──
        if (TRADING_TYPES.includes(type)) {
            cleanup(ctx);

            const mapDragging = ctx._mapDragging && ctx._timelineMapEl;

            // Pin the container's height so removing children doesn't
            // collapse it to 0 and cause the browser to scroll up.
            const hostEl = ctx.container[0];
            if (hostEl) ctx.container.css('min-height', hostEl.offsetHeight + 'px');

            if (mapDragging) {
                // During timeline-map drag: remove chart elements but
                // leave the map wrapper and its listeners completely untouched.
                [...hostEl.children].forEach(child => {
                    if (child !== ctx._timelineMapEl) child.remove();
                });
            } else {
                // Normal render: detach map first, then clear everything.
                const existingMap = ctx._timelineMapEl;
                if (existingMap?.parentNode) existingMap.parentNode.removeChild(existingMap);
                ctx.container.addClass('chart').html('');
            }

            // Apply container JIT styles (position:relative, overflow:hidden, etc.)
            PART.CONTAINER.apply(ctx.container);
            ctx.container.addClass('is-trading');

            // Tooltip element (must exist before renderTrading binds hover)
            if (this.#config.tooltip !== false) {
                const tipDiv = document.createElement('div');
                tipDiv.className = 'chart-tooltip';
                PART.TOOLTIP.apply(tipDiv);
                ctx.tooltip = ctx.razyui(tipDiv);
                ctx.container.append(ctx.tooltip);
            }

            const layout = renderTrading(ctx);

            if (layout && !layout._isCanvas) {
                // SVG path: draw indicators on top, then append SVG
                if (this.#indicatorsInstalled) {
                    renderIndicators(ctx, layout.svg, layout.viewData, layout);
                }
                ctx.container.append(layout.svg);
            }
            // Canvas path: canvas wrap + indicators already drawn inside renderCanvasTrading

            // Timeline map (mini-map navigator) — skip during drag
            if (layout && this.#config.timelineMap && !mapDragging) {
                renderTimelineMap(ctx, layout);
            }

            // During drag the map div was kept in-place while siblings
            // were removed and re-added — push it back to the end so
            // it always renders below the chart SVG.
            if (mapDragging && ctx._timelineMapEl?.parentNode) {
                ctx.container.append(ctx._timelineMapEl);
            }

            // Release the pinned height now that content is back in place.
            if (hostEl) ctx.container.css('min-height', '');

            // Activate data feeds (live polling / history fetch)
            if (this.#datafeedInstalled) {
                this.#datafeedCtrl = activateDatafeed(ctx);
            }
            return;
        }

        // ── Lite chart types (price-line / baseline) ──
        if (type === 'baseline') {
            cleanup(ctx);
            ctx.container.addClass('chart').html('');
            this.#renderTypeSwitcher(ctx);
            renderBaseline(ctx);
            return;
        }

        if (type === 'price-line') {
            cleanup(ctx);
            ctx.container.addClass('chart').html('');
            this.#renderTypeSwitcher(ctx);
            renderLite(ctx);
            return;
        }

        // All other chart types — original render path
        render(ctx);
    }

    // ─────────────────────────────────────
    //  Cleanup
    // ─────────────────────────────────────

    #cleanup() {
        cleanup(this.#ctx());
    }

    // ─────────────────────────────────────
    //  Public API
    // ─────────────────────────────────────

    /** Merge new config and re-render. */
    update(config) {
        if (this.#destroyed) return;
        this.#config = this.#mergeConfig(Object.assign({}, this.#config, config));
        this.#installFeatures();  // Re-check if new type needs a feature
        this.#scheduleRender();
    }

    /** Replace data and optionally labels. */
    setData(datasets, labels) {
        if (this.#destroyed) return;
        this.#config.datasets = datasets;
        if (labels) this.#config.labels = labels;
        this.#scheduleRender();
    }

    /**
     * Push a new data value to the first dataset and re-render.
     * Designed for inline-bar / inline-line timeline charts.
     * Automatically trims to maxBars / maxPoints.
     */
    push(value) {
        if (this.#destroyed) return;
        const cfg = this.#config;
        if (!cfg.datasets.length) cfg.datasets.push({ data: [] });
        cfg.datasets[0].data.push(value);

        const limit = cfg.maxBars || cfg.maxPoints || 0;
        if (limit > 0 && cfg.datasets[0].data.length > limit * 2) {
            cfg.datasets[0].data = cfg.datasets[0].data.slice(-limit);
        }
        this.#scheduleRender();
    }

    /**
     * Export chart as a data URL (PNG by default).
     *
     * @param {Object} [opts]
     * @param {string}  [opts.format='image/png']   — MIME type ('image/png', 'image/jpeg', 'image/webp')
     * @param {number}  [opts.quality=1]             — quality (0-1, for jpeg/webp)
     * @param {number}  [opts.scale=2]               — pixel-density scale (2 = Retina)
     * @param {string}  [opts.background]            — background color (default: transparent for png, '#fff' for jpeg)
     * @returns {Promise<string>} data URL
     */
    toDataURL(opts = {}) {
        const svg = this.#svg;
        if (!svg) return Promise.resolve('');

        const format   = opts.format   || 'image/png';
        const quality  = opts.quality  ?? 1;
        const scale    = opts.scale    ?? 2;
        const bgColor  = opts.background ?? (format === 'image/jpeg' ? '#1a1a2e' : null);

        // Clone SVG so we can inline computed styles without affecting the live DOM
        const clone = svg.cloneNode(true);

        // Inline critical computed styles from the live SVG into the clone.
        // This ensures exported PNGs look identical even without the stylesheet.
        const liveEls = svg.querySelectorAll('text, line, rect, path, circle, polygon, polyline');
        const cloneEls = clone.querySelectorAll('text, line, rect, path, circle, polygon, polyline');
        for (let i = 0; i < liveEls.length && i < cloneEls.length; i++) {
            const cs = getComputedStyle(liveEls[i]);
            const ce = cloneEls[i];
            // Copy fill / stroke / font if not already set as attributes
            if (!ce.getAttribute('fill')   && cs.fill   !== 'none') ce.setAttribute('fill', cs.fill);
            if (!ce.getAttribute('stroke') && cs.stroke !== 'none') ce.setAttribute('stroke', cs.stroke);
            if (ce.tagName === 'text') {
                if (!ce.getAttribute('font-family')) ce.setAttribute('font-family', cs.fontFamily);
                if (!ce.getAttribute('font-size'))   ce.setAttribute('font-size', cs.fontSize);
            }
        }

        const vb = svg.viewBox.baseVal;
        const w = vb.width  || 600;
        const h = vb.height || 300;

        const svgData = new XMLSerializer().serializeToString(clone);
        const blob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(blob);

        return new Promise(resolve => {
            const img = new Image();
            img.onload = () => {
                const canvas = document.createElement('canvas');
                canvas.width  = w * scale;
                canvas.height = h * scale;
                const ctx2d = canvas.getContext('2d');

                // Optional background fill (needed for JPEG which has no alpha)
                if (bgColor) {
                    ctx2d.fillStyle = bgColor;
                    ctx2d.fillRect(0, 0, canvas.width, canvas.height);
                }

                ctx2d.scale(scale, scale);
                ctx2d.drawImage(img, 0, 0, w, h);
                URL.revokeObjectURL(url);
                resolve(canvas.toDataURL(format, quality));
            };
            img.onerror = () => {
                URL.revokeObjectURL(url);
                resolve('');
            };
            img.src = url;
        });
    }

    /**
     * Add one or more annotations and re-render.
     * @param {...Object} annotations — annotation objects
     */
    addAnnotation(...annotations) {
        if (this.#destroyed) return;
        if (!this.#config.annotations) this.#config.annotations = [];
        this.#config.annotations.push(...annotations);
        this.#scheduleRender();
    }

    /**
     * Remove annotations by filter function and re-render.
     * @param {Function} filterFn — return true to KEEP the annotation
     */
    removeAnnotation(filterFn) {
        if (this.#destroyed) return;
        if (!this.#config.annotations) return;
        this.#config.annotations = this.#config.annotations.filter(filterFn);
        this.#scheduleRender();
    }

    /** Remove all annotations. */
    clearAnnotations() {
        if (this.#destroyed) return;
        this.#config.annotations = [];
        this.#scheduleRender();
    }

    /** Return a controller object. */
    getControl() {
        const self = this;
        return {
            get element() { return self.#el; },
            update:           (config) => self.update(config),
            setData:          (datasets, labels) => self.setData(datasets, labels),
            push:             (value) => self.push(value),
            destroy:          () => self.destroy(),
            toDataURL:        (opts) => self.toDataURL(opts),
            addAnnotation:    (...a) => self.addAnnotation(...a),
            removeAnnotation: (fn) => self.removeAnnotation(fn),
            clearAnnotations: () => self.clearAnnotations(),
            // ── Data Feed API ──
            /** Fetch historical bars and merge into dataset. */
            fetchHistory: (start, end, opts) => {
                return self.#datafeedCtrl
                    ? self.#datafeedCtrl.fetchHistory(start, end, opts)
                    : fetchHistory(self.#ctx(), start, end, opts);
            },
            /** Access the live feed controller (start/stop/setBarType/poll). */
            get liveFeed() { return self.#datafeedCtrl?.liveFeedCtrl || null; },
            /** Stop all data feeds. */
            stopFeed: () => { if (self.#datafeedCtrl) self.#datafeedCtrl.destroy(); },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        if (this.#datafeedCtrl) { this.#datafeedCtrl.destroy(); this.#datafeedCtrl = null; }
        this.#cleanup();
        this.#container.html('').removeClass('chart');
    }
};

export default Chart;
