/**
 * @fileoverview Canvas-based renderer for trading charts.
 *
 * Replaces per-candle SVG DOM elements with immediate-mode Canvas 2D
 * drawing for dramatically better pan/zoom performance with large datasets.
 *
 * Two-layer architecture:
 *   Main canvas    — chart data (candles, volume, grid, axes, indicators)
 *   Overlay canvas — crosshair, OHLC header, candle highlight
 *
 * Usage: called from `renderTrading()` when Canvas mode is active
 * (the default for trading charts; opt out with `useCanvas: false`).
 *
 * @module module/Chart/features/canvas-trading
 */

import razyui from '../../../index.js';
import { niceScale } from '../helpers.js';
import { sma, ema, bollingerBands, vwap, macd, rsi, volumeIndex } from './indicators.js';

const DPR = Math.max(1, typeof devicePixelRatio !== 'undefined' ? devicePixelRatio : 1);
const FONT = '-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif';
const WICK_W = 1.5;

// ─────────────────────────────────────────
//  Helpers
// ─────────────────────────────────────────

function makeCanvas(w, h) {
    const el = document.createElement('canvas');
    el.width  = Math.round(w * DPR);
    el.height = Math.round(h * DPR);
    el.style.width  = w + 'px';
    el.style.height = h + 'px';
    el.style.display = 'block';
    const c = el.getContext('2d');
    c.scale(DPR, DPR);
    return { el, c };
}

function cssVars(el) {
    const cs = getComputedStyle(el || document.body);
    return {
        grid:  cs.getPropertyValue('--rui-border').trim()     || '#333',
        muted: cs.getPropertyValue('--rui-text-muted').trim() || '#888',
    };
}

function roundRect(c, x, y, w, h, r) {
    if (c.roundRect) { c.beginPath(); c.roundRect(x, y, w, h, r); return; }
    c.beginPath();
    c.moveTo(x + r, y);
    c.arcTo(x + w, y, x + w, y + h, r);
    c.arcTo(x + w, y + h, x, y + h, r);
    c.arcTo(x, y + h, x, y, r);
    c.arcTo(x, y, x + w, y, r);
    c.closePath();
}

// ─────────────────────────────────────────
//  Viewport layout (recomputed on every pan/zoom)
// ─────────────────────────────────────────

function computeViewport(cfg, allData, S) {
    const visibleBars = cfg.visibleBars || Math.min(allData.length, 60);
    const startIdx = Math.max(0, cfg._viewStart ?? allData.length - visibleBars);
    const endIdx   = Math.min(allData.length, startIdx + visibleBars);
    const viewData = allData.slice(startIdx, endIdx);
    if (!viewData.length) return null;

    const { w, baseH, pad } = S;
    const volumeH     = cfg.showVolume !== false ? baseH * (cfg.volumeHeight || 0.2) : 0;
    const priceAreaTop = pad.top;
    const priceAreaH   = baseH - pad.top - pad.bottom - volumeH;
    const volumeTop    = priceAreaTop + priceAreaH + 4;
    const plotW        = w - pad.left - pad.right;
    const volAreaH     = volumeH - 8;

    let pMin = Infinity, pMax = -Infinity, vMax = 0;
    for (const d of viewData) {
        if (d.low  < pMin) pMin = d.low;
        if (d.high > pMax) pMax = d.high;
        if (d.volume > vMax) vMax = d.volume;
    }
    if (cfg.yMin != null) pMin = cfg.yMin;
    if (cfg.yMax != null) pMax = cfg.yMax;

    const priceScale = niceScale(pMin, pMax, 6);
    const pRange = priceScale.max - priceScale.min || 1;
    const toY = v => priceAreaTop + priceAreaH - ((v - priceScale.min) / pRange) * priceAreaH;

    const n        = viewData.length;
    const spacing  = plotW / n;
    const candleW  = spacing * (cfg.candleWidth || 0.7);
    const refOpen  = viewData[0].open;
    const maxLbl   = Math.floor(plotW / 60);
    const lblStep  = Math.max(1, Math.ceil(n / maxLbl));

    return {
        ...S,                   // carries w, h, baseH, pad, upColor, downColor, isOHLC, etc.
        viewData, startIdx, endIdx,
        visibleBars, plotW,
        priceAreaTop, priceAreaH,
        volumeTop, volumeH, volAreaH,
        priceScale, pRange, toY,
        n, spacing, candleW, vMax,
        refOpen, lblStep,
    };
}

// ─────────────────────────────────────────
//  Indicator computation
// ─────────────────────────────────────────

function computeIndicators(cfg, allData, L) {
    const indicators = cfg.indicators || [];
    if (!indicators.length) return { overlays: [], panels: [], series: [] };

    const allCloses = allData.map(d => d.close);
    const sl = arr => arr.slice(L.startIdx, L.startIdx + L.n);
    const overlays = [], panels = [], series = [];

    for (const ind of indicators) {
        switch (ind.type) {
            case 'sma': case 'ema': {
                const vals = (ind.type === 'ema' ? ema : sma)(allCloses, ind.period || 20);
                const v = sl(vals);
                const color = ind.color || (ind.type === 'ema' ? 'hsl(28,80%,52%)' : 'hsl(216,72%,56%)');
                overlays.push({ type: ind.type, values: v, color, lw: ind.lineWidth || 1.5 });
                series.push({ label: `${ind.type.toUpperCase()}(${ind.period || 20})`, color, values: v });
                break;
            }
            case 'bb': {
                const bb = bollingerBands(allCloses, ind.period || 20, ind.stdDev || 2);
                const color = ind.color || 'hsl(270,55%,56%)';
                const u = sl(bb.upper), mid = sl(bb.middle), lo = sl(bb.lower);
                overlays.push({ type: 'bb', upper: u, middle: mid, lower: lo, color, lw: ind.lineWidth || 1 });
                series.push({ label: `BB↑(${ind.period || 20})`, color, values: u });
                series.push({ label: `BB(${ind.period || 20})`, color, values: mid });
                series.push({ label: `BB↓(${ind.period || 20})`, color, values: lo });
                break;
            }
            case 'vwap': {
                const v = sl(vwap(allData));
                const color = ind.color || 'hsl(45,85%,50%)';
                overlays.push({ type: 'vwap', values: v, color, lw: ind.lineWidth || 1.5 });
                series.push({ label: 'VWAP', color, values: v });
                break;
            }
            case 'macd': {
                const r = macd(allCloses, ind.fast || 12, ind.slow || 26, ind.signal || 9);
                panels.push({
                    type: 'macd', pH: ind.panelHeight || 80,
                    macd: sl(r.macd), signal: sl(r.signal), hist: sl(r.histogram),
                    mc: ind.macdColor || 'hsl(216,72%,56%)',
                    sc: ind.signalColor || 'hsl(340,65%,55%)',
                });
                series.push({ label: 'MACD', color: ind.macdColor || 'hsl(216,72%,56%)', values: sl(r.macd), fmt: v => v.toFixed(2) });
                series.push({ label: 'Sig',  color: ind.signalColor || 'hsl(340,65%,55%)', values: sl(r.signal), fmt: v => v.toFixed(2) });
                break;
            }
            case 'rsi': {
                const v = sl(rsi(allCloses, ind.period || 14));
                panels.push({ type: 'rsi', pH: ind.panelHeight || 60, values: v, color: ind.color || 'hsl(270,55%,56%)', period: ind.period || 14 });
                series.push({ label: `RSI(${ind.period || 14})`, color: ind.color || 'hsl(270,55%,56%)', values: v, fmt: v => v.toFixed(1) });
                break;
            }
            case 'vi': {
                const v = sl(volumeIndex(allData, ind.period || 20));
                panels.push({ type: 'vi', pH: ind.panelHeight || 60, values: v, color: ind.color || 'hsl(175,55%,40%)', period: ind.period || 20 });
                series.push({ label: `VI(${ind.period || 20})`, color: ind.color || 'hsl(175,55%,40%)', values: v, fmt: v => v.toFixed(0) });
                break;
            }
        }
    }
    return { overlays, panels, series };
}

// ─────────────────────────────────────────
//  Main chart draw
// ─────────────────────────────────────────

function drawChart(c, L, cfg, css) {
    const { w, h, pad, plotW, viewData, priceAreaTop, priceAreaH, priceScale,
            toY, n, spacing, candleW, upColor, downColor, isOHLC,
            vMax, volumeTop, volAreaH, baseH, fmtPrice, fmtAxisDate,
            showPct, priceOnRight, refOpen, lblStep, startIdx, isDailyPlus } = L;

    const F10  = `10px ${FONT}`;
    const F10B = `600 10px ${FONT}`;
    const F9B  = `600 9px ${FONT}`;

    c.clearRect(0, 0, w, h);

    // ── Grid ──
    if (cfg.grid !== false) {
        c.save();
        c.setLineDash([3, 3]);
        c.lineWidth = 0.5;
        c.strokeStyle = css.grid;
        c.beginPath();
        for (const v of priceScale.steps) {
            const y = toY(v);
            if (y >= priceAreaTop && y <= priceAreaTop + priceAreaH) {
                c.moveTo(pad.left, y);
                c.lineTo(pad.left + plotW, y);
            }
        }
        c.stroke();
        c.restore();
    }

    // ── Price axis labels ──
    c.font = F10;
    c.textBaseline = 'middle';
    for (const v of priceScale.steps) {
        const y = toY(v);
        if (y < priceAreaTop || y > priceAreaTop + priceAreaH) continue;
        c.textAlign  = priceOnRight ? 'left' : 'right';
        c.fillStyle  = css.muted;
        c.fillText(fmtPrice(v), priceOnRight ? w - pad.right + 4 : pad.left - 4, y);
        if (showPct && refOpen) {
            const pct = ((v - refOpen) / refOpen) * 100;
            c.textAlign = priceOnRight ? 'right' : 'left';
            c.fillStyle = pct >= 0 ? upColor : downColor;
            c.fillText(`${pct >= 0 ? '+' : ''}${pct.toFixed(1)}%`,
                       priceOnRight ? pad.left - 4 : w - pad.right + 4, y);
        }
    }

    // ── Date / year-crossing separator lines ──
    for (let i = 1; i < n; i++) {
        const prev = new Date(viewData[i - 1].date);
        const curr = new Date(viewData[i].date);
        if (isNaN(prev) || isNaN(curr)) continue;
        const yr = prev.getFullYear() !== curr.getFullYear();
        const dy = !isDailyPlus && (yr || prev.getMonth() !== curr.getMonth() || prev.getDate() !== curr.getDate());
        if (!yr && !dy) continue;
        const cx = pad.left + spacing * i;
        c.save();
        c.globalAlpha = yr ? 0.35 : 0.18;
        c.strokeStyle = css.muted;
        c.lineWidth = 1;
        c.setLineDash([]);
        c.beginPath(); c.moveTo(cx, priceAreaTop); c.lineTo(cx, priceAreaTop + priceAreaH); c.stroke();
        c.restore();
        c.save();
        c.font = F9B; c.fillStyle = css.muted;
        c.globalAlpha = yr ? 0.5 : 0.4;
        c.textAlign = 'left'; c.textBaseline = 'top';
        c.fillText(yr ? String(curr.getFullYear()) : `${curr.getMonth() + 1}/${curr.getDate()}`, cx + 4, priceAreaTop + 2);
        c.restore();
    }

    // ── Candlesticks / OHLC ──
    for (let i = 0; i < n; i++) {
        const d  = viewData[i];
        const cx = pad.left + spacing * i + spacing / 2;
        const isUp = d.close >= d.open;
        const color = isUp ? upColor : downColor;
        const highY = toY(d.high), lowY = toY(d.low);
        const openY = toY(d.open), closeY = toY(d.close);
        const bodyTop = Math.min(openY, closeY);
        const bodyH   = Math.max(1, Math.abs(closeY - openY));

        if (isOHLC) {
            c.strokeStyle = color; c.lineWidth = WICK_W;
            c.beginPath();
            c.moveTo(cx, highY); c.lineTo(cx, lowY);
            c.moveTo(cx - candleW / 2, openY); c.lineTo(cx, openY);
            c.moveTo(cx, closeY); c.lineTo(cx + candleW / 2, closeY);
            c.stroke();
        } else {
            // Wick
            c.strokeStyle = color; c.lineWidth = WICK_W;
            c.beginPath(); c.moveTo(cx, highY); c.lineTo(cx, lowY); c.stroke();
            // Body
            if (isUp) {
                c.lineWidth = 1.2; c.strokeStyle = color;
                c.strokeRect(cx - candleW / 2, bodyTop, candleW, bodyH);
            } else {
                c.fillStyle = color;
                c.fillRect(cx - candleW / 2, bodyTop, candleW, bodyH);
            }
        }
    }

    // ── Volume overlay ──
    if (cfg.showVolume !== false && vMax > 0) {
        c.save();
        c.strokeStyle = css.grid; c.lineWidth = 0.5; c.setLineDash([]);
        c.beginPath(); c.moveTo(pad.left, volumeTop - 2); c.lineTo(pad.left + plotW, volumeTop - 2); c.stroke();
        c.globalAlpha = 0.35;
        for (let i = 0; i < n; i++) {
            const d  = viewData[i];
            const cx = pad.left + spacing * i + spacing / 2;
            c.fillStyle = d.close >= d.open ? upColor : downColor;
            const vh = (d.volume / vMax) * volAreaH;
            c.fillRect(cx - candleW / 2, volumeTop + volAreaH - vh, candleW, vh);
        }
        c.restore();
    }

    // ── Current price line ──
    if (cfg.showCurrentPrice !== false && n) {
        const last = viewData[n - 1];
        const isUp = last.close >= last.open;
        const color = isUp ? upColor : downColor;
        const y = toY(last.close);
        c.save();
        c.setLineDash([4, 2]); c.strokeStyle = color; c.globalAlpha = 0.7; c.lineWidth = 1;
        c.beginPath(); c.moveTo(pad.left, y); c.lineTo(w - pad.right, y); c.stroke();
        c.restore();
        // Badge
        const bH = 16;
        const bW = (priceOnRight ? pad.right : pad.left) - 2;
        const bX = priceOnRight ? w - pad.right + 1 : 1;
        c.fillStyle = color;
        roundRect(c, bX, y - bH / 2, bW, bH, 2); c.fill();
        c.font = F9B; c.textAlign = 'end'; c.textBaseline = 'middle'; c.fillStyle = '#fff';
        c.fillText(fmtPrice(last.close), priceOnRight ? w - 4 : pad.left - 4, y);
    }

    // ── Date axis labels ──
    c.font = F10; c.fillStyle = css.muted; c.textAlign = 'center'; c.textBaseline = 'middle';
    for (let i = 0; i < n; i++) {
        if (i % lblStep) continue;
        c.fillText(fmtAxisDate(viewData[i].date), pad.left + spacing * i + spacing / 2, baseH - pad.bottom / 2);
    }

    // ── OHLC header (last candle) ──
    _drawOHLCHeader(c, L, viewData[n - 1], css, null);

    // ── Annotations ──
    if (cfg.annotations?.length) _drawAnnotations(c, L, cfg.annotations, css);
}

// ─────────────────────────────────────────
//  OHLC Header
// ─────────────────────────────────────────

function _drawOHLCHeader(c, L, d, css, hoverSeries) {
    const { pad, plotW, upColor, downColor, fmtPrice } = L;
    const isUp = d.close >= d.open;
    const color = isUp ? upColor : downColor;
    const items = [
        { l: 'O', v: fmtPrice(d.open) },  { l: 'H', v: fmtPrice(d.high) },
        { l: 'L', v: fmtPrice(d.low) },   { l: 'C', v: fmtPrice(d.close) },
    ];
    if (d.volume != null) items.push({ l: 'Vol', v: d.volume.toLocaleString() });

    const F10  = `10px ${FONT}`;
    const F10B = `600 10px ${FONT}`;
    let x = pad.left + 4, y = pad.top + 3;

    for (const { l, v } of items) {
        c.font = F10; c.fillStyle = css.muted; c.textAlign = 'left'; c.textBaseline = 'top';
        c.fillText(l + ' ', x, y);
        x += c.measureText(l + ' ').width + 2;
        c.font = F10B; c.fillStyle = color;
        c.fillText(v, x, y);
        x += c.measureText(v).width + 8;
    }

    // Indicator series
    if (hoverSeries?.length) {
        const maxX = pad.left + plotW - 10;
        let ix = pad.left + 4, row = 0;
        for (const s of hoverSeries) {
            const sv = s.values?.[s._idx];
            if (sv == null) continue;
            const fmt = s.fmt || fmtPrice;
            const fv  = fmt(sv);
            c.font = F10;
            const lW = c.measureText(s.label + ' ').width + 2;
            c.font = F10B;
            const vW = c.measureText(fv).width + 8;
            if (ix + lW + vW > maxX && ix > pad.left + 4) { row++; ix = pad.left + 4; }
            const iy = pad.top + 18 + row * 13;
            c.font = F10; c.fillStyle = css.muted; c.fillText(s.label + ' ', ix, iy); ix += lW;
            c.font = F10B; c.fillStyle = s.color; c.fillText(fv, ix, iy); ix += vW;
        }
    }
}

// ─────────────────────────────────────────
//  Overlay indicators (on price area)
// ─────────────────────────────────────────

function drawOverlays(c, L, overlays) {
    for (const ov of overlays) {
        if (ov.type === 'bb') {
            _drawLine(c, L, ov.upper, ov.color, ov.lw, true);
            _drawLine(c, L, ov.middle, ov.color, ov.lw, false);
            _drawLine(c, L, ov.lower, ov.color, ov.lw, true);
            // Fill band
            c.save(); c.globalAlpha = 0.05; c.fillStyle = ov.color;
            c.beginPath();
            let started = false;
            for (let i = 0; i < L.n; i++) {
                if (ov.upper[i] == null) continue;
                const x = L.pad.left + L.spacing * i + L.spacing / 2;
                if (!started) { c.moveTo(x, L.toY(ov.upper[i])); started = true; }
                else c.lineTo(x, L.toY(ov.upper[i]));
            }
            for (let i = L.n - 1; i >= 0; i--) {
                if (ov.lower[i] == null) continue;
                c.lineTo(L.pad.left + L.spacing * i + L.spacing / 2, L.toY(ov.lower[i]));
            }
            c.closePath(); c.fill(); c.restore();
        } else {
            _drawLine(c, L, ov.values, ov.color, ov.lw, false);
        }
    }
}

function _drawLine(c, L, values, color, lw, dashed) {
    c.save();
    c.strokeStyle = color; c.lineWidth = lw || 1.5; c.lineJoin = 'round';
    if (dashed) c.setLineDash([4, 3]);
    c.beginPath();
    let s = false;
    for (let i = 0; i < L.n; i++) {
        if (values[i] == null) { s = false; continue; }
        const x = L.pad.left + L.spacing * i + L.spacing / 2;
        if (!s) { c.moveTo(x, L.toY(values[i])); s = true; } else c.lineTo(x, L.toY(values[i]));
    }
    c.stroke(); c.restore();
}

// ─────────────────────────────────────────
//  Panel indicators (MACD, RSI, VI)
// ─────────────────────────────────────────

function drawPanels(c, L, panels, css) {
    let off = L.baseH;
    for (const p of panels) {
        // Separator
        c.strokeStyle = css.grid; c.lineWidth = 0.5; c.setLineDash([]);
        c.beginPath(); c.moveTo(L.pad.left, off); c.lineTo(L.pad.left + L.plotW, off); c.stroke();

        if (p.type === 'macd') _drawMACD(c, L, p, off, css);
        else if (p.type === 'rsi') _drawRSI(c, L, p, off, css);
        else if (p.type === 'vi') _drawVI(c, L, p, off, css);
        off += p.pH + 8;
    }
}

function _drawMACD(c, L, p, off, css) {
    const vals = [...p.macd, ...p.signal, ...p.hist].filter(v => v != null);
    if (!vals.length) return;
    let mn = Math.min(...vals), mx = Math.max(...vals);
    if (mn === mx) { mn -= 1; mx += 1; }
    const rng = mx - mn || 1;
    const tY = v => off + p.pH - ((v - mn) / rng) * p.pH;
    const zY = tY(0);
    // Histogram
    const bw = L.spacing * 0.6;
    c.globalAlpha = 0.5;
    for (let i = 0; i < L.n; i++) {
        const v = p.hist[i]; if (v == null) continue;
        const cx = L.pad.left + L.spacing * i + L.spacing / 2;
        c.fillStyle = v >= 0 ? L.upColor : L.downColor;
        c.fillRect(cx - bw / 2, Math.min(tY(v), zY), bw, Math.abs(tY(v) - zY));
    }
    c.globalAlpha = 1;
    // Lines
    _drawPanelLine(c, L, p.macd, p.mc, 1.5, tY);
    _drawPanelLine(c, L, p.signal, p.sc, 1, tY);
    // Zero
    c.save(); c.setLineDash([3, 3]); c.strokeStyle = css.muted; c.lineWidth = 0.5; c.globalAlpha = 0.5;
    c.beginPath(); c.moveTo(L.pad.left, zY); c.lineTo(L.pad.left + L.plotW, zY); c.stroke(); c.restore();
    // Label
    c.font = `600 9px ${FONT}`; c.fillStyle = css.muted; c.textAlign = 'left'; c.textBaseline = 'top';
    c.fillText('MACD', L.pad.left + 4, off + 2);
}

function _drawRSI(c, L, p, off, css) {
    const tY = v => off + p.pH - (v / 100) * p.pH;
    // Guides
    c.save(); c.setLineDash([3, 3]); c.strokeStyle = css.muted; c.lineWidth = 0.5; c.globalAlpha = 0.4;
    c.beginPath(); c.moveTo(L.pad.left, tY(30)); c.lineTo(L.pad.left + L.plotW, tY(30));
    c.moveTo(L.pad.left, tY(70)); c.lineTo(L.pad.left + L.plotW, tY(70)); c.stroke(); c.restore();
    // Zone fill
    c.save(); c.globalAlpha = 0.04; c.fillStyle = p.color;
    c.fillRect(L.pad.left, tY(70), L.plotW, tY(30) - tY(70)); c.restore();
    _drawPanelLine(c, L, p.values, p.color, 1.5, tY);
    c.font = `600 9px ${FONT}`; c.fillStyle = css.muted; c.textAlign = 'left'; c.textBaseline = 'top';
    c.fillText(`RSI(${p.period})`, L.pad.left + 4, off + 2);
}

function _drawVI(c, L, p, off, css) {
    const v = p.values.filter(x => x != null);
    if (!v.length) return;
    let mn = Math.min(...v), mx = Math.max(...v);
    if (mn === mx) { mn -= 1; mx += 1; }
    const rng = mx - mn || 1;
    const tY = val => off + p.pH - ((val - mn) / rng) * p.pH;
    _drawPanelLine(c, L, p.values, p.color, 1.5, tY);
    // Zero
    c.save(); c.setLineDash([3, 3]); c.strokeStyle = css.muted; c.lineWidth = 0.5; c.globalAlpha = 0.5;
    c.beginPath(); c.moveTo(L.pad.left, tY(0)); c.lineTo(L.pad.left + L.plotW, tY(0)); c.stroke(); c.restore();
    c.font = `600 9px ${FONT}`; c.fillStyle = css.muted; c.textAlign = 'left'; c.textBaseline = 'top';
    c.fillText(`VI(${p.period})`, L.pad.left + 4, off + 2);
}

function _drawPanelLine(c, L, vals, color, lw, tY) {
    c.save(); c.strokeStyle = color; c.lineWidth = lw; c.lineJoin = 'round';
    c.beginPath(); let s = false;
    for (let i = 0; i < L.n; i++) {
        if (vals[i] == null) { s = false; continue; }
        const x = L.pad.left + L.spacing * i + L.spacing / 2;
        if (!s) { c.moveTo(x, tY(vals[i])); s = true; } else c.lineTo(x, tY(vals[i]));
    }
    c.stroke(); c.restore();
}

// ─────────────────────────────────────────
//  Annotations
// ─────────────────────────────────────────

function _drawAnnotations(c, L, annotations, css) {
    const { pad, plotW, priceAreaTop, priceAreaH, spacing, viewData, toY, fmtPrice, w } = L;
    function dToX(date) {
        const t = date instanceof Date ? date.getTime() : typeof date === 'number' ? date : new Date(date).getTime();
        for (let i = 0; i < viewData.length; i++) {
            const ts = viewData[i].date instanceof Date ? viewData[i].date.getTime() : new Date(viewData[i].date).getTime();
            if (ts >= t) {
                if (i > 0) {
                    const pt = viewData[i - 1].date instanceof Date ? viewData[i - 1].date.getTime() : new Date(viewData[i - 1].date).getTime();
                    if (t - pt < ts - t) return pad.left + (i - 1) * spacing + spacing / 2;
                }
                return pad.left + i * spacing + spacing / 2;
            }
        }
        return pad.left + (viewData.length - 1) * spacing + spacing / 2;
    }
    for (const a of annotations) {
        switch (a.type) {
            case 'hline': {
                const y = toY(a.price);
                c.save(); c.strokeStyle = a.color || 'hsl(45,85%,55%)'; c.lineWidth = a.width || 1;
                c.setLineDash((a.dash || '6,3').split(',').map(Number)); c.globalAlpha = 0.8;
                c.beginPath(); c.moveTo(pad.left, y); c.lineTo(pad.left + plotW, y); c.stroke(); c.restore();
                if (a.label) { c.font = `600 9px ${FONT}`; c.fillStyle = a.color || 'hsl(45,85%,55%)'; c.textAlign = 'left'; c.textBaseline = 'middle'; c.fillText(a.label, pad.left + plotW + 4, y); }
                break;
            }
            case 'vline': {
                const x = dToX(a.date);
                c.save(); c.strokeStyle = a.color || 'hsl(270,55%,56%)'; c.lineWidth = a.width || 1;
                c.setLineDash((a.dash || '6,3').split(',').map(Number)); c.globalAlpha = 0.8;
                c.beginPath(); c.moveTo(x, priceAreaTop); c.lineTo(x, priceAreaTop + priceAreaH); c.stroke(); c.restore();
                if (a.label) { c.font = `600 9px ${FONT}`; c.fillStyle = a.color || 'hsl(270,55%,56%)'; c.textAlign = 'center'; c.textBaseline = 'bottom'; c.fillText(a.label, x, priceAreaTop - 4); }
                break;
            }
            case 'marker': {
                const x = dToX(a.date), y = toY(a.price), cl = a.color || 'hsl(45,85%,55%)', sz = a.size || 6;
                c.save(); c.fillStyle = cl; c.globalAlpha = 0.85;
                c.beginPath(); c.arc(x, y, sz, 0, Math.PI * 2); c.fill(); c.restore();
                if (a.label) { c.font = `600 9px ${FONT}`; c.fillStyle = cl; c.textAlign = 'center'; c.textBaseline = 'bottom'; c.fillText(a.label, x, y - sz - 4); }
                break;
            }
            case 'trendline': {
                if (!a.from || !a.to) break;
                c.save(); c.strokeStyle = a.color || 'hsl(216,72%,56%)'; c.lineWidth = a.width || 1.5; c.lineCap = 'round';
                if (a.dash) c.setLineDash(a.dash.split(',').map(Number));
                c.beginPath(); c.moveTo(dToX(a.from.date), toY(a.from.price));
                c.lineTo(dToX(a.to.date), toY(a.to.price)); c.stroke(); c.restore();
                break;
            }
            case 'range': {
                const x1 = dToX(a.from), x2 = dToX(a.to);
                c.save(); c.fillStyle = a.color || 'hsl(216,72%,56%)'; c.globalAlpha = a.opacity ?? 0.08;
                c.fillRect(Math.min(x1, x2), priceAreaTop, Math.abs(x2 - x1), priceAreaH); c.restore();
                break;
            }
            case 'event': {
                const x = dToX(a.date), cl = a.color || 'hsl(45,85%,55%)', top = (a.position || 'top') === 'top';
                const y = top ? priceAreaTop + 6 : priceAreaTop + priceAreaH - 6;
                const text = a.label || '';
                c.save(); c.strokeStyle = cl; c.globalAlpha = 0.5; c.lineWidth = 1;
                c.beginPath(); c.moveTo(x, top ? priceAreaTop : priceAreaTop + priceAreaH); c.lineTo(x, y); c.stroke(); c.restore();
                c.font = `700 8px ${FONT}`;
                const tw = c.measureText(text).width + 8;
                c.save(); c.fillStyle = cl; c.globalAlpha = 0.9;
                roundRect(c, x - tw / 2, top ? y - 14 : y, tw, 14, 2); c.fill(); c.restore();
                c.fillStyle = '#fff'; c.textAlign = 'center'; c.textBaseline = 'middle';
                c.fillText(text, x, top ? y - 7 : y + 7);
                break;
            }
        }
    }
}

// ─────────────────────────────────────────
//  Crosshair overlay
// ─────────────────────────────────────────

function setupCrosshair(wrap, overEl, overC, ctx, getL, cssFn) {
    const cfg = ctx.config;
    if (cfg._crosshairAC) cfg._crosshairAC.abort();
    const ac = new AbortController();
    cfg._crosshairAC = ac;
    const sig = { signal: ac.signal };

    function draw(e) {
        const L = getL();
        if (!L) return;
        const css = cssFn();
        const { w, h, pad, plotW, priceAreaTop, priceAreaH, priceScale, pRange,
                n, spacing, candleW, viewData, fmtPrice, fmtAxisDate, fmtDate,
                upColor, downColor, toY, startIdx, baseH, priceOnRight } = L;

        const rect = wrap.getBoundingClientRect();
        const mx = (e.clientX - rect.left) * (w / rect.width);
        const my = (e.clientY - rect.top) * (h / rect.height);
        overC.clearRect(0, 0, w, h);

        if (mx < pad.left || mx > pad.left + plotW || my < priceAreaTop || my > priceAreaTop + priceAreaH) {
            if (ctx.tooltip) razyui(ctx.tooltip).removeClass('is-visible');
            return;
        }

        let idx = Math.floor((mx - pad.left) / spacing);
        idx = Math.max(0, Math.min(n - 1, idx));
        const sx = pad.left + idx * spacing + spacing / 2;

        // Lines
        overC.save(); overC.setLineDash([4, 3]); overC.strokeStyle = css.muted; overC.lineWidth = 0.5;
        overC.beginPath();
        overC.moveTo(pad.left, my); overC.lineTo(pad.left + plotW, my);
        overC.moveTo(sx, priceAreaTop); overC.lineTo(sx, priceAreaTop + priceAreaH);
        overC.stroke(); overC.restore();

        // Price tag
        const price = priceScale.min + (1 - (my - priceAreaTop) / priceAreaH) * pRange;
        const tagX = priceOnRight ? w - pad.right : 0;
        const tagW = priceOnRight ? pad.right : pad.left;
        overC.fillStyle = 'hsl(220,12%,22%)';
        roundRect(overC, tagX, my - 8, tagW, 16, 2); overC.fill();
        overC.font = `10px ${FONT}`; overC.textAlign = 'end'; overC.textBaseline = 'middle'; overC.fillStyle = '#fff';
        overC.fillText(fmtPrice(price), priceOnRight ? w - 4 : pad.left - 4, my);

        // Date tag
        if (idx < n) {
            const dl = fmtAxisDate(viewData[idx].date);
            overC.font = `9px ${FONT}`;
            const tw = overC.measureText(dl).width + 12;
            overC.fillStyle = 'hsl(220,12%,22%)';
            roundRect(overC, sx - tw / 2, baseH - pad.bottom, tw, 16, 2); overC.fill();
            overC.fillStyle = '#fff'; overC.textAlign = 'center'; overC.textBaseline = 'top';
            overC.fillText(dl, sx, baseH - pad.bottom + 3);
        }

        // Highlight candle
        if (idx < n) {
            const d = viewData[idx];
            const hx = pad.left + spacing * idx + spacing / 2;
            overC.save(); overC.globalCompositeOperation = 'lighter'; overC.globalAlpha = 0.18;
            overC.fillStyle = d.close >= d.open ? upColor : downColor;
            overC.fillRect(hx - candleW / 2 - 2, toY(d.high) - 2, candleW + 4, toY(d.low) - toY(d.high) + 4);
            overC.restore();
        }

        // OHLC header for hovered candle (drawn on overlay, clears header area)
        if (idx < n) {
            const hdrX = pad.left;
            const hdrH = 50;
            overC.clearRect(hdrX, pad.top, plotW, hdrH);
            // Fill with chart background so main canvas header is hidden beneath
            overC.fillStyle = getComputedStyle(wrap).getPropertyValue('--rui-bg-inset').trim() || getComputedStyle(wrap).getPropertyValue('--rui-bg').trim() || '#fff';
            overC.fillRect(hdrX, pad.top, plotW, hdrH);
            const series = (ctx._indicatorSeries || []).map(s => ({ ...s, _idx: idx }));
            _drawOHLCHeader(overC, L, viewData[idx], css, series.length ? series : null);
        }

        // Tooltip
        if (idx < n && ctx.tooltip) {
            const d = viewData[idx];
            const ch = d.close - d.open;
            const chPct = ((ch / d.open) * 100).toFixed(2);
            const chS = ch >= 0 ? '+' : '';
            const $tip = razyui(ctx.tooltip);
            $tip.html(
                `<strong>${fmtDate(d.date)}</strong><br>` +
                `O: ${fmtPrice(d.open)}  H: ${fmtPrice(d.high)}<br>` +
                `L: ${fmtPrice(d.low)}  C: ${fmtPrice(d.close)}<br>` +
                (d.volume ? `Vol: ${d.volume.toLocaleString()}<br>` : '') +
                `<span style="color:${ch >= 0 ? upColor : downColor}">${chS}${fmtPrice(ch)} (${chS}${chPct}%)</span>`
            );
            $tip.addClass('is-visible');

            const cRect = ctx.container.getRect();
            const tipEl = $tip[0] || $tip.el;
            const tipW = tipEl?.offsetWidth || 140;
            const tipH = tipEl?.offsetHeight || 100;

            // Position tooltip near cursor, flip to avoid overflow
            let tl = e.clientX - cRect.left + 16;
            let tt = e.clientY - cRect.top - 8;
            if (tl + tipW > cRect.width) tl = e.clientX - cRect.left - tipW - 16;
            if (tt + tipH > cRect.height) tt = cRect.height - tipH - 4;
            if (tt < 0) tt = 4;
            $tip.css({ left: tl + 'px', top: tt + 'px' });

            if (typeof cfg.onCrosshair === 'function') {
                cfg.onCrosshair({ date: d.date, open: d.open, high: d.high, low: d.low, close: d.close, volume: d.volume, price, index: startIdx + idx });
            }
        }
    }

    function clear() {
        const L = getL();
        if (L) overC.clearRect(0, 0, L.w, L.h);
        if (ctx.tooltip) razyui(ctx.tooltip).removeClass('is-visible');
    }

    wrap.addEventListener('mousemove', draw, sig);
    wrap.addEventListener('mouseleave', clear, sig);
}

// ─────────────────────────────────────────
//  Pan & Zoom (Canvas-optimised)
// ─────────────────────────────────────────

function setupCanvasPanZoom(wrap, ctx, getL, allData) {
    const cfg = ctx.config;
    if (cfg._canvasPanZoomAC) cfg._canvasPanZoomAC.abort();
    const ac = new AbortController();
    cfg._canvasPanZoomAC = ac;
    const sig = { signal: ac.signal };

    function svgCoords(e) {
        const L = getL(); if (!L) return { x: 0, y: 0 };
        const r = wrap.getBoundingClientRect();
        return { x: (e.clientX - r.left) * (L.w / r.width), y: (e.clientY - r.top) * (L.h / r.height) };
    }
    function pxPerBar() {
        const L = getL(); if (!L) return 10;
        return (L.spacing * wrap.getBoundingClientRect().width) / L.w;
    }

    // Wheel zoom
    wrap.addEventListener('wheel', (e) => {
        if (cfg.enableZoom === false) return;
        e.preventDefault(); e.stopPropagation();
        const L = getL(); if (!L) return;
        const delta = e.deltaY > 0 ? (cfg.zoomStep || 5) : -(cfg.zoomStep || 5);
        const nv = Math.max(10, Math.min(allData.length, L.visibleBars + delta));
        if (nv === L.visibleBars) return;
        cfg.visibleBars = nv;
        const { x: sx } = svgCoords(e);
        const mx = Math.max(0, Math.min(1, (sx - L.pad.left) / L.plotW));
        const center = L.startIdx + Math.floor(L.visibleBars * mx);
        cfg._viewStart = Math.max(0, Math.min(allData.length - nv, center - Math.floor(nv * mx)));
        ctx._canvasRedraw();
    }, { passive: false, signal: ac.signal });

    let mode = null, dsX = 0, dsY = 0, dvs = 0, lbd = 0;

    wrap.addEventListener('mousedown', (e) => {
        if (e.button !== 0 || cfg.enablePan === false) return;
        e.preventDefault();
        const L = getL(); if (!L) return;
        const { x: sx } = svgCoords(e);
        if (sx < L.pad.left || sx > L.pad.left + L.plotW) {
            mode = 'yscale'; dsY = e.clientY; wrap.style.cursor = 'ns-resize';
        } else {
            mode = 'pan'; dsX = e.clientX; dvs = cfg._viewStart ?? L.startIdx; lbd = 0;
            wrap.style.cursor = 'grabbing';
        }
    }, sig);

    document.addEventListener('mousemove', (e) => {
        if (!mode) return;
        const L = getL(); if (!L) return;
        if (mode === 'pan') {
            const bd = Math.round(-(e.clientX - dsX) / pxPerBar());
            if (bd !== lbd) {
                lbd = bd;
                const ns = Math.max(0, Math.min(allData.length - L.visibleBars, dvs + bd));
                if (ns !== cfg._viewStart) { cfg._viewStart = ns; ctx._canvasRedraw(); }
            }
        } else if (mode === 'yscale') {
            const dy = e.clientY - dsY; dsY = e.clientY;
            let pMn = cfg.yMin, pMx = cfg.yMax;
            if (pMn == null || pMx == null) {
                let a = Infinity, b = -Infinity;
                for (const d of L.viewData) { if (d.low < a) a = d.low; if (d.high > b) b = d.high; }
                if (pMn == null) pMn = a; if (pMx == null) pMx = b;
            }
            const mid = (pMn + pMx) / 2, half = Math.max((pMx - pMn) / 2 * (1 + dy * 0.001), 0.01);
            cfg.yMin = mid - half; cfg.yMax = mid + half;
            ctx._canvasRedraw();
        }
    }, sig);

    document.addEventListener('mouseup', () => { mode = null; wrap.style.cursor = ''; }, sig);

    wrap.addEventListener('dblclick', (e) => {
        const L = getL(); if (!L) return;
        const { x: sx } = svgCoords(e);
        if (sx < L.pad.left || sx > L.pad.left + L.plotW) {
            cfg.yMin = null; cfg.yMax = null; ctx._canvasRedraw();
        }
    }, sig);
}

// ─────────────────────────────────────────
//  Map visual sync
// ─────────────────────────────────────────

function syncMapVisuals(ctx) {
    const cfg = ctx.config;
    const s = ctx._mapState;
    if (!s) return;
    const vis = cfg.visibleBars || 60;
    const si  = cfg._viewStart ?? Math.max(0, s.totalBars - vis);
    const wL  = Math.max(s.plotL, s.idxToX(si));
    const wR  = Math.min(s.plotR, s.idxToX(Math.min(si + vis, s.totalBars)));
    s.winL = wL; s.winR = wR;
    s.winRect.setAttribute('x', wL);
    s.winRect.setAttribute('width', Math.max(0, wR - wL));
    s.dimLeft.setAttribute('width', Math.max(0, wL));
    s.dimRight.setAttribute('x', wR);
    s.dimRight.setAttribute('width', Math.max(0, s.svgW - wR));
    s.gripL.setAttribute('x1', wL); s.gripL.setAttribute('x2', wL);
    s.gripR.setAttribute('x1', wR); s.gripR.setAttribute('x2', wR);
}

// ═════════════════════════════════════════
//  Main export
// ═════════════════════════════════════════

/**
 * Render a trading chart using Canvas instead of SVG.
 *
 * @param {Object} ctx  — chart context bridge
 * @param {Object} opts — pre-computed layout + allData from renderTrading
 * @returns {Object} layout info (compatible with SVG path return)
 */
export function renderCanvasTrading(ctx, opts) {
    const cfg = ctx.config;
    const { svgW: w, svgH: h, baseH, pad, allData, upColor, downColor,
            isOHLC, isDailyPlus, fmtPrice, fmtDate, fmtAxisDate,
            priceOnRight, showPct } = opts;

    // Static layout (unchanged across redraws)
    const S = { w, h, baseH, pad, upColor, downColor, isOHLC, isDailyPlus,
                fmtPrice, fmtDate, fmtAxisDate, priceOnRight, showPct };

    // Create canvas layers
    const wrap = document.createElement('div');
    wrap.className = 'chart-canvas-wrap';
    wrap.style.cssText = `position:relative;width:100%;height:${h}px;`;

    const { el: mainEl, c: mainC } = makeCanvas(w, h);
    mainEl.className = 'chart-canvas-main';

    const { el: overEl, c: overC } = makeCanvas(w, h);
    overEl.className = 'chart-canvas-overlay';
    overEl.style.cssText += ';position:absolute;top:0;left:0;pointer-events:none;';

    wrap.appendChild(mainEl);
    wrap.appendChild(overEl);

    let curL = null;

    function redraw() {
        const css = cssVars(ctx.container[0]);
        curL = computeViewport(cfg, allData, S);
        if (!curL) return;
        curL._css = css;

        // Compute indicators
        const inds = computeIndicators(cfg, allData, curL);
        ctx._indicatorSeries = inds.series;

        // Draw
        drawChart(mainC, curL, cfg, css);
        drawOverlays(mainC, curL, inds.overlays);
        drawPanels(mainC, curL, inds.panels, css);

        // Sync timeline map
        syncMapVisuals(ctx);
    }

    redraw();

    if (!curL) {
        ctx.container.append(razyui(wrap));
        return { _isCanvas: true, allData, pad, svgW: w };
    }

    // Fast redraw for pan/zoom (no DOM manipulation)
    ctx._canvasRedraw = redraw;

    // Crosshair & pan/zoom
    setupCrosshair(wrap, overEl, overC, ctx, () => curL, () => cssVars(ctx.container[0]));
    setupCanvasPanZoom(wrap, ctx, () => curL, allData);

    ctx.container.append(razyui(wrap));
    cfg._rendered = true;

    return {
        _isCanvas: true,
        viewData: curL.viewData,   pad: curL.pad,
        plotW: curL.plotW,         priceAreaTop: curL.priceAreaTop,
        priceAreaH: curL.priceAreaH, priceScale: curL.priceScale,
        candleSpacing: curL.spacing, startIdx: curL.startIdx,
        svgW: w, baseH, allData,
        toY: curL.toY,            fmtPrice: curL.fmtPrice,
    };
}
