/**
 * @fileoverview Chart DataFeed feature — live tick polling & history range fetching.
 *
 * Provides two data-fetch modes for trading charts:
 *
 * ## 1. Live Fetch (`liveFeed`)
 *
 * Periodically polls the backend for new ticks since the last known bar.
 * The backend returns only the *new* data (incremental update).
 *
 * ```js
 * new Chart('#el', {
 *     type: 'candlestick',
 *     liveFeed: {
 *         url: '/api/ticks/live',
 *         interval: 5000,           // poll every 5s (default)
 *         barType: '5m',            // sent as POST body
 *         // Per-barType interval override:
 *         intervals: {
 *             '1m': 3000,
 *             '5m': 5000,
 *             '1h': 30000,
 *             '1D': 60000,
 *         },
 *         headers: {},              // extra fetch headers
 *         transform: (json) => json.data,  // extract data array from response
 *         onTick: (newBars, chart) => {},   // callback after new data arrives
 *         onError: (err, chart) => {},      // callback on fetch error
 *     },
 *     datasets: [{ data: initialData }],
 * });
 * ```
 *
 * **POST body:**
 * ```json
 * { "bar_type": "5m", "last_update_tick": 1708387200000 }
 * ```
 *
 * The response should return an array of OHLCV objects (any supported format).
 * New bars are appended to the existing dataset and the chart re-renders.
 * If the latest bar's timestamp matches the last existing bar, it replaces
 * (updates) that bar instead of duplicating.
 *
 * ## 2. History Fetch (`historyFeed`)
 *
 * Fetches a historical range of ticks on demand (e.g. scrolling back in time).
 *
 * ```js
 * new Chart('#el', {
 *     type: 'candlestick',
 *     historyFeed: {
 *         url: '/api/ticks/history',
 *         barType: '5m',
 *         maxRange: 90 * 24 * 3600 * 1000,  // 90 days max
 *         headers: {},
 *         transform: (json) => json.data,
 *         onLoad: (bars, chart) => {},
 *         onError: (err, chart) => {},
 *     },
 * });
 * ```
 *
 * **POST body:**
 * ```json
 * {
 *     "bar_type": "5m",
 *     "start_datetime": "2025-12-01T00:00:00.000Z",
 *     "end_datetime": "2025-12-31T23:59:59.999Z"
 * }
 * ```
 *
 * History can be triggered manually via the control API:
 * ```js
 * const ctrl = chart.getControl();
 * ctrl.fetchHistory('2025-12-01', '2025-12-31');
 * ```
 *
 * @module module/Chart/features/datafeed
 */

import { normalizeOHLC } from './trading.js';

// ─────────────────────────────────────────────────
//  Live Feed
// ─────────────────────────────────────────────────

/**
 * Start the live-feed polling loop.
 * Returns a controller object with `.stop()` and `.start()`.
 *
 * @param {Object} ctx   — chart context
 * @returns {{ start: Function, stop: Function, setBarType: Function }}
 */
export function startLiveFeed(ctx) {
    const cfg = ctx.config;
    const feed = cfg.liveFeed;
    if (!feed?.url) return null;

    let timerId = null;
    let stopped = false;
    let fetching = false;

    /** Resolve the poll interval for the current bar type. */
    function getInterval() {
        const bt = feed.barType || cfg.timeline || '5m';
        if (feed.intervals && feed.intervals[bt] != null) {
            return feed.intervals[bt];
        }
        return feed.interval || 5000;
    }

    /** Extract the timestamp (ms) of the last known bar. */
    function lastTick() {
        const ds = cfg.datasets?.[0];
        if (!ds?.data?.length) return 0;
        const raw = ds.data;
        const last = raw[raw.length - 1];
        if (!last) return 0;
        // Handle all supported formats
        const d = last.date ?? last.d ?? last.t ?? (Array.isArray(last) ? last[0] : 0);
        return d instanceof Date ? d.getTime() : (typeof d === 'number' ? d : new Date(d).getTime());
    }

    /** Single poll cycle. */
    async function poll() {
        if (stopped || fetching) return;
        fetching = true;

        const barType = feed.barType || cfg.timeline || '5m';
        const body = {
            bar_type: barType,
            last_update_tick: lastTick(),
        };

        try {
            const resp = await fetch(feed.url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    ...(feed.headers || {}),
                },
                body: JSON.stringify(body),
            });

            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);

            let json = await resp.json();
            let newData = feed.transform ? feed.transform(json) : json;

            if (!newData || (Array.isArray(newData) && !newData.length)) {
                fetching = false;
                return;
            }

            // Normalise incoming bars
            const bars = normalizeOHLC(Array.isArray(newData) ? newData : [newData]);
            if (!bars.length) { fetching = false; return; }

            // Merge into existing dataset
            const ds = cfg.datasets[0] || (cfg.datasets[0] = { data: [] });
            const existing = ds.data;

            // If the first incoming bar matches the last existing bar's timestamp,
            // replace it (in-place update of the current forming bar).
            if (existing.length) {
                const lastExisting = existing[existing.length - 1];
                const lastExTime = (lastExisting.date ?? lastExisting.d ?? lastExisting.t);
                const lastExMs = lastExTime instanceof Date ? lastExTime.getTime()
                    : typeof lastExTime === 'number' ? lastExTime
                    : new Date(lastExTime).getTime();

                const firstNew = bars[0];
                const firstNewMs = firstNew.date instanceof Date
                    ? firstNew.date.getTime() : firstNew.date;

                if (firstNewMs === lastExMs) {
                    // Update the last bar in place
                    existing[existing.length - 1] = bars.shift();
                }
            }

            // Append remaining new bars
            if (bars.length) {
                existing.push(...bars);
            }

            // Auto-scroll: keep the view at the latest bar if user was already there
            const wasAtEnd = (cfg._viewStart == null) ||
                (cfg._viewStart + (cfg.visibleBars || 60) >= existing.length - bars.length);

            if (wasAtEnd) {
                const vb = cfg.visibleBars || 60;
                cfg._viewStart = Math.max(0, existing.length - vb);
            }

            // Re-render
            if (typeof ctx.rerender === 'function') ctx.rerender();

            // Callback
            if (feed.onTick) feed.onTick(bars, ctx);

        } catch (err) {
            if (feed.onError) feed.onError(err, ctx);
            else console.warn('[Chart liveFeed]', err);
        } finally {
            fetching = false;
        }
    }

    /** Schedule next poll. */
    function schedule() {
        if (stopped) return;
        timerId = setTimeout(() => {
            poll().finally(() => schedule());
        }, getInterval());
    }

    function start() {
        if (!stopped) return;
        stopped = false;
        schedule();
    }

    function stop() {
        stopped = true;
        if (timerId) { clearTimeout(timerId); timerId = null; }
    }

    function setBarType(bt) {
        feed.barType = bt;
        // Restart with new interval
        stop();
        stopped = false;
        schedule();
    }

    // Begin polling
    schedule();

    return { start, stop, setBarType, poll };
}


// ─────────────────────────────────────────────────
//  History Feed
// ─────────────────────────────────────────────────

/**
 * Fetch a historical range of bars and either replace or prepend
 * to the current dataset.
 *
 * @param {Object}       ctx   — chart context
 * @param {string|Date}  start — start datetime
 * @param {string|Date}  end   — end datetime
 * @param {Object}       [opts]
 * @param {'replace'|'prepend'|'append'} [opts.mode='replace'] — how to merge data
 * @returns {Promise<Array>} — the fetched bars (normalised)
 */
export async function fetchHistory(ctx, start, end, opts = {}) {
    const cfg = ctx.config;
    const feed = cfg.historyFeed;
    if (!feed?.url) throw new Error('[Chart historyFeed] url is required');

    const startMs = start instanceof Date ? start.getTime() : new Date(start).getTime();
    const endMs   = end   instanceof Date ? end.getTime()   : new Date(end).getTime();

    // Enforce max range
    if (feed.maxRange && (endMs - startMs) > feed.maxRange) {
        const msg = `Range exceeds maximum allowed (${feed.maxRange}ms)`;
        if (feed.onError) { feed.onError(new Error(msg), ctx); return []; }
        throw new Error('[Chart historyFeed] ' + msg);
    }

    const barType = feed.barType || cfg.timeline || '5m';
    const body = {
        bar_type: barType,
        start_datetime: new Date(startMs).toISOString(),
        end_datetime:   new Date(endMs).toISOString(),
    };

    try {
        const resp = await fetch(feed.url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                ...(feed.headers || {}),
            },
            body: JSON.stringify(body),
        });

        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);

        let json = await resp.json();
        let rawData = feed.transform ? feed.transform(json) : json;

        if (!rawData || (Array.isArray(rawData) && !rawData.length)) {
            if (feed.onLoad) feed.onLoad([], ctx);
            return [];
        }

        const bars = normalizeOHLC(Array.isArray(rawData) ? rawData : [rawData]);
        if (!bars.length) { if (feed.onLoad) feed.onLoad([], ctx); return []; }

        // Merge strategy
        const mode = opts.mode || 'replace';
        const ds = cfg.datasets[0] || (cfg.datasets[0] = { data: [] });

        if (mode === 'replace') {
            ds.data = bars;
            cfg._viewStart = null; // reset viewport
        } else if (mode === 'prepend') {
            // Deduplicate: remove any bars from `bars` that already exist
            const firstExistingMs = _barMs(ds.data[0]);
            const newBars = bars.filter(b => _barMs(b) < firstExistingMs);
            if (newBars.length) {
                ds.data = [...newBars, ...ds.data];
                // Shift viewport to keep same candles visible
                if (cfg._viewStart != null) {
                    cfg._viewStart += newBars.length;
                }
            }
        } else if (mode === 'append') {
            const lastExistingMs = _barMs(ds.data[ds.data.length - 1]);
            const newBars = bars.filter(b => _barMs(b) > lastExistingMs);
            if (newBars.length) {
                ds.data.push(...newBars);
            }
        }

        // Re-render
        if (typeof ctx.rerender === 'function') ctx.rerender();

        if (feed.onLoad) feed.onLoad(bars, ctx);
        return bars;

    } catch (err) {
        if (feed.onError) feed.onError(err, ctx);
        else console.warn('[Chart historyFeed]', err);
        return [];
    }
}


// ─────────────────────────────────────────────────
//  Install — wire lifecycle into chart context
// ─────────────────────────────────────────────────

/**
 * Install the datafeed feature onto the chart context.
 * Called once during feature installation.
 *
 * @param {Object} ctx — chart context
 */
export function installDatafeed(ctx) {
    // nothing to install globally — feeds are started/stopped via lifecycle
}

/**
 * Start feeds if configured. Returns a cleanup function.
 * Called after every render cycle.
 *
 * @param {Object} ctx
 * @returns {{ liveFeedCtrl: Object|null, fetchHistory: Function, destroy: Function }}
 */
export function activateDatafeed(ctx) {
    const cfg = ctx.config;

    // ── Live feed ──
    let liveCtrl = ctx._liveFeedCtrl;
    if (cfg.liveFeed?.url && !liveCtrl) {
        liveCtrl = startLiveFeed(ctx);
        ctx._liveFeedCtrl = liveCtrl;
    }

    // Sync bar type with timeline changes
    if (liveCtrl && cfg.timeline) {
        const currentBT = cfg.liveFeed.barType || cfg.timeline;
        if (currentBT !== cfg.timeline) {
            cfg.liveFeed.barType = cfg.timeline;
            liveCtrl.setBarType(cfg.timeline);
        }
    }

    return {
        liveFeedCtrl: liveCtrl,
        fetchHistory: (start, end, opts) => fetchHistory(ctx, start, end, opts),
        destroy() {
            if (liveCtrl) { liveCtrl.stop(); ctx._liveFeedCtrl = null; }
        },
    };
}


// ── Helpers ──

/** Get ms timestamp from a normalised bar. */
function _barMs(bar) {
    if (!bar) return 0;
    const d = bar.date ?? bar.d ?? bar.t ?? (Array.isArray(bar) ? bar[0] : 0);
    return d instanceof Date ? d.getTime() : (typeof d === 'number' ? d : new Date(d).getTime());
}
